import { GoogleGenAI, Type } from "@google/genai";
import { CheckIn, Lead, WorkoutProfile } from "../types";

const apiKey = process.env.API_KEY || ''; // Fallback for safety, though env is required
const ai = new GoogleGenAI({ apiKey });

const SYSTEM_INSTRUCTION = `
You are Nexus 360, an advanced High-Performance OS AI. 
Your tone is direct, analytical, and action-oriented. 
Do not be polite. Be effective. 
Analyze data to find correlations between health, wealth, and time.
Focus on "What the user SHOULD do", not just what they want to do.
`;

export const getDailyInsight = async (checkIn: CheckIn, previousPerformance: string): Promise<string> => {
  if (!apiKey) return "AI Key missing. Please configure.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `
        User Check-in:
        Energy: ${checkIn.energy}/10
        Mood: ${checkIn.mood}
        Sleep: ${checkIn.sleepQuality}
        Main Goal: ${checkIn.mainGoal}

        Context: ${previousPerformance}

        Based on this state, give ONE high-impact directive for today. Maximum 2 sentences.
      `,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });
    return response.text || "Focus on your main goal.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "System offline. Proceed with planned tasks.";
  }
};

export const analyzeCRM = async (leads: Lead[]): Promise<string> => {
  if (!apiKey) return "AI Key missing.";

  try {
    const leadsStr = JSON.stringify(leads.map(l => ({ s: l.status, v: l.value, p: l.probability, n: l.nextAction })));
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze these leads: ${leadsStr}. Identify the biggest bottleneck and suggest one specific action to unlock revenue.`,
      config: { systemInstruction: SYSTEM_INSTRUCTION }
    });
    return response.text || "Review your negotiation stage leads.";
  } catch (error) {
    return "Unable to analyze CRM data.";
  }
};

export const generateWorkoutPlan = async (profile: WorkoutProfile): Promise<any> => {
  if (!apiKey) return null;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a daily workout plan for: ${JSON.stringify(profile)}. Return JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            focus: { type: Type.STRING },
            exercises: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  sets: { type: Type.STRING },
                  reps: { type: Type.STRING },
                  tip: { type: Type.STRING }
                }
              }
            },
            durationMinutes: { type: Type.NUMBER }
          }
        }
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Workout Gen Error", error);
    return null;
  }
};

export const getInvestmentAdvice = async (savings: number, riskProfile: string): Promise<string> => {
   if (!apiKey) return "AI unavailable.";
   try {
     const response = await ai.models.generateContent({
       model: 'gemini-3-flash-preview',
       contents: `User has $${savings} monthly savings. Risk profile: ${riskProfile}. Suggest an allocation strategy (Percentages for Stocks, Bonds, Crypto, Cash). Educational only.`,
       config: { systemInstruction: SYSTEM_INSTRUCTION }
     });
     return response.text || "Diversify your portfolio.";
   } catch (error) {
     return "Market analysis unavailable.";
   }
}

import React, { useState, useEffect } from 'react';
import { CheckIn } from '../types';
import { getDailyInsight } from '../services/geminiService';
import { Battery, Moon, Sun, Target, Zap, AlertTriangle } from 'lucide-react';

interface DashboardProps {
  onCheckIn: (data: CheckIn) => void;
  checkInData: CheckIn | null;
}

export const Dashboard: React.FC<DashboardProps> = ({ onCheckIn, checkInData }) => {
  const [energy, setEnergy] = useState(7);
  const [mood, setMood] = useState('Neutral');
  const [sleep, setSleep] = useState('Average');
  const [goal, setGoal] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const data: CheckIn = { energy, mood, sleepQuality: sleep, mainGoal: goal, timestamp: new Date().toISOString() };
    onCheckIn(data);

    setLoading(true);
    const insight = await getDailyInsight(data, "Previous day: 80% productivity.");
    setAiInsight(insight);
    setLoading(false);
  };

  // If we already have checkin data (persisted), generate insight if missing
  useEffect(() => {
    if (checkInData && !aiInsight && !loading) {
       setLoading(true);
       getDailyInsight(checkInData, "Previous day: 80% productivity.")
        .then(res => {
            setAiInsight(res);
            setLoading(false);
        });
    }
  }, [checkInData]); // eslint-disable-line react-hooks/exhaustive-deps

  if (!checkInData) {
    return (
      <div className="p-6 max-w-2xl mx-auto animate-fade-in">
        <h2 className="text-3xl font-bold mb-6 text-white flex items-center gap-2">
          <Sun className="text-yellow-400" /> Morning Protocol
        </h2>
        <div className="bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-700">
          <form onSubmit={handleSubmit} className="space-y-8">
            <div>
              <label className="block text-slate-400 mb-2 font-medium">System Energy Level (0-10)</label>
              <input 
                type="range" min="0" max="10" value={energy} 
                onChange={(e) => setEnergy(parseInt(e.target.value))}
                className="w-full h-2 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-blue-500"
              />
              <div className="flex justify-between text-xs text-slate-500 mt-2">
                <span>Drained</span>
                <span className="text-blue-400 font-bold text-lg">{energy}</span>
                <span>Peak</span>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-slate-400 mb-2 font-medium">Mood State</label>
                <select value={mood} onChange={(e) => setMood(e.target.value)} className="w-full bg-slate-700 border border-slate-600 text-white rounded-lg p-3 focus:border-blue-500 focus:outline-none">
                  <option>Motivated</option>
                  <option>Neutral</option>
                  <option>Anxious</option>
                  <option>Exhausted</option>
                </select>
              </div>
              <div>
                <label className="block text-slate-400 mb-2 font-medium">Sleep Quality</label>
                <select value={sleep} onChange={(e) => setSleep(e.target.value)} className="w-full bg-slate-700 border border-slate-600 text-white rounded-lg p-3 focus:border-blue-500 focus:outline-none">
                  <option>Restorative</option>
                  <option>Average</option>
                  <option>Poor</option>
                  <option>Insomnia</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-slate-400 mb-2 font-medium">Primary Directive (Main Goal)</label>
              <input 
                type="text" 
                value={goal}
                onChange={(e) => setGoal(e.target.value)}
                placeholder="e.g., Close the Acme deal"
                className="w-full bg-slate-700 border border-slate-600 text-white rounded-lg p-3 focus:border-blue-500 focus:outline-none"
                required
              />
            </div>

            <button type="submit" className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl transition-all flex items-center justify-center gap-2">
              <Zap size={20} /> Initialize Day
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="p-4 md:p-8 space-y-6">
      <header className="mb-8">
        <h1 className="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-emerald-400">
          Nexus Dashboard
        </h1>
        <p className="text-slate-400 mt-2">System Status: <span className="text-emerald-400">Online</span></p>
      </header>

      {/* AI Insight Card */}
      <div className="bg-gradient-to-r from-slate-800 to-slate-900 border border-blue-900/50 p-6 rounded-2xl shadow-lg relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
            <Zap size={100} />
        </div>
        <div className="relative z-10">
          <h3 className="text-blue-400 text-sm font-bold uppercase tracking-wider mb-2 flex items-center gap-2">
            <Zap size={16} /> Nexus AI Directive
          </h3>
          {loading ? (
             <div className="animate-pulse h-16 bg-slate-700 rounded w-3/4"></div>
          ) : (
            <p className="text-xl md:text-2xl font-light text-white leading-relaxed">
              "{aiInsight}"
            </p>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Metric Cards */}
        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col justify-between">
            <div className="flex justify-between items-start">
                <div>
                    <p className="text-slate-400 text-sm">Bio-Energy</p>
                    <h4 className="text-3xl font-bold text-white mt-1">{checkInData.energy}<span className="text-sm text-slate-500">/10</span></h4>
                </div>
                <Battery className={`${checkInData.energy > 6 ? 'text-emerald-500' : 'text-orange-500'}`} />
            </div>
            <div className="mt-4 h-2 bg-slate-700 rounded-full overflow-hidden">
                <div className={`h-full ${checkInData.energy > 6 ? 'bg-emerald-500' : 'bg-orange-500'}`} style={{ width: `${checkInData.energy * 10}%`}}></div>
            </div>
        </div>

        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col justify-between">
            <div className="flex justify-between items-start">
                <div>
                    <p className="text-slate-400 text-sm">Sleep Recovery</p>
                    <h4 className="text-2xl font-bold text-white mt-1">{checkInData.sleepQuality}</h4>
                </div>
                <Moon className="text-indigo-400" />
            </div>
             <p className="text-xs text-slate-500 mt-4">Impacts cognition by approx {checkInData.sleepQuality === 'Restorative' ? '+15%' : '-10%'}</p>
        </div>

        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col justify-between">
            <div className="flex justify-between items-start">
                <div>
                    <p className="text-slate-400 text-sm">Primary Objective</p>
                    <h4 className="text-xl font-bold text-white mt-1 truncate" title={checkInData.mainGoal}>{checkInData.mainGoal}</h4>
                </div>
                <Target className="text-red-400" />
            </div>
            <button className="mt-4 text-xs bg-red-500/10 text-red-400 py-1 px-3 rounded border border-red-500/20 hover:bg-red-500/20 transition-colors w-max">
                Engage Focus Mode
            </button>
        </div>
      </div>

      {/* Quick Actions / Alerts */}
      <div className="bg-slate-800 rounded-xl border border-slate-700 p-6">
        <h3 className="text-lg font-semibold text-white mb-4 flex items-center gap-2">
            <AlertTriangle size={18} className="text-amber-400" /> System Alerts
        </h3>
        <div className="space-y-3">
             <div className="flex items-center gap-4 p-3 bg-slate-700/50 rounded-lg border-l-4 border-amber-500">
                <Clock size={20} className="text-slate-300" />
                <div>
                    <p className="text-sm font-medium text-white">Productivity Dip Predicted</p>
                    <p className="text-xs text-slate-400">Based on sleep data, expect lower focus between 2:00 PM - 4:00 PM.</p>
                </div>
             </div>
             <div className="flex items-center gap-4 p-3 bg-slate-700/50 rounded-lg border-l-4 border-blue-500">
                <Briefcase size={20} className="text-slate-300" />
                <div>
                    <p className="text-sm font-medium text-white">CRM Follow-up Required</p>
                    <p className="text-xs text-slate-400">3 High-value leads have been inactive for > 4 days.</p>
                </div>
             </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Lead } from '../types';
import { MOCK_LEADS } from '../constants';
import { analyzeCRM } from '../services/geminiService';
import { TrendingUp, Users, DollarSign, Brain, MoreHorizontal } from 'lucide-react';

export const Professional: React.FC = () => {
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS as any);
  const [aiAnalysis, setAiAnalysis] = useState<string>("");
  const [analyzing, setAnalyzing] = useState(false);

  const handleAnalyze = async () => {
    setAnalyzing(true);
    const result = await analyzeCRM(leads);
    setAiAnalysis(result);
    setAnalyzing(false);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'proposal': return 'bg-purple-500/20 text-purple-400 border-purple-500/30';
      case 'negotiation': return 'bg-amber-500/20 text-amber-400 border-amber-500/30';
      case 'closed': return 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30';
      case 'lost': return 'bg-red-500/20 text-red-400 border-red-500/30';
      default: return 'bg-blue-500/20 text-blue-400 border-blue-500/30';
    }
  };

  const totalPipeline = leads.reduce((acc, lead) => acc + lead.value, 0);
  const weightedPipeline = leads.reduce((acc, lead) => acc + (lead.value * (lead.probability / 100)), 0);

  return (
    <div className="p-4 md:p-8 h-full flex flex-col">
      <header className="flex flex-col md:flex-row md:justify-between md:items-center mb-8 gap-4">
        <div>
            <h1 className="text-3xl font-bold text-white">Professional CRM</h1>
            <p className="text-slate-400">Pipeline Performance & Optimization</p>
        </div>
        <button 
            onClick={handleAnalyze}
            disabled={analyzing}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-4 py-2 rounded-lg text-white font-medium transition-all disabled:opacity-50"
        >
            <Brain size={18} /> {analyzing ? 'Analyzing...' : 'AI Pipeline Audit'}
        </button>
      </header>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700">
            <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400"><DollarSign size={20} /></div>
                <span className="text-slate-400 font-medium">Total Pipeline</span>
            </div>
            <p className="text-2xl font-bold text-white">${totalPipeline.toLocaleString()}</p>
        </div>
        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700">
            <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-400"><TrendingUp size={20} /></div>
                <span className="text-slate-400 font-medium">Weighted Value</span>
            </div>
            <p className="text-2xl font-bold text-white">${weightedPipeline.toLocaleString()}</p>
        </div>
        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700">
            <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-purple-500/10 rounded-lg text-purple-400"><Users size={20} /></div>
                <span className="text-slate-400 font-medium">Active Leads</span>
            </div>
            <p className="text-2xl font-bold text-white">{leads.length}</p>
        </div>
      </div>

      {aiAnalysis && (
        <div className="mb-8 bg-indigo-900/20 border border-indigo-500/50 p-4 rounded-xl animate-fade-in">
            <h3 className="text-indigo-400 font-bold mb-1 flex items-center gap-2"><Brain size={16}/> Strategic Insight</h3>
            <p className="text-slate-200">{aiAnalysis}</p>
        </div>
      )}

      {/* List View */}
      <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden flex-1">
        <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
                <thead>
                    <tr className="bg-slate-900/50 border-b border-slate-700 text-slate-400 text-sm uppercase tracking-wider">
                        <th className="p-4">Lead / Company</th>
                        <th className="p-4">Status</th>
                        <th className="p-4">Value</th>
                        <th className="p-4">Probability</th>
                        <th className="p-4">Next Action</th>
                        <th className="p-4"></th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-700">
                    {leads.map((lead) => (
                        <tr key={lead.id} className="hover:bg-slate-700/30 transition-colors group">
                            <td className="p-4">
                                <p className="font-bold text-white">{lead.name}</p>
                                <p className="text-xs text-slate-500">{lead.company}</p>
                            </td>
                            <td className="p-4">
                                <span className={`px-2 py-1 rounded-full text-xs font-bold border ${getStatusColor(lead.status)}`}>
                                    {lead.status}
                                </span>
                            </td>
                            <td className="p-4 text-slate-300 font-mono">${lead.value.toLocaleString()}</td>
                            <td className="p-4">
                                <div className="flex items-center gap-2">
                                    <div className="w-16 h-1.5 bg-slate-700 rounded-full overflow-hidden">
                                        <div className="h-full bg-blue-500" style={{ width: `${lead.probability}%` }}></div>
                                    </div>
                                    <span className="text-xs text-slate-400">{lead.probability}%</span>
                                </div>
                            </td>
                            <td className="p-4 text-slate-300 text-sm">{lead.nextAction}</td>
                            <td className="p-4 text-right">
                                <button className="text-slate-500 hover:text-white p-2">
                                    <MoreHorizontal size={18} />
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { WorkoutProfile } from '../types';
import { generateWorkoutPlan } from '../services/geminiService';
import { Activity, Dumbbell, PlayCircle, RotateCcw, CheckCircle } from 'lucide-react';

export const Body: React.FC = () => {
  const [profile, setProfile] = useState<WorkoutProfile | null>(null);
  const [formData, setFormData] = useState<Partial<WorkoutProfile>>({
    sex: 'Male', age: 30, weight: 75, goal: 'hypertrophy', limitations: 'None'
  });
  const [plan, setPlan] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!formData.age) return;
    const p = formData as WorkoutProfile;
    setProfile(p);
    setLoading(true);
    const aiPlan = await generateWorkoutPlan(p);
    setPlan(aiPlan);
    setLoading(false);
  };

  if (!profile || !plan) {
    return (
      <div className="p-8 max-w-2xl mx-auto">
         <h2 className="text-3xl font-bold text-white mb-2">Biometrics & Goals</h2>
         <p className="text-slate-400 mb-6">Configure your profile for an adaptive workout plan.</p>

         <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 space-y-4">
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-slate-400 text-sm mb-1">Weight (kg)</label>
                    <input type="number" value={formData.weight} onChange={(e) => setFormData({...formData, weight: Number(e.target.value)})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white" />
                </div>
                <div>
                    <label className="block text-slate-400 text-sm mb-1">Age</label>
                    <input type="number" value={formData.age} onChange={(e) => setFormData({...formData, age: Number(e.target.value)})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white" />
                </div>
            </div>

            <div>
                <label className="block text-slate-400 text-sm mb-1">Primary Objective</label>
                <select value={formData.goal} onChange={(e) => setFormData({...formData, goal: e.target.value as any})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white">
                    <option value="hypertrophy">Hypertrophy (Muscle Gain)</option>
                    <option value="weight_loss">Weight Loss</option>
                    <option value="conditioning">Conditioning / Endurance</option>
                    <option value="health">General Health</option>
                </select>
            </div>

            <div>
                <label className="block text-slate-400 text-sm mb-1">Limitations / Injuries</label>
                <input type="text" value={formData.limitations} onChange={(e) => setFormData({...formData, limitations: e.target.value})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white" />
            </div>

            <button 
                onClick={handleGenerate}
                disabled={loading}
                className="w-full mt-4 bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all"
            >
                {loading ? <RotateCcw className="animate-spin" /> : <Activity />}
