const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

export const Finance: React.FC = () => {
  const [advice, setAdvice] = useState('');
  const [loading, setLoading] = useState(false);

  // Calculate basic stats
  const income = MOCK_TRANSACTIONS.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
  const expense = MOCK_TRANSACTIONS.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
  const savings = income - expense;

  // Group expenses for chart
  const expensesByCategory = MOCK_TRANSACTIONS.filter(t => t.type === 'expense').reduce((acc, t) => {
    acc[t.category] = (acc[t.category] || 0) + t.amount;
    return acc;
  }, {} as any);

  const chartData = Object.keys(expensesByCategory).map(key => ({ name: key, value: expensesByCategory[key] }));

  const handleGetAdvice = async () => {
    setLoading(true);
    const res = await getInvestmentAdvice(savings, "Moderate");
    setAdvice(res);
    setLoading(false);
  };

  return (
    <div className="p-4 md:p-8 h-full flex flex-col gap-6">
       <header>
            <h1 className="text-3xl font-bold text-white">Financial Command</h1>
            <p className="text-slate-400">Cashflow & Asset Allocation</p>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
                <p className="text-slate-400 text-sm">Monthly Net Flow</p>
                <h3 className={`text-3xl font-bold mt-1 ${savings >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                    {savings >= 0 ? '+' : ''}${savings}
                </h3>
            </div>
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
                <p className="text-slate-400 text-sm">Burn Rate</p>
                <h3 className="text-3xl font-bold mt-1 text-white">${expense}</h3>
            </div>
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 cursor-pointer hover:border-blue-500 transition-colors" onClick={handleGetAdvice}>
                 <div className="flex justify-between items-start">
                    <div>
                        <p className="text-slate-400 text-sm">Investable Capital</p>
                        <h3 className="text-3xl font-bold mt-1 text-blue-400">${Math.max(0, savings)}</h3>
                    </div>
                    <TrendingUp className="text-blue-500" />
                 </div>
                 <p className="text-xs text-blue-300 mt-2 flex items-center gap-1">
                    {loading ? 'Analyzing...' : 'Click for AI Allocation Strategy'}
                 </p>
            </div>
        </div>

        {advice && (
             <div className="bg-blue-900/20 border border-blue-500/50 p-6 rounded-xl animate-fade-in">
                <h3 className="text-blue-400 font-bold mb-2 flex items-center gap-2">
                    <BrainIcon /> Nexus Financial Advisor
                </h3>
                <p className="text-slate-200 leading-relaxed whitespace-pre-line">{advice}</p>
                <p className="text-xs text-slate-500 mt-4">*Educational purposes only. Not financial advice.</p>
            </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 flex-1">
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><PieIcon size={18}/> Expense Breakdown</h3>
                <div className="flex-1 min-h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                            <Pie
                                data={chartData}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                fill="#8884d8"
                                paddingAngle={5}
                                dataKey="value"
                            >
                                {chartData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff'}} />
                            <Legend />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            </div>

            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
                <h3 className="text-lg font-bold text-white mb-4">Recent Transactions</h3>
                <div className="space-y-3">
                    {MOCK_TRANSACTIONS.map(t => (
                        <div key={t.id} className="flex justify-between items-center p-3 bg-slate-700/30 rounded-lg hover:bg-slate-700/50 transition-colors">
                            <div className="flex items-center gap-3">
