const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavigationTab>('dashboard');
  const [checkInData, setCheckInData] = useState<CheckIn | null>(null);

  // Load state from local storage on mount (Simulation of persistence)
  useEffect(() => {
    const savedCheckIn = localStorage.getItem('nexus_checkin');
    if (savedCheckIn) {
        try {
            const parsed = JSON.parse(savedCheckIn);
            // Reset check-in if it's from a previous day
            if (new Date(parsed.timestamp).getDate() === new Date().getDate()) {
                setCheckInData(parsed);
            }
        } catch(e) {}
    }
  }, []);

  const handleCheckIn = (data: CheckIn) => {
    setCheckInData(data);
    localStorage.setItem('nexus_checkin', JSON.stringify(data));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard onCheckIn={handleCheckIn} checkInData={checkInData} />;
      case 'professional': return <Professional />;
      case 'body': return <Body />;
      case 'finance': return <Finance />;
      default: return (
        <div className="flex flex-col items-center justify-center h-full text-slate-500">
            <LayoutGrid size={48} className="mb-4 opacity-50"/>
