interface DashboardProps {
  onCheckIn: (data: CheckIn) => void;
  checkInData: CheckIn | null;
}

export const Dashboard: React.FC<DashboardProps> = ({ onCheckIn, checkInData }) => {
  const [energy, setEnergy] = useState(7);
