import { GoogleGenAI, Type } from "@google/genai";
import { CheckIn, Lead, WorkoutProfile } from "../types";

const apiKey = process.env.API_KEY || ''; // Fallback for safety, though env is required
const ai = new GoogleGenAI({ apiKey });

const SYSTEM_INSTRUCTION = `
Você é o Nexus 360, uma IA avançada de Sistema Operacional de Alta Performance.
Seu tom é direto, analítico e orientado para a ação.
Não seja excessivamente educado. Seja eficaz.
Analise dados para encontrar correlações entre saúde, riqueza e tempo.
Foque no "O que o usuário DEVE fazer", não apenas no que ele quer fazer.
Responda sempre em Português do Brasil.
`;

export const getDailyInsight = async (checkIn: CheckIn, previousPerformance: string): Promise<string> => {
  if (!apiKey) return "Chave de API ausente. Por favor, configure.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `
        Check-in do Usuário:
        Energia: ${checkIn.energy}/10
        Humor: ${checkIn.mood}
        Sono: ${checkIn.sleepQuality}
        Objetivo Principal: ${checkIn.mainGoal}

        Contexto: ${previousPerformance}

        Com base neste estado, dê UMA diretriz de alto impacto para hoje. Máximo de 2 frases.
      `,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      }
    });
    return response.text || "Concentre-se no seu objetivo principal.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Sistema offline. Prossiga com as tarefas planejadas.";
  }
};

export const analyzeCRM = async (leads: Lead[]): Promise<string> => {
  if (!apiKey) return "Chave de API ausente.";

  try {
    const leadsStr = JSON.stringify(leads.map(l => ({ s: l.status, v: l.value, p: l.probability, n: l.nextAction })));
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analise estes leads: ${leadsStr}. Identifique o maior gargalo e sugira uma ação específica para desbloquear receita. Responda em Português.`,
      config: { systemInstruction: SYSTEM_INSTRUCTION }
    });
    return response.text || "Revise seus leads em fase de negociação.";
  } catch (error) {
    return "Não foi possível analisar os dados do CRM.";
  }
};

export const generateWorkoutPlan = async (profile: WorkoutProfile): Promise<any> => {
  if (!apiKey) return null;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Gere um plano de treino diário para este perfil: ${JSON.stringify(profile)}. Retorne JSON. O conteúdo do plano deve estar em Português.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            focus: { type: Type.STRING },
            exercises: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  sets: { type: Type.STRING },
                  reps: { type: Type.STRING },
                  tip: { type: Type.STRING }
                }
              }
            },
            durationMinutes: { type: Type.NUMBER }
          }
        }
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Workout Gen Error", error);
    return null;
  }
};

export const getInvestmentAdvice = async (savings: number, riskProfile: string): Promise<string> => {
   if (!apiKey) return "IA indisponível.";
   try {
     const response = await ai.models.generateContent({
       model: 'gemini-3-flash-preview',
       contents: `O usuário tem $${savings} de economia mensal. Perfil de risco: ${riskProfile}. Sugira uma estratégia de alocação (Porcentagens para Ações, Renda Fixa, Cripto, Caixa). Apenas educativo. Responda em Português.`,
       config: { systemInstruction: SYSTEM_INSTRUCTION }
     });
     return response.text || "Diversifique seu portfólio.";
   } catch (error) {
     return "Análise de mercado indisponível.";
   }
}

