import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { CheckIn, Lead, WorkoutProfile } from "../types";

const apiKey = process.env.API_KEY || ''; 
const ai = new GoogleGenAI({ apiKey });

const SYSTEM_INSTRUCTION = `
Você é o Nexus 360, uma IA avançada de Sistema Operacional de Alta Performance.
Seu tom é direto, analítico e orientado para a ação.
Responda sempre em Português do Brasil.

VOCÊ POSSUI FERRAMENTAS PARA EXECUTAR COMANDOS DO USUÁRIO.
Sempre que o usuário mencionar que gastou dinheiro, ganhou dinheiro, fez um exercício ou precisa lembrar de uma tarefa, USE AS FERRAMENTAS DISPONÍVEIS.

Não pergunte "você quer que eu anote?". Se o usuário declarou o fato, EXECUTE A FERRAMENTA IMEDIATAMENTE.
`;

// Definição das Ferramentas (Tools)
const addTransactionTool: FunctionDeclaration = {
    name: 'addTransaction',
    parameters: {
      type: Type.OBJECT,
      description: 'Adiciona uma transação financeira (gasto ou ganho).',
      properties: {
        type: { type: Type.STRING, description: 'income (ganho/salário) ou expense (gasto/compra)' },
        category: { type: Type.STRING, description: 'Categoria ex: Alimentação, Transporte, Salário, Lazer' },
        amount: { type: Type.NUMBER, description: 'Valor numérico da transação' },
      },
      required: ['type', 'category', 'amount']
    }
};

const addTaskTool: FunctionDeclaration = {
    name: 'addTask',
    parameters: {
        type: Type.OBJECT,
        description: 'Adiciona uma tarefa à lista de produtividade.',
        properties: {
            title: { type: Type.STRING, description: 'A descrição da tarefa.' }
        },
        required: ['title']
    }
};

const logWorkoutTool: FunctionDeclaration = {
    name: 'logWorkout',
    parameters: {
        type: Type.OBJECT,
        description: 'Registra um treino ou exercício físico realizado.',
        properties: {
            description: { type: Type.STRING, description: 'Descrição do treino (ex: Treino de Braços, 15 reps, Corrida 5km)' }
        },
        required: ['description']
    }
};

export const chatWithNexus = async (message: string, history: any[]) => {
    if (!apiKey) return { text: "Chave de API não configurada.", functionCall: null };

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: message, // Simplificado para este exemplo, idealmente passaria histórico
            config: {
                systemInstruction: SYSTEM_INSTRUCTION,
                tools: [{ functionDeclarations: [addTransactionTool, addTaskTool, logWorkoutTool] }],
            }
        });

        // Extração de Function Call
        const functionCall = response.candidates?.[0]?.content?.parts?.find(p => p.functionCall)?.functionCall;
        const text = response.text;

        return { text, functionCall };

    } catch (error) {
        console.error("Gemini Chat Error:", error);
        return { text: "Erro ao processar comando. Tente novamente.", functionCall: null };
    }
};

