import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { chatWithNexus } from '../services/geminiService';
import { Send, Zap, Bot, User, Terminal } from 'lucide-react';

interface DashboardProps {
  onCommand: (toolName: string, args: any) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ onCommand }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Nexus 360 Online. Pronto para comandos. Posso registrar finanças, treinos ou tarefas, ou tirar suas dúvidas.',
      timestamp: new Date()
    }
  ]);
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const { text, functionCall } = await chatWithNexus(input, messages);

    setLoading(false);

    if (functionCall) {
        // Executar o comando no App pai
        onCommand(functionCall.name, functionCall.args);

        // Mensagem de sistema confirmando a ação
        const sysMsg: Message = {
            id: Date.now().toString() + '_sys',
            role: 'system',
            text: `Comando executado: ${functionCall.name}`,
            timestamp: new Date()
        };
        setMessages(prev => [...prev, sysMsg]);

        // Se a IA também mandou texto (raro quando chama função, mas possível)
        if (text) {
             setMessages(prev => [...prev, {
                id: Date.now().toString() + '_ai',
                role: 'model',
                text: text,
                timestamp: new Date()
            }]);
        } else {
             // Resposta padrão pós comando se a IA não falar nada
             setMessages(prev => [...prev, {
                id: Date.now().toString() + '_ai',
                role: 'model',
                text: "Registro efetuado com sucesso.",
                timestamp: new Date()
            }]);
        }

    } else if (text) {
        setMessages(prev => [...prev, {
            id: Date.now().toString() + '_ai',
            role: 'model',
            text: text,
            timestamp: new Date()
        }]);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-100px)] md:h-[calc(100vh-40px)] max-w-4xl mx-auto">
      <header className="mb-4 flex items-center gap-3 border-b border-slate-800 pb-4">
        <div className="p-3 bg-blue-600/20 rounded-xl text-blue-400 border border-blue-500/30">
            <Terminal size={24} />
