import React, { useState } from 'react';
import { Task } from '../types';
import { CheckSquare, Square, Trash2, Plus, Calendar } from 'lucide-react';

interface ProductivityProps {
    tasks: Task[];
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    onAddTask: (title: string) => void;
}

export const Productivity: React.FC<ProductivityProps> = ({ tasks, onToggleTask, onDeleteTask, onAddTask }) => {
    const [newTaskTitle, setNewTaskTitle] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (newTaskTitle.trim()) {
            onAddTask(newTaskTitle);
            setNewTaskTitle('');
        }
    };

    const activeTasks = tasks.filter(t => !t.completed);
    const completedTasks = tasks.filter(t => t.completed);

    return (
        <div className="p-4 md:p-8 h-full flex flex-col max-w-5xl mx-auto">
            <header className="mb-8">
                <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                    <CheckSquare className="text-emerald-500" /> Lista de Foco
                </h1>
                <p className="text-slate-400">Gerenciamento de tarefas e prioridades diárias.</p>
            </header>

            {/* Input */}
            <form onSubmit={handleSubmit} className="flex gap-2 mb-8">
                <input 
                    type="text" 
                    value={newTaskTitle}
                    onChange={(e) => setNewTaskTitle(e.target.value)}
                    placeholder="Adicionar nova tarefa..."
                    className="flex-1 bg-slate-800 border border-slate-700 text-white rounded-lg px-4 py-3 focus:border-emerald-500 focus:outline-none"
                />
                <button type="submit" className="bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-3 rounded-lg font-bold transition-colors flex items-center gap-2">
                    <Plus size={20} /> Adicionar
                </button>
            </form>

            <div className="grid md:grid-cols-2 gap-8 overflow-y-auto">
                {/* Active Tasks */}
                <div className="space-y-4">
                    <h2 className="text-lg font-bold text-slate-300 uppercase tracking-wider text-sm mb-2">Pendente ({activeTasks.length})</h2>
                    {activeTasks.length === 0 && (
                        <div className="p-8 border-2 border-dashed border-slate-800 rounded-xl text-center text-slate-600">
                            Sem tarefas pendentes. Bom trabalho!
                        </div>
                    )}
                    {activeTasks.map(task => (
                        <div key={task.id} className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex items-center justify-between group hover:border-emerald-500/30 transition-all">
                            <div className="flex items-center gap-3">
                                <button onClick={() => onToggleTask(task.id)} className="text-slate-500 hover:text-emerald-500 transition-colors">
                                    <Square size={24} />
                                </button>
                                <span className="text-white font-medium">{task.title}</span>
                            </div>
                            <button onClick={() => onDeleteTask(task.id)} className="text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all">
                                <Trash2 size={18} />
                            </button>
                        </div>
                    ))}
                </div>

                {/* Completed Tasks */}
                <div className="space-y-4 opacity-75">
                     <h2 className="text-lg font-bold text-slate-400 uppercase tracking-wider text-sm mb-2">Concluído ({completedTasks.length})</h2>
                     {completedTasks.map(task => (
                        <div key={task.id} className="bg-slate-900 p-4 rounded-xl border border-slate-800 flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <button onClick={() => onToggleTask(task.id)} className="text-emerald-500">
                                    <CheckSquare size={24} />
                                </button>
                                <span className="text-slate-500 line-through decoration-slate-600">{task.title}</span>
                            </div>
                            <button onClick={() => onDeleteTask(task.id)} className="text-slate-700 hover:text-red-900 transition-colors">
                                <Trash2 size={18} />
                            </button>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { Transaction } from '../types';
import { getInvestmentAdvice } from '../services/geminiService';
import { DollarSign, PieChart as PieIcon, TrendingUp } from 'lucide-react';

const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

interface FinanceProps {
    transactions: Transaction[];
}

export const Finance: React.FC<FinanceProps> = ({ transactions }) => {
  const [advice, setAdvice] = useState('');
  const [loading, setLoading] = useState(false);

  // Calculate basic stats
  const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
  const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
  const savings = income - expense;

  // Group expenses for chart
  const expensesByCategory = transactions.filter(t => t.type === 'expense').reduce((acc, t) => {
    acc[t.category] = (acc[t.category] || 0) + t.amount;
    return acc;
  }, {} as any);

  const chartData = Object.keys(expensesByCategory).map(key => ({ name: key, value: expensesByCategory[key] }));

  const handleGetAdvice = async () => {
    setLoading(true);
    const res = await getInvestmentAdvice(savings, "Moderado");
    setAdvice(res);
    setLoading(false);
  };

  return (
    <div className="p-4 md:p-8 h-full flex flex-col gap-6">
       <header>
            <h1 className="text-3xl font-bold text-white">Comando Financeiro</h1>
            <p className="text-slate-400">Fluxo de Caixa e Alocação de Ativos</p>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
                <p className="text-slate-400 text-sm">Fluxo Líquido Mensal</p>
                <h3 className={`text-3xl font-bold mt-1 ${savings >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                    {savings >= 0 ? '+' : ''}R$ {savings.toLocaleString()}
                </h3>
            </div>
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
                <p className="text-slate-400 text-sm">Total de Despesas</p>
                <h3 className="text-3xl font-bold mt-1 text-white">R$ {expense.toLocaleString()}</h3>
            </div>
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 cursor-pointer hover:border-blue-500 transition-colors" onClick={handleGetAdvice}>
                 <div className="flex justify-between items-start">
                    <div>
                        <p className="text-slate-400 text-sm">Capital Investível</p>
                        <h3 className="text-3xl font-bold mt-1 text-blue-400">R$ {Math.max(0, savings).toLocaleString()}</h3>
                    </div>
                    <TrendingUp className="text-blue-500" />
                 </div>
                 <p className="text-xs text-blue-300 mt-2 flex items-center gap-1">
                    {loading ? 'Analisando...' : 'Clique para Estratégia de Alocação IA'}
                 </p>
            </div>
        </div>

        {advice && (
             <div className="bg-blue-900/20 border border-blue-500/50 p-6 rounded-xl animate-fade-in">
                <h3 className="text-blue-400 font-bold mb-2 flex items-center gap-2">
                    <BrainIcon /> Consultor Financeiro Nexus
                </h3>
                <p className="text-slate-200 leading-relaxed whitespace-pre-line">{advice}</p>
                <p className="text-xs text-slate-500 mt-4">*Apenas fins educativos. Não é aconselhamento financeiro.</p>
            </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 flex-1">
            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><PieIcon size={18}/> Detalhamento de Despesas</h3>
                <div className="flex-1 min-h-[300px]">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                            <Pie
                                data={chartData}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                fill="#8884d8"
                                paddingAngle={5}
                                dataKey="value"
                            >
                                {chartData.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff'}} />
                            <Legend />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            </div>

            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 overflow-y-auto max-h-[400px]">
                <h3 className="text-lg font-bold text-white mb-4">Transações Recentes</h3>
                <div className="space-y-3">
                    {transactions.slice().reverse().map(t => (
                        <div key={t.id} className="flex justify-between items-center p-3 bg-slate-700/30 rounded-lg hover:bg-slate-700/50 transition-colors">
                            <div className="flex items-center gap-3">
                                <div className={`p-2 rounded-full ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-red-500/10 text-red-500'}`}>
                                    <DollarSign size={16} />
                                </div>
                                <div>
                                    <p className="text-white font-medium">{t.category}</p>
                                    <p className="text-xs text-slate-400">{new Date(t.date).toLocaleDateString()}</p>
                                </div>
                            </div>
                            <span className={`font-bold ${t.type === 'income' ? 'text-emerald-400' : 'text-slate-300'}`}>
                                {t.type === 'income' ? '+' : '-'} R$ {t.amount}
                            </span>
                        </div>
                    ))}
                    {transactions.length === 0 && <p className="text-slate-500 text-center py-4">Nenhuma transação registrada. Use o Chat para adicionar.</p>}
                </div>
            </div>
        </div>
    </div>
  );
};

