import React, { useState } from 'react';
import { WorkoutProfile, WorkoutLog } from '../types';
import { generateWorkoutPlan } from '../services/geminiService';
import { Activity, Dumbbell, PlayCircle, RotateCcw, CheckCircle, History } from 'lucide-react';

interface BodyProps {
    workoutLogs: WorkoutLog[];
}

export const Body: React.FC<BodyProps> = ({ workoutLogs }) => {
  const [profile, setProfile] = useState<WorkoutProfile | null>(null);
  const [formData, setFormData] = useState<Partial<WorkoutProfile>>({
