                <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                    <Dumbbell className="text-emerald-500" /> Corpo & Performance
                </h1>
                <p className="text-slate-400">Geração de treino e registros de atividade.</p>
            </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

            {/* Logs Section (From Chat) */}
            <div className="lg:col-span-1 bg-slate-800 p-6 rounded-xl border border-slate-700 h-fit">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <History size={18} className="text-blue-400" /> Histórico de Atividades
