import React, { useState } from 'react';
import { Task, TaskCategory, UserStats } from '../types';
import { CheckSquare, Square, Trash2, Plus, Clock, Trophy, Star, AlertCircle, Smartphone } from 'lucide-react';

interface ProductivityProps {
    tasks: Task[];
    stats: UserStats;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    onAddTask: (task: Partial<Task>) => void;
}

export const Productivity: React.FC<ProductivityProps> = ({ tasks, stats, onToggleTask, onDeleteTask, onAddTask }) => {
    const [viewMode, setViewMode] = useState<'day' | 'week'>('day');
    const [showConfetti, setShowConfetti] = useState(false);

    // Form State
    const [title, setTitle] = useState('');
    const [time, setTime] = useState('');
    const [duration, setDuration] = useState(30);
    const [category, setCategory] = useState<TaskCategory>('work');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (title.trim()) {
            onAddTask({
                title,
                startTime: time,
                durationMinutes: duration,
                category,
                completed: false,
                xpReward: category === 'wasted' ? 0 : (duration > 60 ? 100 : 50)
            });
            setTitle('');
            setTime('');
        }
    };

    const handleCheck = (id: string) => {
        onToggleTask(id);
        const task = tasks.find(t => t.id === id);
        if (task && !task.completed) {
            setShowConfetti(true);
            setTimeout(() => setShowConfetti(false), 3000);
        }
    };

    const getCategoryColor = (cat: TaskCategory) => {
        switch(cat) {
            case 'work': return 'border-l-4 border-blue-500 bg-blue-500/10';
            case 'study': return 'border-l-4 border-purple-500 bg-purple-500/10';
            case 'workout': return 'border-l-4 border-emerald-500 bg-emerald-500/10';
            case 'wasted': return 'border-l-4 border-red-500 bg-red-500/10 opacity-70';
            default: return 'border-l-4 border-slate-500 bg-slate-500/10';
        }
    };

    const getCategoryIcon = (cat: TaskCategory) => {
        switch(cat) {
            case 'wasted': return <Smartphone size={16} className="text-red-400"/>;
            case 'workout': return <Star size={16} className="text-emerald-400"/>;
            default: return <Clock size={16} className="text-slate-400"/>;
        }
    }

    // Sort tasks by time if available, or just push to end
    const sortedTasks = [...tasks].sort((a, b) => {
        if (!a.startTime) return 1;
        if (!b.startTime) return -1;
        return a.startTime.localeCompare(b.startTime);
    });

    // XP Progress
    const xpForNextLevel = stats.level * 1000;
    const progressPercent = (stats.xp / xpForNextLevel) * 100;

    return (
        <div className="p-4 md:p-8 h-full flex flex-col max-w-6xl mx-auto overflow-hidden">
            {/* Header com Gamificação */}
            <header className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-end gap-4 bg-slate-800 p-6 rounded-2xl border border-slate-700 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
                    <Trophy size={140} />
                </div>

                <div className="z-10">
                    <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                        <Trophy className="text-yellow-500" /> Nível {stats.level}
                    </h1>
                    <p className="text-slate-400 mt-1">Alta Performance | {stats.streak} dias de ofensiva</p>

                    <div className="mt-4 w-full md:w-64">
                        <div className="flex justify-between text-xs text-slate-300 mb-1">
                            <span>{stats.xp} XP</span>
                            <span>{xpForNextLevel} XP</span>
                        </div>
                        <div className="h-3 bg-slate-700 rounded-full overflow-hidden border border-slate-600">
                            <div className="h-full bg-gradient-to-r from-blue-500 to-purple-500 transition-all duration-1000" style={{ width: `${progressPercent}%` }}></div>
                        </div>
                    </div>
                </div>

                {showConfetti && (
                    <div className="absolute inset-0 flex items-center justify-center bg-black/40 z-50 backdrop-blur-sm animate-fade-in">
                        <div className="text-center transform scale-110">
                            <h2 className="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 drop-shadow-lg">
                                OBJETIVO ATINGIDO!
                            </h2>
                            <p className="text-white mt-2 font-medium">+XP Adicionado</p>
                        </div>
                    </div>
                )}

                <div className="flex gap-2 z-10">
                    <button onClick={() => setViewMode('day')} className={`px-4 py-2 rounded-lg font-medium transition-all ${viewMode === 'day' ? 'bg-blue-600 text-white' : 'bg-slate-700 text-slate-400 hover:text-white'}`}>Dia</button>
                    <button onClick={() => setViewMode('week')} className={`px-4 py-2 rounded-lg font-medium transition-all ${viewMode === 'week' ? 'bg-blue-600 text-white' : 'bg-slate-700 text-slate-400 hover:text-white'}`}>Semana</button>
                </div>
