            <div className="flex-1 grid grid-cols-1 lg:grid-cols-3 gap-6 overflow-hidden">

                {/* Coluna 1: Lançamento de Tarefas */}
                <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 h-fit">
                    <h3 className="text-white font-bold mb-4 flex items-center gap-2">
                        <Plus size={18} className="text-emerald-400"/> Lançador de Tarefas
                    </h3>
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="text-xs text-slate-400 uppercase font-bold">O que fazer?</label>
                            <input 
                                type="text" 
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                                placeholder="Ex: Estudar React"
                                className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-emerald-500 focus:outline-none"
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="text-xs text-slate-400 uppercase font-bold">Horário (00-23)</label>
                                <input 
                                    type="time" 
                                    value={time}
                                    onChange={(e) => setTime(e.target.value)}
                                    className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-emerald-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-xs text-slate-400 uppercase font-bold">Duração (min)</label>
                                <input 
                                    type="number" 
                                    value={duration}
                                    onChange={(e) => setDuration(Number(e.target.value))}
                                    className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-emerald-500 focus:outline-none"
                                />
                            </div>
                        </div>
                        <div>
                            <label className="text-xs text-slate-400 uppercase font-bold">Categoria</label>
                            <select 
                                value={category}
                                onChange={(e) => setCategory(e.target.value as TaskCategory)}
                                className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-emerald-500 focus:outline-none"
                            >
                                <option value="work">Trabalho (Alta Performance)</option>
                                <option value="study">Estudo (Evolução)</option>
                                <option value="workout">Treino (Saúde)</option>
                                <option value="routine">Rotina (Neutro)</option>
                                <option value="leisure">Lazer (Descanso)</option>
                                <option value="wasted">Desperdício (Celular/Ocio)</option>
                            </select>
                        </div>
                        <button type="submit" className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg transition-all flex justify-center items-center gap-2">
                           Agendar Tarefa
                        </button>
                    </form>

                    <div className="mt-6 p-4 bg-slate-900/50 rounded-lg border border-slate-700/50">
                        <h4 className="text-slate-400 text-xs font-bold uppercase mb-2">Dica de Produtividade</h4>
                        <p className="text-slate-300 text-sm italic">"Lance suas tarefas na noite anterior para começar o dia com clareza total. Evite decisões pela manhã."</p>
                    </div>
                </div>

                {/* Coluna 2 e 3: Timeline Checklist */}
                <div className="lg:col-span-2 bg-slate-900 rounded-xl border border-slate-800 flex flex-col overflow-hidden">
                    <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800">
                        <h3 className="font-bold text-white flex items-center gap-2">
                             <Clock className="text-blue-400" /> Timeline do Dia (05:00 - 00:00)
                        </h3>
                        <span className="text-xs bg-slate-900 px-2 py-1 rounded text-slate-400">{sortedTasks.length} Atividades</span>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                        {sortedTasks.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center text-slate-500 opacity-50">
                                <CheckSquare size={48} className="mb-2" />
                                <p>Nenhuma atividade planejada.</p>
                            </div>
                        ) : (
                            sortedTasks.map((task) => (
                                <div key={task.id} className={`p-4 rounded-xl border flex items-center justify-between transition-all group ${getCategoryColor(task.category)} ${task.completed ? 'opacity-60 saturate-0' : 'hover:scale-[1.01]'}`}>
                                    <div className="flex items-center gap-4">
                                        <button 
                                            onClick={() => handleCheck(task.id)}
                                            className={`rounded-full p-1 transition-colors ${task.completed ? 'text-emerald-500 bg-emerald-500/20' : 'text-slate-400 hover:text-emerald-500'}`}
                                        >
                                            {task.completed ? <CheckSquare size={28} /> : <Square size={28} />}
                                        </button>

                                        <div>
                                            <div className="flex items-center gap-2">
                                                <span className={`text-xs font-mono px-1.5 py-0.5 rounded ${task.category === 'wasted' ? 'bg-red-500 text-white' : 'bg-slate-700 text-slate-300'}`}>
                                                    {task.startTime || '--:--'}
                                                </span>
                                                <h4 className={`font-bold ${task.completed ? 'text-slate-500 line-through' : 'text-white'}`}>
                                                    {task.title}
                                                </h4>
                                            </div>
                                            <div className="flex gap-3 mt-1 text-xs text-slate-400">
                                                <span className="flex items-center gap-1">{getCategoryIcon(task.category)} {task.durationMinutes} min</span>
                                                {task.category !== 'wasted' && <span className="text-yellow-500 font-bold flex items-center gap-1">+{task.xpReward} XP</span>}
                                            </div>
                                        </div>
                                    </div>

                                    <button onClick={() => onDeleteTask(task.id)} className="text-slate-600 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all p-2">
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            ))
                        )}

                        {/* Indicador de Hora de Dormir */}
                        <div className="border-t border-slate-800 pt-4 mt-8 opacity-50">
                            <div className="flex items-center gap-2 text-slate-500">
                                <Clock size={16} /> <span>00:00 - Fim do Ciclo Diário</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React from 'react';
import { Task } from '../types';
import { BarChart, Bar, XAxis, YAxis, Tooltip as ReTooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { BarChart3, AlertTriangle, TrendingUp, Smartphone, Brain, Battery } from 'lucide-react';

interface ReportsProps {
    tasks: Task[];
}

export const Reports: React.FC<ReportsProps> = ({ tasks }) => {
    // 1. Calculate Time Stats
    const totalMinutes = tasks.reduce((acc, t) => acc + t.durationMinutes, 0);

    const wastedMinutes = tasks.filter(t => t.category === 'wasted').reduce((acc, t) => acc + t.durationMinutes, 0);
    const productiveMinutes = tasks.filter(t => ['work', 'study', 'workout'].includes(t.category)).reduce((acc, t) => acc + t.durationMinutes, 0);
    const neutralMinutes = totalMinutes - wastedMinutes - productiveMinutes;

    const productiveHours = (productiveMinutes / 60).toFixed(1);
    const wastedHours = (wastedMinutes / 60).toFixed(1);

    // Assumindo um dia padrão de 16 horas acordado se não houver dados suficientes, ou usando o total logado se for maior
    const timeAwakeMinutes = Math.max(16 * 60, totalMinutes); 
    const timeAwakeHours = (timeAwakeMinutes / 60).toFixed(1);

    // Productivity Score: (Productive / (Total Logged - Neutral)) * 100
    // Neutral tasks (routine, chores) shouldn't punish the score heavily, but wasted time should.
    const denominator = (productiveMinutes + wastedMinutes) || 1;
    const productivityScore = Math.round((productiveMinutes / denominator) * 100);

    // 2. Prepare Chart Data
    const pieData = [
        { name: 'Produtivo (Trabalho/Estudo/Treino)', value: productiveMinutes },
