import React, { useState, useRef, useEffect } from 'react';
import { Message, CheckIn } from '../types';
import { chatWithNexus, getDailyInsight } from '../services/geminiService';
import { Send, Zap, Bot, User, Terminal, Sun } from 'lucide-react';

interface DashboardProps {
  onCommand: (toolName: string, args: any) => void;
  onCheckIn: (data: CheckIn) => void;
  hasCheckedIn: boolean;
}

export const Dashboard: React.FC<DashboardProps> = ({ onCommand, onCheckIn, hasCheckedIn }) => {
  // Chat State
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Nexus 360 Online. Use este chat para lançar tarefas, treinos ou finanças. Ex: "Estudei 2 horas de inglês" ou "Gastei 50 reais em mercado".',
      timestamp: new Date()
    }
  ]);
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // CheckIn State
  const [energy, setEnergy] = useState(7);
  const [mood, setMood] = useState('Neutro');
  const [sleepQuality, setSleepQuality] = useState('Médio');
  const [sleepHours, setSleepHours] = useState(7);
  const [goal, setGoal] = useState('');
  const [checkingIn, setCheckingIn] = useState(false);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const { text, functionCall } = await chatWithNexus(input, messages);

    setLoading(false);

    if (functionCall) {
        onCommand(functionCall.name, functionCall.args);

        const sysMsg: Message = {
            id: Date.now().toString() + '_sys',
            role: 'system',
            text: `Comando executado: ${functionCall.name}`,
            timestamp: new Date()
        };
        setMessages(prev => [...prev, sysMsg]);

        const responseText = text || "Registro efetuado e sincronizado com a aba correspondente.";
        setMessages(prev => [...prev, {
            id: Date.now().toString() + '_ai',
            role: 'model',
            text: responseText,
            timestamp: new Date()
        }]);

    } else if (text) {
        setMessages(prev => [...prev, {
            id: Date.now().toString() + '_ai',
            role: 'model',
            text: text,
            timestamp: new Date()
        }]);
    }
  };

  const handleCheckInSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setCheckingIn(true);
      const data: CheckIn = { energy, mood, sleepQuality, sleepHours, mainGoal: goal, timestamp: new Date().toISOString() };
      onCheckIn(data);

      // Get quick insight
      try {
        const insight = await getDailyInsight(data, "Dia anterior normal.");
        setMessages(prev => [...prev, {
            id: 'insight_' + Date.now(),
            role: 'model',
            text: `Protocolo Matinal aceito. Insight do dia: ${insight}`,
            timestamp: new Date()
        }]);
      } catch (e) {}

      setCheckingIn(false);
  };

  if (!hasCheckedIn) {
      return (
        <div className="p-6 max-w-2xl mx-auto animate-fade-in flex flex-col justify-center h-full">
            <h2 className="text-3xl font-bold mb-6 text-white flex items-center gap-2">
            <Sun className="text-yellow-400" /> Protocolo Matinal
            </h2>
            <div className="bg-slate-800 p-8 rounded-2xl shadow-xl border border-slate-700">
            <form onSubmit={handleCheckInSubmit} className="space-y-6">
                <div>
                <label className="block text-slate-400 mb-2 font-medium">Nível de Energia (0-10)</label>
                <input 
                    type="range" min="0" max="10" value={energy} 
                    onChange={(e) => setEnergy(parseInt(e.target.value))}
                    className="w-full h-2 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-blue-500"
                />
                <div className="flex justify-between text-xs text-slate-500 mt-2">
                    <span>Esgotado</span>
                    <span className="text-blue-400 font-bold text-lg">{energy}</span>
                    <span>Pico</span>
                </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-slate-400 mb-2 font-medium">Horas de Sono</label>
                        <input 
                            type="number" 
                            value={sleepHours}
                            onChange={(e) => setSleepHours(Number(e.target.value))}
                            className="w-full bg-slate-700 border border-slate-600 text-white rounded-lg p-3 focus:border-blue-500 outline-none"
                        />
                    </div>
                    <div>
                        <label className="block text-slate-400 mb-2 font-medium">Qualidade</label>
                        <select value={sleepQuality} onChange={(e) => setSleepQuality(e.target.value)} className="w-full bg-slate-700 border border-slate-600 text-white rounded-lg p-3 focus:border-blue-500 outline-none">
                        <option>Restaurador</option>
                        <option>Médio</option>
                        <option>Ruim</option>
                        </select>
                    </div>
                </div>

                <div>
                <label className="block text-slate-400 mb-2 font-medium">Objetivo Principal do Dia</label>
                <input 
                    type="text" 
                    value={goal}
                    onChange={(e) => setGoal(e.target.value)}
                    placeholder="ex: Fechar contrato Acme"
                    className="w-full bg-slate-700 border border-slate-600 text-white rounded-lg p-3 focus:border-blue-500 outline-none"
                    required
                />
                </div>

                <button type="submit" disabled={checkingIn} className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl transition-all flex items-center justify-center gap-2">
                {checkingIn ? <Zap className="animate-spin" /> : <Zap size={20} />} Inicializar Sistema
                </button>
            </form>
            </div>
        </div>
      );
  }

  return (
    <div className="flex flex-col h-[calc(100vh-100px)] md:h-[calc(100vh-40px)] max-w-4xl mx-auto">
      <header className="mb-4 flex items-center gap-3 border-b border-slate-800 pb-4">
        <div className="p-3 bg-blue-600/20 rounded-xl text-blue-400 border border-blue-500/30">
            <Terminal size={24} />
        </div>
        <div>
            <h1 className="text-2xl font-bold text-white">Central de Comando</h1>
            <p className="text-slate-400 text-sm">IA Generativa & Execução de Tarefas</p>
        </div>
      </header>

      {/* Area de Chat */}
      <div className="flex-1 overflow-y-auto space-y-4 pr-2 mb-4 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>

            <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 
                ${msg.role === 'user' ? 'bg-slate-700' : msg.role === 'system' ? 'bg-emerald-900/50' : 'bg-blue-600'}`}>
                {msg.role === 'user' ? <User size={16} /> : msg.role === 'system' ? <Zap size={16} className="text-emerald-400"/> : <Bot size={16} />}
            </div>

            <div className={`p-4 rounded-2xl max-w-[80%] text-sm leading-relaxed shadow-md
                ${msg.role === 'user' 
                    ? 'bg-slate-700 text-slate-100 rounded-tr-none' 
                    : msg.role === 'system'
                    ? 'bg-emerald-900/20 text-emerald-300 border border-emerald-500/30 font-mono text-xs'
                    : 'bg-slate-800 border border-slate-700 text-slate-200 rounded-tl-none'}`}>
              {msg.text}
            </div>
          </div>
        ))}
        {loading && (
             <div className="flex gap-3">
                 <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center animate-pulse"><Bot size={16}/></div>
                 <div className="bg-slate-800 p-4 rounded-2xl rounded-tl-none border border-slate-700 flex items-center gap-2">
                    <span className="w-2 h-2 bg-slate-500 rounded-full animate-bounce"></span>
                    <span className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-75"></span>
                    <span className="w-2 h-2 bg-slate-500 rounded-full animate-bounce delay-150"></span>
                 </div>
             </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <form onSubmit={handleSend} className="relative">
        <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Digite um comando (ex: Treinei peito hoje, Estudei 1h, Gastei 10 reais)..."
            className="w-full bg-slate-800 text-white pl-4 pr-14 py-4 rounded-xl border border-slate-700 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 focus:outline-none transition-all shadow-lg shadow-black/20"
        />
        <button 
            type="submit" 
            disabled={!input.trim() || loading}
            className="absolute right-2 top-2 p-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
            <Send size={20} />
        </button>
      </form>
    </div>
  );
};

import React from 'react';
