import React, { useState } from 'react';
import { Task, TaskCategory, UserStats } from '../types';
import { CheckSquare, Square, Trash2, Plus, Clock, Trophy, Star, AlertCircle, Smartphone } from 'lucide-react';

interface ProductivityProps {
    tasks: Task[];
    stats: UserStats;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    onAddTask: (task: Partial<Task>) => void;
}

export const Productivity: React.FC<ProductivityProps> = ({ tasks, stats, onToggleTask, onDeleteTask, onAddTask }) => {
    // Form State
    const [title, setTitle] = useState('');
    const [time, setTime] = useState('');
    const [duration, setDuration] = useState(60);
    const [category, setCategory] = useState<TaskCategory>('work');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (title.trim()) {
            onAddTask({
                title,
                startTime: time || '00:00',
                durationMinutes: duration,
                category,
                completed: false,
                xpReward: category === 'wasted' ? 0 : (duration >= 60 ? 100 : 50)
            });
            setTitle('');
            setTime('');
        }
    };

    const getCategoryColor = (cat: TaskCategory) => {
        switch(cat) {
            case 'work': return 'bg-blue-600/20 border-l-4 border-blue-500 text-blue-100';
            case 'study': return 'bg-purple-600/20 border-l-4 border-purple-500 text-purple-100';
            case 'workout': return 'bg-emerald-600/20 border-l-4 border-emerald-500 text-emerald-100';
            case 'wasted': return 'bg-red-600/20 border-l-4 border-red-500 text-red-100 opacity-60';
            case 'leisure': return 'bg-pink-600/20 border-l-4 border-pink-500 text-pink-100';
            default: return 'bg-slate-700/50 border-l-4 border-slate-500 text-slate-300';
        }
    };

    // Sort tasks strictly by time for the schedule view
    const scheduleTasks = [...tasks].sort((a, b) => {
        const timeA = a.startTime || '23:59';
        const timeB = b.startTime || '23:59';
        return timeA.localeCompare(timeB);
    });

    return (
        <div className="p-4 md:p-8 h-full flex flex-col max-w-6xl mx-auto overflow-hidden">
            <header className="mb-6">
                <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                    <CheckSquare className="text-emerald-500" /> Cronograma de Hoje
                </h1>
                <p className="text-slate-400">Organize seu dia. Tarefas lançadas no Chat aparecem aqui automaticamente.</p>
            </header>

            <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-6 overflow-hidden">

                {/* Agendamento Manual */}
                <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 h-fit">
                    <h3 className="text-white font-bold mb-4 flex items-center gap-2">
                        <Plus size={18} className="text-blue-400"/> Adicionar Evento
                    </h3>
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="text-xs text-slate-400 uppercase font-bold">Atividade</label>
                            <input 
                                type="text" 
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                                placeholder="Ex: Reunião com Cliente"
                                className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-blue-500 focus:outline-none"
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="text-xs text-slate-400 uppercase font-bold">Início</label>
                                <input 
                                    type="time" 
                                    value={time}
                                    onChange={(e) => setTime(e.target.value)}
                                    className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-blue-500 focus:outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-xs text-slate-400 uppercase font-bold">Duração (min)</label>
                                <input 
                                    type="number" 
                                    value={duration}
                                    onChange={(e) => setDuration(Number(e.target.value))}
                                    className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-blue-500 focus:outline-none"
                                />
                            </div>
                        </div>
                        <div>
                            <label className="text-xs text-slate-400 uppercase font-bold">Categoria</label>
                            <select 
                                value={category}
                                onChange={(e) => setCategory(e.target.value as TaskCategory)}
                                className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3 mt-1 focus:border-blue-500 focus:outline-none"
                            >
                                <option value="work">Trabalho</option>
                                <option value="study">Estudo</option>
                                <option value="workout">Treino</option>
                                <option value="routine">Rotina</option>
                                <option value="leisure">Lazer</option>
                                <option value="wasted">Tempo Ocioso</option>
                            </select>
                        </div>
                        <button type="submit" className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 rounded-lg transition-all">
                           Agendar no Cronograma
                        </button>
                    </form>
                </div>

                {/* Visualização de Cronograma (Timeline) */}
                <div className="md:col-span-2 bg-slate-900 rounded-xl border border-slate-800 flex flex-col overflow-hidden relative">
                    <div className="absolute top-0 left-0 w-16 h-full border-r border-slate-800 bg-slate-950/50 z-0"></div>

                    <div className="p-4 border-b border-slate-800 bg-slate-800 z-10 flex justify-between items-center">
                        <h3 className="font-bold text-white">Linha do Tempo</h3>
                        <span className="text-xs text-slate-400">{scheduleTasks.length} eventos</span>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 custom-scrollbar z-10">
                        {scheduleTasks.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-full text-slate-600">
                                <Clock size={48} className="mb-2 opacity-50"/>
                                <p>Dia livre. Adicione tarefas aqui ou via Chat.</p>
                            </div>
                        ) : (
                            <div className="space-y-4">
                                {scheduleTasks.map((task) => (
                                    <div key={task.id} className="flex group">
                                        {/* Time Column */}
                                        <div className="w-16 flex flex-col items-center pt-2 pr-4 border-r border-transparent">
                                            <span className="text-sm font-mono font-bold text-slate-400">{task.startTime}</span>
                                            <div className="h-full w-px bg-slate-800 mt-2"></div>
                                        </div>

                                        {/* Task Card */}
                                        <div className={`flex-1 ml-4 p-3 rounded-lg border ${getCategoryColor(task.category)} transition-all hover:brightness-110 relative`}>
                                            <div className="flex justify-between items-start">
                                                <div className="flex items-center gap-3">
                                                    <button onClick={() => onToggleTask(task.id)} className="text-inherit opacity-70 hover:opacity-100">
                                                        {task.completed ? <CheckSquare /> : <Square />}
                                                    </button>
                                                    <span className={`font-medium ${task.completed ? 'line-through opacity-70' : ''}`}>
                                                        {task.title}
                                                    </span>
                                                </div>
                                                <button onClick={() => onDeleteTask(task.id)} className="opacity-0 group-hover:opacity-100 text-inherit hover:text-red-400 transition-opacity">
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                            <div className="mt-2 text-xs opacity-70 flex gap-3">
                                                <span>{task.durationMinutes} min</span>
                                                <span className="uppercase tracking-wider font-bold">{task.category}</span>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { NAV_ITEMS, MOCK_TRANSACTIONS, MOCK_TASKS } from './constants';
import { NavigationTab, Transaction, WorkoutLog, Task, UserStats, TaskCategory, CheckIn } from './types';
import { Dashboard } from './components/Dashboard';
import { Professional } from './components/Professional';
import { Productivity } from './components/Productivity';
import { Body } from './components/Body';
import { Finance } from './components/Finance';
import { Reports } from './components/Reports';
import { LayoutGrid } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<NavigationTab>('dashboard');

  // -- Global Application State --
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS as any);
  const [workoutLogs, setWorkoutLogs] = useState<WorkoutLog[]>([]);
  const [tasks, setTasks] = useState<Task[]>(MOCK_TASKS);

  // CheckIn History (Stores all check-ins, allowing Reports to chart Sleep)
  const [checkIns, setCheckIns] = useState<CheckIn[]>([]);
  const [hasCheckedInToday, setHasCheckedInToday] = useState(false);

  // Gamification State
  const [userStats, setUserStats] = useState<UserStats>({
      xp: 1250,
      level: 2,
      streak: 5
  });

  // -- Command Handler for Nexus Chat --
  const handleCommand = (toolName: string, args: any) => {
      console.log("Executing Command:", toolName, args);

      if (toolName === 'addTransaction') {
          const newTx: Transaction = {
              id: Date.now().toString(),
              type: args.type.toLowerCase() as 'income' | 'expense',
              category: args.category,
              amount: Number(args.amount),
              date: new Date().toISOString()
          };
          setTransactions(prev => [...prev, newTx]);
      } 
      else if (toolName === 'logActivity') {
          const duration = Number(args.durationMinutes) || 30;
          const category = (args.category || 'work') as TaskCategory;

          const newTask: Task = {
              id: Date.now().toString(),
              title: args.title,
              completed: true, 
              category: category,
              startTime: args.startTime || new Date().toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}),
              durationMinutes: duration,
              xpReward: category === 'wasted' ? 0 : (duration > 60 ? 100 : 50),
              date: new Date().toISOString()
          };

          setTasks(prev => [...prev, newTask]);

          if (newTask.xpReward > 0) addXp(newTask.xpReward);
      }
      else if (toolName === 'logWorkout') {
          const newLog: WorkoutLog = {
              id: Date.now().toString(),
              description: args.description,
              date: new Date().toISOString()
          };
          setWorkoutLogs(prev => [...prev, newLog]);

          // Log as task too for productivity report
          const taskLog: Task = {
              id: 'wo_' + Date.now(),
              title: 'Treino: ' + args.description,
              completed: true,
              category: 'workout',
              startTime: new Date().toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'}),
              durationMinutes: 60,
              xpReward: 100,
              date: new Date().toISOString()
          };
          setTasks(prev => [...prev, taskLog]);
          addXp(100);
      }
  };

  const handleCheckIn = (data: CheckIn) => {
      setCheckIns(prev => [...prev, data]);
      setHasCheckedInToday(true);
      // Logic could be added here to check dates and prevent double check-in per day logic if needed
  };

  const addXp = (amount: number) => {
      setUserStats(prev => {
          const newXp = prev.xp + amount;
          const nextLevelXp = prev.level * 1000;
          if (newXp >= nextLevelXp) {
              return { ...prev, xp: newXp - nextLevelXp, level: prev.level + 1 };
          }
          return { ...prev, xp: newXp };
      });
  };

  const toggleTask = (id: string) => {
      setTasks(prev => prev.map(t => {
          if (t.id === id) {
              const isCompleting = !t.completed;
              if (isCompleting && t.xpReward > 0) addXp(t.xpReward);
              return { ...t, completed: isCompleting };
          }
          return t;
      }));
  };

  const deleteTask = (id: string) => {
      setTasks(prev => prev.filter(t => t.id !== id));
  };

  const addTaskDirect = (task: Partial<Task>) => {
      const newTask: Task = {
          id: Date.now().toString(),
          title: task.title || 'Nova Tarefa',
          completed: false,
          category: task.category || 'work',
          startTime: task.startTime,
          durationMinutes: task.durationMinutes || 30,
          xpReward: task.xpReward || 50,
          date: new Date().toISOString()
      };
      setTasks(prev => [...prev, newTask]);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': 
        return <Dashboard onCommand={handleCommand} onCheckIn={handleCheckIn} hasCheckedIn={hasCheckedInToday} />;
      case 'productivity': 
        return <Productivity tasks={tasks} stats={userStats} onToggleTask={toggleTask} onDeleteTask={deleteTask} onAddTask={addTaskDirect} />;
      case 'professional': 
        return <Professional />;
      case 'body': 
        return <Body workoutLogs={workoutLogs} />;
      case 'finance': 
        return <Finance transactions={transactions} />;
      case 'reports':
        return <Reports tasks={tasks} transactions={transactions} checkIns={checkIns} />;
      default: return (
        <div className="flex flex-col items-center justify-center h-full text-slate-500">
            <LayoutGrid size={48} className="mb-4 opacity-50"/>
            <p>Módulo em construção...</p>
        </div>
