export const getDailyInsight = async (checkIn: CheckIn, context: string): Promise<string> => {
  if (!apiKey) return "Insight indisponível.";
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analise este check-in matinal: ${JSON.stringify(checkIn)}. Contexto: ${context}. Dê um insight curto (max 20 palavras) para o dia.`,
      config: { systemInstruction: SYSTEM_INSTRUCTION }
    });
    return response.text || "Foco total hoje.";
  } catch (error) { return "Bom dia! Vamos pra cima."; }
};

import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { chatWithNexus } from '../services/geminiService';
import { Send, Sparkles, Bot, User, ArrowUp, DollarSign, Dumbbell, Clock, Mic, Image as ImageIcon, X, Paperclip } from 'lucide-react';

interface DashboardProps {
  onCommand: (toolName: string, args: any) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ onCommand }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [loading, setLoading] = useState(false);

  // New States for Audio/Image
  const [isListening, setIsListening] = useState(false);
  const [attachment, setAttachment] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  // --- AUDIO INPUT HANDLER ---
  const toggleListening = () => {
    if (isListening) {
        // Typically stop is handled by the event 'end', but we can force stop if needed
        setIsListening(false);
        return;
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
        alert("Seu navegador não suporta entrada de voz.");
        return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'pt-BR';
    recognition.continuous = false;
    recognition.interimResults = false;

    setIsListening(true);

    recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(prev => prev + (prev ? ' ' : '') + transcript);
        setIsListening(false);
    };

    recognition.onerror = (event: any) => {
        console.error("Speech error", event.error);
        setIsListening(false);
    };

    recognition.onend = () => {
        setIsListening(false);
    };

    recognition.start();
  };

  // --- IMAGE UPLOAD HANDLER ---
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => {
              setAttachment(reader.result as string);
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSend = async (e?: React.FormEvent, textOverride?: string) => {
    if (e) e.preventDefault();
    const textToSend = textOverride || input;

    // Allow sending if there is text OR an attachment
    if (!textToSend.trim() && !attachment) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      timestamp: new Date()
    };

    // Include a visual indicator in the message list if an image was sent (optional logic, 
    // for now we just show the text, but the image is sent to backend)
    // To visualize the image in the chat history, we could add an 'image' field to Message type later.
    // For now, let's append a small note if it's image only
    if (!textToSend.trim() && attachment) {
        userMsg.text = "📷 [Imagem enviada para análise]";
    }

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    const currentAttachment = attachment;
    setAttachment(null); // Clear attachment immediately
    setLoading(true);

    const { text, functionCall } = await chatWithNexus(textToSend, messages, currentAttachment || undefined);

    setLoading(false);

    if (functionCall) {
        onCommand(functionCall.name, functionCall.args);

        const responseText = text || "Certo, já registrei isso para você.";

        setMessages(prev => [...prev, {
            id: Date.now().toString() + '_ai',
            role: 'model',
            text: responseText,
            timestamp: new Date()
        }]);

    } else if (text) {
        setMessages(prev => [...prev, {
            id: Date.now().toString() + '_ai',
            role: 'model',
            text: text,
            timestamp: new Date()
        }]);
    }
  };

  const SuggestionCard = ({ icon: Icon, text, onClick }: any) => (
      <button 
        onClick={onClick}
        className="flex flex-col items-start gap-2 p-4 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-2xl transition-all text-left group w-full"
      >
          <div className="p-2 rounded-full bg-slate-900 group-hover:bg-slate-800 text-blue-400">
            <Icon size={18} />
          </div>
          <span className="text-sm text-slate-300 font-medium">{text}</span>
      </button>
  );

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto relative">

      {/* Header Minimalista */}
      <header className="absolute top-0 left-0 right-0 p-4 z-10 flex justify-between items-center bg-gradient-to-b from-slate-900 to-transparent">
        <div className="flex items-center gap-2">
            <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">
                Nexus AI
            </span>
            <span className="text-xs px-2 py-0.5 rounded-full bg-blue-500/10 text-blue-400 border border-blue-500/20">Beta</span>
        </div>
      </header>

      {/* Área Principal */}
      <div className="flex-1 overflow-y-auto pt-16 pb-32 px-4 scrollbar-hide">

        {/* Estado Vazio (Welcome) */}
        {messages.length === 0 && (
            <div className="flex flex-col items-center justify-center min-h-[60vh] animate-fade-in">
                <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-600/20 mb-6">
                    <Sparkles size={32} className="text-white" />
                </div>
                <h2 className="text-3xl font-bold text-white mb-2 text-center">Como posso ajudar hoje?</h2>
                <p className="text-slate-400 text-center max-w-md mb-12">
                    Sou seu controlador geral. Posso analisar fotos de documentos, registrar gastos por voz e organizar seu dia.
                </p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full max-w-2xl">
                    <SuggestionCard 
                        icon={DollarSign} 
                        text="Gastei R$ 45,00 no almoço" 
                        onClick={() => handleSend(undefined, "Gastei R$ 45,00 no almoço")}
                    />
                     <SuggestionCard 
                        icon={ImageIcon} 
                        text="Analise esta foto (conta/gráfico)" 
                        onClick={() => {
                            // Trigger file upload programmatically
                            fileInputRef.current?.click();
                        }}
                    />
                    <SuggestionCard 
                        icon={Dumbbell} 
                        text="Treinei superiores por 1 hora" 
                        onClick={() => handleSend(undefined, "Treinei superiores por 1 hora")}
                    />
                    <SuggestionCard 
                        icon={Mic} 
                        text="Falar sobre minha rotina" 
                        onClick={toggleListening}
                    />
                </div>
            </div>
        )}

        {/* Lista de Mensagens */}
        <div className="space-y-6 max-w-3xl mx-auto">
            {messages.map((msg) => (
            <div key={msg.id} className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>

                {msg.role !== 'user' && (
                    <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-gradient-to-br from-blue-600 to-purple-600 shadow-lg mt-1">
                        <Bot size={16} className="text-white" />
                    </div>
                )}

                <div className={`p-4 rounded-2xl max-w-[85%] text-sm leading-relaxed shadow-sm
                    ${msg.role === 'user' 
                        ? 'bg-slate-800 text-slate-100 rounded-tr-sm' 
                        : 'text-slate-200'}`}>
                    {msg.role === 'model' ? (
                        <div className="prose prose-invert prose-sm max-w-none">
                           {msg.text.split('\n').map((line, i) => <p key={i} className="mb-2 last:mb-0">{line}</p>)}
                        </div>
                    ) : (
                        msg.text
                    )}
                </div>

                {msg.role === 'user' && (
                    <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-slate-700 mt-1">
                        <User size={16} className="text-slate-300" />
                    </div>
                )}
            </div>
            ))}

            {loading && (
                <div className="flex gap-4 max-w-3xl mx-auto">
                     <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-gradient-to-br from-blue-600 to-purple-600 shadow-lg mt-1">
                        <Sparkles size={16} className="text-white animate-pulse" />
                    </div>
                    <div className="flex items-center gap-1 h-10">
                        <span className="w-2 h-2 bg-slate-600 rounded-full animate-bounce"></span>
                        <span className="w-2 h-2 bg-slate-600 rounded-full animate-bounce delay-75"></span>
                        <span className="w-2 h-2 bg-slate-600 rounded-full animate-bounce delay-150"></span>
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>
      </div>

      {/* Input Flutuante */}
      <div className="absolute bottom-6 left-0 right-0 px-4 flex justify-center">
        <form onSubmit={(e) => handleSend(e)} className="w-full max-w-3xl relative flex flex-col items-center">

            {/* Image Preview */}
            {attachment && (
                <div className="self-start mb-2 relative bg-slate-800 p-2 rounded-xl border border-slate-700 animate-fade-in">
                    <img src={attachment} alt="Preview" className="h-24 rounded-lg object-cover" />
                    <button 
                        type="button"
                        onClick={() => setAttachment(null)}
                        className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg hover:bg-red-600 transition-colors"
                    >
                        <X size={14} />
                    </button>
                </div>
            )}

            <div className="relative w-full">
                {/* Hidden File Input */}
                <input 
                    type="file" 
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    accept="image/*"
                    className="hidden"
                />

                <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder={isListening ? "Ouvindo sua voz..." : "Converse ou envie uma foto..."}
                    className={`w-full bg-slate-800/90 backdrop-blur-md text-white pl-12 pr-28 py-4 rounded-full border shadow-2xl focus:outline-none transition-all placeholder:text-slate-500
                        ${isListening ? 'border-red-500/50 ring-1 ring-red-500/50' : 'border-slate-700 focus:border-blue-500 focus:ring-1 focus:ring-blue-500'}
                    `}
                />

                {/* Image Upload Button */}
                <button 
                    type="button"
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute left-3 top-3 bottom-3 aspect-square text-slate-400 hover:text-blue-400 hover:bg-slate-700/50 rounded-full transition-all flex items-center justify-center"
                    title="Anexar Imagem"
                >
                    <Paperclip size={20} />
                </button>

                {/* Right Side Buttons */}
                <div className="absolute right-2 top-2 bottom-2 flex items-center gap-1">
                    {/* Mic Button */}
                    <button 
                        type="button"
                        onClick={toggleListening}
                        className={`aspect-square rounded-full transition-all flex items-center justify-center w-10 h-10
                            ${isListening 
                                ? 'bg-red-500 text-white animate-pulse' 
                                : 'text-slate-400 hover:bg-slate-700 hover:text-white'
                            }`}
                        title="Entrada de Voz"
                    >
                        <Mic size={20} />
                    </button>

                    {/* Send Button */}
                    <button 
                        type="submit" 
                        disabled={(!input.trim() && !attachment) || loading}
                        className="aspect-square bg-blue-600 hover:bg-blue-500 text-white rounded-full transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center shadow-lg w-10 h-10"
                    >
                        {loading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"/> : <ArrowUp size={20} />}
                    </button>
                </div>
            </div>
        </form>
      </div>

    </div>
  );
};

import React, { useState } from 'react';
import { Task, Transaction, CheckIn, TaskCategory } from '../types';
import { BarChart, Bar, LineChart, Line, XAxis, YAxis, Tooltip as ReTooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { BarChart3, AlertTriangle, TrendingUp, Smartphone, Brain, Moon, DollarSign, Wallet, Briefcase, List, PieChart as PieChartIcon, CheckCircle2, XCircle, Clock, Calendar } from 'lucide-react';

interface ReportsProps {
    tasks: Task[];
    transactions: Transaction[];
    checkIns: CheckIn[];
}

export const Reports: React.FC<ReportsProps> = ({ tasks, transactions, checkIns }) => {
    const [activeTab, setActiveTab] = useState<'overview' | 'tasks'>('overview');

    // --- STATISTICS CALCULATION ---

    // 1. Productivity Stats (Include ALL categories)
    const getMinutes = (cat: TaskCategory) => tasks.filter(t => t.category === cat).reduce((acc, t) => acc + t.durationMinutes, 0);

    const workMinutes = getMinutes('work');
    const studyMinutes = getMinutes('study');
    const workoutMinutes = getMinutes('workout');
    const routineMinutes = getMinutes('routine');
    const leisureMinutes = getMinutes('leisure');
    const wastedMinutes = getMinutes('wasted');

    // 2. Financial Stats (Today & Weekly)
    const today = new Date().toISOString().split('T')[0];
    const todayIncome = transactions.filter(t => t.type === 'income' && t.date.startsWith(today)).reduce((acc, t) => acc + t.amount, 0);
    const todayExpense = transactions.filter(t => t.type === 'expense' && t.date.startsWith(today)).reduce((acc, t) => acc + t.amount, 0);
    const totalIncome = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const totalExpense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);

    // 3. Sleep Stats
    const latestSleep = checkIns.length > 0 ? checkIns[checkIns.length - 1].sleepHours : 0;
    const avgSleep = checkIns.length > 0 ? (checkIns.reduce((acc, c) => acc + c.sleepHours, 0) / checkIns.length).toFixed(1) : 0;

    // --- CHART DATA ---

    // Pie Chart Data (Time Distribution) - Now inclusive
    const timeDistData = [
        { name: 'Trabalho', value: workMinutes, color: '#3b82f6' }, // Blue
        { name: 'Estudo', value: studyMinutes, color: '#8b5cf6' }, // Purple
        { name: 'Treino', value: workoutMinutes, color: '#10b981' }, // Emerald
        { name: 'Rotina', value: routineMinutes, color: '#f59e0b' }, // Amber (Lunch, Haircut etc)
        { name: 'Lazer', value: leisureMinutes, color: '#ec4899' }, // Pink
        { name: 'Ocioso', value: wastedMinutes, color: '#ef4444' }, // Red
    ].filter(d => d.value > 0);

    // Sleep History Data
    const sleepData = checkIns.map((c, i) => ({
        day: `D${i+1}`,
        hours: c.sleepHours
    }));

    // Helper for task list styling
    const getCategoryStyle = (cat: TaskCategory) => {
        switch(cat) {
            case 'work': return 'bg-blue-500/20 text-blue-400 border-blue-500/30';
            case 'study': return 'bg-purple-500/20 text-purple-400 border-purple-500/30';
            case 'workout': return 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30';
            case 'wasted': return 'bg-red-500/20 text-red-400 border-red-500/30';
            case 'leisure': return 'bg-pink-500/20 text-pink-400 border-pink-500/30';
            case 'routine': return 'bg-amber-500/20 text-amber-400 border-amber-500/30';
            default: return 'bg-slate-500/20 text-slate-400 border-slate-500/30';
        }
    };

    const getCategoryLabel = (cat: string) => {
        const labels: {[key: string]: string} = {
            work: 'Trabalho', study: 'Estudo', workout: 'Treino', 
            routine: 'Rotina', leisure: 'Lazer', wasted: 'Ocioso'
        };
        return labels[cat] || cat;
    };

    return (
        <div className="p-4 md:p-8 h-full flex flex-col gap-8 overflow-y-auto pb-24">
            <header className="flex flex-col md:flex-row md:justify-between md:items-end gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                        <BarChart3 className="text-blue-500" /> Relatórios
                    </h1>
                    <p className="text-slate-400">Análise detalhada de performance e atividades.</p>
                </div>

                {/* Navigation Tabs */}
                <div className="bg-slate-800 p-1 rounded-lg flex gap-1 border border-slate-700">
                    <button 
                        onClick={() => setActiveTab('overview')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'overview' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
                    >
                        <PieChartIcon size={16} />
                        Visão Geral
                    </button>
                    <button 
                        onClick={() => setActiveTab('tasks')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all ${activeTab === 'tasks' ? 'bg-blue-600 text-white shadow' : 'text-slate-400 hover:text-white hover:bg-slate-700'}`}
                    >
                        <List size={16} />
                        Histórico de Atividades
                    </button>
                </div>
            </header>

            {/* --- TAB CONTENT: OVERVIEW --- */}
            {activeTab === 'overview' && (
                <div className="space-y-8 animate-fade-in">
                    {/* KPI CARDS */}
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                        {/* Sono */}
                        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700">
                            <p className="text-slate-400 text-xs uppercase font-bold flex items-center gap-2"><Moon size={14}/> Sono (Última Noite)</p>
                            <h2 className="text-3xl font-bold text-indigo-400 mt-2">{latestSleep}h</h2>
                            <p className="text-xs text-slate-500">Média: {avgSleep}h</p>
                        </div>

                        {/* Estudo */}
                        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700">
                            <p className="text-slate-400 text-xs uppercase font-bold flex items-center gap-2"><Brain size={14}/> Estudos (Total)</p>
                            <h2 className="text-3xl font-bold text-white mt-2">{(studyMinutes / 60).toFixed(1)}h</h2>
                        </div>

                        {/* Trabalho */}
                        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700">
                            <p className="text-slate-400 text-xs uppercase font-bold flex items-center gap-2"><Briefcase size={14} /> Trabalho (Total)</p>
                            <h2 className="text-3xl font-bold text-blue-400 mt-2">{(workMinutes / 60).toFixed(1)}h</h2>
                        </div>

                        {/* Dinheiro Hoje */}
                        <div className="bg-slate-800 p-5 rounded-xl border border-slate-700">
                            <p className="text-slate-400 text-xs uppercase font-bold flex items-center gap-2"><Wallet size={14}/> Caixa Diário</p>
                            <div className="mt-2">
                                <span className="text-emerald-400 font-bold block text-lg">+ R$ {todayIncome}</span>
                                <span className="text-red-400 font-bold block text-sm">- R$ {todayExpense}</span>
                            </div>
                        </div>
                    </div>

                    {/* CHARTS */}
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                        {/* 1. Gráfico de Produtividade (Pizza) */}
                        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col min-h-[350px]">
                            <h3 className="text-white font-bold mb-4">Distribuição do Tempo (Todas Categorias)</h3>
                            <div className="flex-1 w-full">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie
                                            data={timeDistData}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={60}
                                            outerRadius={80}
                                            paddingAngle={5}
                                            dataKey="value"
                                        >
                                            {timeDistData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={entry.color} />
                                            ))}
                                        </Pie>
                                        <ReTooltip 
                                            contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff'}}
                                            formatter={(value: number) => [`${value} min`, 'Tempo']}
                                        />
                                        <Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        {/* 2. Finanças (Barra Comparativa Total) */}
                        <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex flex-col min-h-[350px]">
                            <h3 className="text-white font-bold mb-4">Finanças Totais (Acumulado)</h3>
                            <div className="flex-1 w-full">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={[
                                        { name: 'Receita', value: totalIncome, fill: '#10b981' },
                                        { name: 'Despesa', value: totalExpense, fill: '#ef4444' }
                                    ]}>
                                        <XAxis dataKey="name" stroke="#64748b" tickLine={false} axisLine={false} />
                                        <YAxis stroke="#64748b" tickLine={false} axisLine={false} />
                                        <ReTooltip 
                                            cursor={{fill: 'rgba(255,255,255,0.05)'}}
                                            contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff'}}
                                        />
                                        <Bar dataKey="value" radius={[4, 4, 0, 0]} barSize={60}>
                                            {
                                                [
                                                    { name: 'Receita', value: totalIncome, fill: '#10b981' },
                                                    { name: 'Despesa', value: totalExpense, fill: '#ef4444' }
                                                ].map((entry, index) => (
                                                    <Cell key={`cell-${index}`} fill={entry.fill} />
                                                ))
                                            }
                                        </Bar>
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    </div>

                    {/* SLEEP TREND */}
                    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 min-h-[250px]">
                        <h3 className="text-white font-bold mb-4 flex items-center gap-2"><Moon className="text-indigo-400"/> Tendência de Sono</h3>
                        <div className="w-full h-[200px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <LineChart data={sleepData}>
                                    <XAxis dataKey="day" stroke="#64748b" tickLine={false} axisLine={false} />
                                    <YAxis stroke="#64748b" tickLine={false} axisLine={false} domain={[0, 12]}/>
                                    <ReTooltip contentStyle={{backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff'}} />
                                    <Line type="monotone" dataKey="hours" stroke="#818cf8" strokeWidth={3} dot={{r: 4, fill: '#818cf8'}} />
                                </LineChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>
            )}

            {/* --- TAB CONTENT: TASKS HISTORY --- */}
            {activeTab === 'tasks' && (
                <div className="bg-slate-800 rounded-xl border border-slate-700 overflow-hidden animate-fade-in flex-1">
                     <div className="p-4 border-b border-slate-700 bg-slate-800/50 flex justify-between items-center">
                        <h3 className="font-bold text-white flex items-center gap-2">
                            <List size={18} className="text-blue-400"/> Registro Completo de Atividades
                        </h3>
                        <span className="text-xs text-slate-500 bg-slate-900 px-2 py-1 rounded border border-slate-700">
                            {tasks.length} registros
                        </span>
                     </div>

                     <div className="overflow-x-auto">
                        <table className="w-full text-left text-sm">
                            <thead className="bg-slate-900/50 text-slate-400 uppercase text-xs font-bold">
                                <tr>
