                                                    {task.startTime || '--:--'}
                                                </div>
                                            </td>
                                            <td className="p-4 text-right text-slate-300 font-mono">
                                                {task.durationMinutes} min
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                        </table>
                     </div>
