    name: '',
    company: '',
    cpfCnpj: '',
    instagram: '',
    phone: '',
    state: '',
    location: '',
    value: 0,
    status: 'lead',
    probability: 10,
    nextAction: 'Iniciar contato'
  });

  const handleAnalyze = async () => {
    setAnalyzing(true);
    const result = await analyzeCRM(leads);
    setAiAnalysis(result);
    setAnalyzing(false);
  };

  const handleSaveClient = (e: React.FormEvent) => {
      e.preventDefault();
      if (!formData.name) return;

      const newClient: Lead = {
          id: Date.now().toString(),
          name: formData.name || 'Cliente Sem Nome',
          company: formData.company || 'N/A',
          status: (formData.status as any) || 'lead',
          value: Number(formData.value) || 0,
          probability: Number(formData.probability) || 0,
          lastContact: new Date().toISOString().split('T')[0],
          nextAction: formData.nextAction || 'Definir próximos passos',
          cpfCnpj: formData.cpfCnpj,
          instagram: formData.instagram,
          phone: formData.phone,
          state: formData.state,
          location: formData.location
      };

      setLeads([...leads, newClient]);
      setShowForm(false);
      // Reset form
      setFormData({
        name: '', company: '', cpfCnpj: '', instagram: '', phone: '', state: '', location: '', value: 0, status: 'lead', probability: 10, nextAction: 'Iniciar contato'
      });
  };

  // --- DRAG AND DROP HANDLERS ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      setDraggedLeadId(id);
      e.dataTransfer.effectAllowed = 'move';
      // Set a transparent drag image or similar if needed, but default is usually fine
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); // Necessary to allow dropping
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, newStatus: Lead['status']) => {
      e.preventDefault();
      if (!draggedLeadId) return;

      setLeads(prevLeads => prevLeads.map(lead => {
          if (lead.id === draggedLeadId) {
              return { ...lead, status: newStatus };
          }
          return lead;
      }));
      setDraggedLeadId(null);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'proposal': return 'bg-purple-500/20 text-purple-400 border-purple-500/30';
      case 'negotiation': return 'bg-amber-500/20 text-amber-400 border-amber-500/30';
      case 'closed': return 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30';
      case 'lost': return 'bg-red-500/20 text-red-400 border-red-500/30';
      default: return 'bg-blue-500/20 text-blue-400 border-blue-500/30';
    }
  };

  const getStatusLabel = (status: string) => {
      switch (status) {
          case 'proposal': return 'Proposta';
          case 'negotiation': return 'Negociação';
          case 'closed': return 'Fechado';
          case 'lost': return 'Perdido';
          case 'lead': return 'Lead';
          case 'contact': return 'Contato';
          default: return status;
      }
  }

  const totalPipeline = leads.reduce((acc, lead) => acc + lead.value, 0);
  const weightedPipeline = leads.reduce((acc, lead) => acc + (lead.value * (lead.probability / 100)), 0);

  // Kanban Columns Configuration
  const columns: { id: Lead['status'], label: string, color: string }[] = [
      { id: 'lead', label: 'Novos Leads', color: 'border-blue-500/50' },
      { id: 'contact', label: 'Em Contato', color: 'border-cyan-500/50' },
      { id: 'proposal', label: 'Proposta Enviada', color: 'border-purple-500/50' },
      { id: 'negotiation', label: 'Em Negociação', color: 'border-amber-500/50' },
      { id: 'closed', label: 'Fechado / Ganho', color: 'border-emerald-500/50' },
      { id: 'lost', label: 'Perdido', color: 'border-red-500/50' },
  ];

  return (
    <div className="p-4 md:p-8 h-full flex flex-col relative overflow-hidden">
      <header className="flex flex-col md:flex-row md:justify-between md:items-center mb-6 gap-4 flex-shrink-0">
        <div>
            <h1 className="text-3xl font-bold text-white">CRM Profissional</h1>
            <p className="text-slate-400">Gestão de Funil e Pipeline</p>
        </div>
        <div className="flex gap-2">
            <div className="bg-slate-800 p-1 rounded-lg border border-slate-700 flex mr-2">
                <button 
                    onClick={() => setViewMode('kanban')}
                    className={`p-2 rounded ${viewMode === 'kanban' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                    title="Visão de Funil"
                >
                    <LayoutGrid size={18} />
                </button>
                <button 
                    onClick={() => setViewMode('list')}
                    className={`p-2 rounded ${viewMode === 'list' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                    title="Visão de Lista"
                >
                    <ListIcon size={18} />
                </button>
            </div>
            <button 
                onClick={() => setShowForm(true)}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 px-4 py-2 rounded-lg text-white font-medium transition-all shadow-lg shadow-emerald-900/20"
            >
                <Plus size={18} /> Novo Cliente
            </button>
            <button 
                onClick={handleAnalyze}
                disabled={analyzing}
                className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-4 py-2 rounded-lg text-white font-medium transition-all disabled:opacity-50"
            >
                <Brain size={18} /> {analyzing ? 'Analisando...' : 'Auditoria IA'}
            </button>
        </div>
      </header>

      {/* KPI Cards (Compact) */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6 flex-shrink-0">
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Pipeline Total</span>
                <p className="text-xl font-bold text-white">${totalPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400"><DollarSign size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Ponderado</span>
                <p className="text-xl font-bold text-white">${weightedPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-400"><TrendingUp size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                 <span className="text-slate-400 text-xs font-medium uppercase">Leads Ativos</span>
                <p className="text-xl font-bold text-white">{leads.length}</p>
            </div>
            <div className="p-2 bg-purple-500/10 rounded-lg text-purple-400"><Users size={20} /></div>
        </div>
      </div>

      {aiAnalysis && (
        <div className="mb-6 bg-indigo-900/20 border border-indigo-500/50 p-4 rounded-xl animate-fade-in flex-shrink-0">
            <h3 className="text-indigo-400 font-bold mb-1 flex items-center gap-2"><Brain size={16}/> Insight Estratégico</h3>
            <p className="text-slate-200 text-sm">{aiAnalysis}</p>
        </div>
      )}

      {/* --- KANBAN FUNNEL VIEW --- */}
      {viewMode === 'kanban' && (
          <div className="flex-1 overflow-x-auto pb-4 custom-scrollbar">
              <div className="flex gap-4 min-w-[1200px] h-full">
                  {columns.map(col => {
                      const colLeads = leads.filter(l => l.status === col.id);
                      const colValue = colLeads.reduce((acc, l) => acc + l.value, 0);

                      return (
                          <div 
                            key={col.id}
                            onDragOver={handleDragOver}
                            onDrop={(e) => handleDrop(e, col.id)}
                            className={`flex-1 min-w-[280px] bg-slate-800/50 rounded-xl border-t-4 ${col.color} border-x border-b border-slate-700 flex flex-col h-full`}
                          >
                              {/* Column Header */}
                              <div className="p-3 border-b border-slate-700 bg-slate-800 rounded-t-lg">
                                  <div className="flex justify-between items-center mb-1">
                                      <h3 className="font-bold text-slate-200 text-sm uppercase tracking-wide">{col.label}</h3>
                                      <span className="text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">{colLeads.length}</span>
                                  </div>
                                  <p className="text-xs text-slate-500 font-mono">R$ {colValue.toLocaleString()}</p>
                              </div>

                              {/* Drop Zone / List */}
                              <div className="flex-1 p-3 space-y-3 overflow-y-auto custom-scrollbar">
                                  {colLeads.map(lead => (
                                      <div
                                        key={lead.id}
                                        draggable
                                        onDragStart={(e) => handleDragStart(e, lead.id)}
                                        className={`
                                            bg-slate-800 p-4 rounded-lg border border-slate-600 shadow-sm cursor-move 
                                            hover:border-blue-400 hover:shadow-lg hover:shadow-blue-900/10 transition-all group
                                            ${draggedLeadId === lead.id ? 'opacity-50 ring-2 ring-blue-500 ring-offset-2 ring-offset-slate-900' : ''}
                                        `}
                                      >
                                          <div className="flex justify-between items-start mb-2">
                                              <h4 className="font-bold text-white text-sm">{lead.name}</h4>
                                              <GripVertical size={14} className="text-slate-600 opacity-0 group-hover:opacity-100" />
                                          </div>

                                          <div className="text-xs text-slate-400 mb-3 flex items-center gap-1">
                                              <Building2 size={12}/> {lead.company}
                                          </div>

                                          <div className="flex justify-between items-end">
                                              <div>
                                                  <p className="text-[10px] text-slate-500 uppercase font-bold">Valor</p>
                                                  <p className="text-emerald-400 font-mono text-sm font-medium">R$ {lead.value.toLocaleString()}</p>
                                              </div>
                                              {lead.probability > 0 && (
                                                  <div className="text-right">
                                                      <p className="text-[10px] text-slate-500 uppercase font-bold">Prob.</p>
                                                      <p className={`text-sm font-medium ${lead.probability > 70 ? 'text-green-400' : lead.probability > 30 ? 'text-amber-400' : 'text-red-400'}`}>
                                                          {lead.probability}%
                                                      </p>
                                                  </div>
                                              )}
                                          </div>

                                          {/* Action / Next Step */}
                                          <div className="mt-3 pt-2 border-t border-slate-700/50">
                                              <p className="text-[10px] text-slate-500 flex items-center gap-1 truncate">
                                                  <TrendingUp size={10} /> {lead.nextAction}
                                              </p>
                                          </div>
                                      </div>
                                  ))}
                                  {colLeads.length === 0 && (
                                      <div className="h-24 border-2 border-dashed border-slate-700/50 rounded-lg flex items-center justify-center text-slate-600 text-xs">
                                          Arraste para cá
                                      </div>
                                  )}
                              </div>
                          </div>
                      );
                  })}
              </div>
          </div>
      )}

      {/* --- LIST VIEW (Original) --- */}
      {viewMode === 'list' && (
        <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden flex-1 overflow-y-auto">
            <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-slate-900/50 border-b border-slate-700 text-slate-400 text-sm uppercase tracking-wider sticky top-0 bg-slate-900 z-10">
                            <th className="p-4">Lead / Empresa</th>
                            <th className="p-4">Contato</th>
                            <th className="p-4">Status</th>
                            <th className="p-4">Valor</th>
                            <th className="p-4">Probabilidade</th>
                            <th className="p-4"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-700">
                        {leads.map((lead) => (
                            <tr key={lead.id} className="hover:bg-slate-700/30 transition-colors group">
                                <td className="p-4">
                                    <p className="font-bold text-white flex items-center gap-2">{lead.name}</p>
                                    <p className="text-xs text-slate-500 flex items-center gap-1">
                                        <Building2 size={10} /> {lead.company}
                                    </p>
                                    {lead.location && <p className="text-[10px] text-slate-500 flex items-center gap-1 mt-0.5"><MapPin size={8} /> {lead.location} - {lead.state}</p>}
                                </td>
                                <td className="p-4">
                                    <div className="space-y-1">
                                        {lead.phone && <p className="text-xs text-slate-300 flex items-center gap-1"><Phone size={10} /> {lead.phone}</p>}
                                        {lead.instagram && <p className="text-xs text-slate-300 flex items-center gap-1"><Instagram size={10} /> {lead.instagram}</p>}
                                        {lead.cpfCnpj && <p className="text-[10px] text-slate-500">Doc: {lead.cpfCnpj}</p>}
                                    </div>
                                </td>
                                <td className="p-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-bold border ${getStatusColor(lead.status)}`}>
                                        {getStatusLabel(lead.status)}
                                    </span>
                                </td>
                                <td className="p-4 text-slate-300 font-mono">${lead.value.toLocaleString()}</td>
                                <td className="p-4">
                                    <div className="flex items-center gap-2">
                                        <div className="w-16 h-1.5 bg-slate-700 rounded-full overflow-hidden">
                                            <div className="h-full bg-blue-500" style={{ width: `${lead.probability}%` }}></div>
                                        </div>
                                        <span className="text-xs text-slate-400">{lead.probability}%</span>
                                    </div>
                                </td>
                                <td className="p-4 text-right">
                                    <button className="text-slate-500 hover:text-white p-2">
                                        <MoreHorizontal size={18} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
      )}

      {/* MODAL DE CADASTRO DE CLIENTE */}
      {showForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
              <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl">
                  <header className="p-6 border-b border-slate-800 flex justify-between items-center sticky top-0 bg-slate-900 z-10">
                      <h2 className="text-xl font-bold text-white flex items-center gap-2">
                          <Plus className="text-emerald-500" /> Cadastro de Novo Cliente
                      </h2>
                      <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-white">
                          <X size={24} />
                      </button>
                  </header>

                  <form onSubmit={handleSaveClient} className="p-6 space-y-6">
                      {/* Dados Principais */}
                      <div className="space-y-4">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <User size={14} /> Informações Básicas
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Nome Completo *</label>
                                  <input 
                                    required
                                    type="text" 
                                    value={formData.name} 
                                    onChange={e => setFormData({...formData, name: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Ex: João Silva"
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Empresa</label>
                                  <input 
                                    type="text" 
                                    value={formData.company} 
                                    onChange={e => setFormData({...formData, company: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Ex: Minha Empresa Ltda"
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">CPF ou CNPJ</label>
                                  <input 
                                    type="text" 
                                    value={formData.cpfCnpj} 
                                    onChange={e => setFormData({...formData, cpfCnpj: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="000.000.000-00"
                                  />
                              </div>
                          </div>
                      </div>

                      {/* Contato e Localização */}
                      <div className="space-y-4 pt-4 border-t border-slate-800">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <MapPin size={14} /> Contato & Localização
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div>
                                  <label className="block text-xs text-slate-400 mb-1">Telefone</label>
                                  <div className="relative">
                                    <Phone className="absolute left-3 top-3.5 text-slate-500" size={16} />
                                    <input 
                                        type="text" 
                                        value={formData.phone} 
                                        onChange={e => setFormData({...formData, phone: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 pl-10 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                    />
                                  </div>
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Instagram da Empresa</label>
                                  <div className="relative">
                                    <Instagram className="absolute left-3 top-3.5 text-slate-500" size={16} />
                                    <input 
                                        type="text" 
                                        value={formData.instagram} 
                                        onChange={e => setFormData({...formData, instagram: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 pl-10 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="@usuario"
                                    />
                                  </div>
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Estado (UF)</label>
                                  <input 
                                    type="text" 
                                    value={formData.state} 
                                    onChange={e => setFormData({...formData, state: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="SP, RJ, MG..."
                                    maxLength={2}
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Onde Fica (Cidade/Endereço)</label>
                                  <input 
                                    type="text" 
                                    value={formData.location} 
                                    onChange={e => setFormData({...formData, location: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Cidade ou Bairro"
                                  />
                              </div>
                          </div>
                      </div>

                       {/* Dados do Pipeline (Opcionais para cadastro rápido) */}
                       <div className="space-y-4 pt-4 border-t border-slate-800">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <TrendingUp size={14} /> Dados do Pipeline (Inicial)
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <div>
                                    <label className="block text-xs text-slate-400 mb-1">Valor Potencial ($)</label>
                                    <input 
                                        type="number" 
                                        value={formData.value} 
                                        onChange={e => setFormData({...formData, value: Number(e.target.value)})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs text-slate-400 mb-1">Fase do Pipeline</label>
                                    <select 
                                        value={formData.status} 
                                        onChange={e => setFormData({...formData, status: e.target.value as any})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    >
                                        <option value="lead">Lead</option>
                                        <option value="contact">Contato</option>
                                        <option value="proposal">Proposta</option>
                                        <option value="negotiation">Negociação</option>
                                        <option value="closed">Fechado</option>
                                    </select>
                                </div>
                          </div>
                       </div>

                      <div className="pt-6 flex gap-3">
                          <button 
                            type="button" 
                            onClick={() => setShowForm(false)}
                            className="flex-1 py-3 bg-slate-800 text-slate-300 font-bold rounded-lg hover:bg-slate-700 transition-colors"
                          >
                            Cancelar
                          </button>
                          <button 
                            type="submit" 
                            className="flex-1 py-3 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-500 transition-colors flex justify-center items-center gap-2"
                          >
                            <Save size={18} /> Salvar Cliente
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

export type NavigationTab = 'dashboard' | 'professional' | 'body' | 'finance' | 'productivity' | 'reports';

export interface CheckIn {
  energy: number; // 0-10
  mood: string;
  sleepQuality: string;
  sleepHours: number; // New field for reporting
  mainGoal: string;
  timestamp: string;
}

export type TaskCategory = 'work' | 'study' | 'workout' | 'routine' | 'wasted' | 'leisure';

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  category: TaskCategory;
  startTime?: string; // HH:mm
  endTime?: string;   // HH:mm
  durationMinutes: number;
  xpReward: number;
  date: string; // ISO Date string for filtering daily/weekly
}

export interface Lead {
  id: string;
  name: string;
  company: string;
  status: 'lead' | 'contact' | 'proposal' | 'negotiation' | 'closed' | 'followup' | 'lost';
  value: number;
  probability: number;
  lastContact: string;
  nextAction: string;
  // New Contact Fields
  cpfCnpj?: string;
  instagram?: string;
  phone?: string;
  state?: string;
  location?: string;
}

export interface WorkoutProfile {
  sex: string;
  age: number;
  weight: number;
  goal: 'weight_loss' | 'hypertrophy' | 'conditioning' | 'health';
  limitations: string;
}

export interface WorkoutLog {
    id: string;
    description: string;
    date: string;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  category: string;
  amount: number;
  date: string;
}

export interface Message {
    id: string;
    role: 'user' | 'model' | 'system';
    text: string;
    timestamp: Date;
}

export interface UserStats {
    xp: number;
    level: number;
    streak: number;
}

import React, { useState } from 'react';
import { Lead } from '../types';
import { MOCK_LEADS } from '../constants';
import { analyzeCRM } from '../services/geminiService';
import { TrendingUp, Users, DollarSign, Brain, MoreHorizontal, Plus, X, Save, MapPin, Instagram, Phone, Building2, User, LayoutGrid, List as ListIcon, GripVertical } from 'lucide-react';

export const Professional: React.FC = () => {
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS as any);
  const [aiAnalysis, setAiAnalysis] = useState<string>("");
  const [analyzing, setAnalyzing] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [viewMode, setViewMode] = useState<'list' | 'kanban'>('kanban'); // Default to kanban for the funnel request
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState<Partial<Lead>>({
    name: '',
    company: '',
    cpfCnpj: '',
    instagram: '',
    phone: '',
    state: '',
    location: '',
    value: 0,
    status: 'lead',
    probability: 10,
    nextAction: 'Iniciar contato'
  });

  const handleAnalyze = async () => {
    setAnalyzing(true);
    const result = await analyzeCRM(leads);
    setAiAnalysis(result);
    setAnalyzing(false);
  };

  const handleSaveClient = (e: React.FormEvent) => {
      e.preventDefault();
      if (!formData.name) return;

      const newClient: Lead = {
          id: Date.now().toString(),
          name: formData.name || 'Cliente Sem Nome',
          company: formData.company || 'N/A',
          status: (formData.status as any) || 'lead',
          value: Number(formData.value) || 0,
          probability: Number(formData.probability) || 0,
          lastContact: new Date().toISOString().split('T')[0],
          nextAction: formData.nextAction || 'Definir próximos passos',
          cpfCnpj: formData.cpfCnpj,
          instagram: formData.instagram,
          phone: formData.phone,
          state: formData.state,
          location: formData.location
      };

      setLeads([...leads, newClient]);
      setShowForm(false);
      // Reset form
      setFormData({
        name: '', company: '', cpfCnpj: '', instagram: '', phone: '', state: '', location: '', value: 0, status: 'lead', probability: 10, nextAction: 'Iniciar contato'
      });
  };

  // --- DRAG AND DROP HANDLERS ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      setDraggedLeadId(id);
      e.dataTransfer.effectAllowed = 'move';
      // Set a transparent drag image or similar if needed, but default is usually fine
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); // Necessary to allow dropping
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, newStatus: Lead['status']) => {
      e.preventDefault();
      if (!draggedLeadId) return;

      setLeads(prevLeads => prevLeads.map(lead => {
          if (lead.id === draggedLeadId) {
              return { ...lead, status: newStatus };
          }
          return lead;
      }));
      setDraggedLeadId(null);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'proposal': return 'bg-purple-500/20 text-purple-400 border-purple-500/30';
      case 'negotiation': return 'bg-amber-500/20 text-amber-400 border-amber-500/30';
      case 'closed': return 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30';
      case 'followup': return 'bg-pink-500/20 text-pink-400 border-pink-500/30';
      case 'lost': return 'bg-red-500/20 text-red-400 border-red-500/30';
      default: return 'bg-blue-500/20 text-blue-400 border-blue-500/30';
    }
  };

  const getStatusLabel = (status: string) => {
      switch (status) {
          case 'proposal': return 'Proposta';
          case 'negotiation': return 'Negociação';
          case 'closed': return 'Fechado';
          case 'followup': return 'Follow-up';
          case 'lost': return 'Perdido';
          case 'lead': return 'Lead';
          case 'contact': return 'Contato';
          default: return status;
      }
  }

  const totalPipeline = leads.reduce((acc, lead) => acc + lead.value, 0);
  const weightedPipeline = leads.reduce((acc, lead) => acc + (lead.value * (lead.probability / 100)), 0);

  // Kanban Columns Configuration
  const columns: { id: Lead['status'], label: string, color: string }[] = [
      { id: 'lead', label: 'Novos Leads', color: 'border-blue-500/50' },
      { id: 'contact', label: 'Em Contato', color: 'border-cyan-500/50' },
      { id: 'proposal', label: 'Proposta Enviada', color: 'border-purple-500/50' },
      { id: 'negotiation', label: 'Em Negociação', color: 'border-amber-500/50' },
      { id: 'closed', label: 'Fechado / Ganho', color: 'border-emerald-500/50' },
      { id: 'followup', label: 'Follow-up', color: 'border-pink-500/50' },
      { id: 'lost', label: 'Perdido', color: 'border-red-500/50' },
  ];

  return (
    <div className="p-4 md:p-8 h-full flex flex-col relative overflow-hidden">
      <header className="flex flex-col md:flex-row md:justify-between md:items-center mb-6 gap-4 flex-shrink-0">
        <div>
            <h1 className="text-3xl font-bold text-white">CRM Profissional</h1>
            <p className="text-slate-400">Gestão de Funil e Pipeline</p>
        </div>
        <div className="flex gap-2">
            <div className="bg-slate-800 p-1 rounded-lg border border-slate-700 flex mr-2">
                <button 
                    onClick={() => setViewMode('kanban')}
                    className={`p-2 rounded ${viewMode === 'kanban' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                    title="Visão de Funil"
                >
                    <LayoutGrid size={18} />
                </button>
                <button 
                    onClick={() => setViewMode('list')}
                    className={`p-2 rounded ${viewMode === 'list' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                    title="Visão de Lista"
                >
                    <ListIcon size={18} />
                </button>
            </div>
            <button 
                onClick={() => setShowForm(true)}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 px-4 py-2 rounded-lg text-white font-medium transition-all shadow-lg shadow-emerald-900/20"
            >
                <Plus size={18} /> Novo Cliente
            </button>
            <button 
                onClick={handleAnalyze}
                disabled={analyzing}
                className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-4 py-2 rounded-lg text-white font-medium transition-all disabled:opacity-50"
            >
                <Brain size={18} /> {analyzing ? 'Analisando...' : 'Auditoria IA'}
            </button>
        </div>
      </header>

      {/* KPI Cards (Compact) */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6 flex-shrink-0">
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Pipeline Total</span>
                <p className="text-xl font-bold text-white">${totalPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400"><DollarSign size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Ponderado</span>
                <p className="text-xl font-bold text-white">${weightedPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-400"><TrendingUp size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                 <span className="text-slate-400 text-xs font-medium uppercase">Leads Ativos</span>
                <p className="text-xl font-bold text-white">{leads.length}</p>
            </div>
            <div className="p-2 bg-purple-500/10 rounded-lg text-purple-400"><Users size={20} /></div>
        </div>
      </div>

      {aiAnalysis && (
        <div className="mb-6 bg-indigo-900/20 border border-indigo-500/50 p-4 rounded-xl animate-fade-in flex-shrink-0">
            <h3 className="text-indigo-400 font-bold mb-1 flex items-center gap-2"><Brain size={16}/> Insight Estratégico</h3>
            <p className="text-slate-200 text-sm">{aiAnalysis}</p>
        </div>
      )}

      {/* --- KANBAN FUNNEL VIEW --- */}
      {viewMode === 'kanban' && (
          <div className="flex-1 overflow-x-auto pb-4 custom-scrollbar">
              <div className="flex gap-4 min-w-[1400px] h-full">
                  {columns.map(col => {
                      const colLeads = leads.filter(l => l.status === col.id);
                      const colValue = colLeads.reduce((acc, l) => acc + l.value, 0);

                      return (
                          <div 
                            key={col.id}
                            onDragOver={handleDragOver}
                            onDrop={(e) => handleDrop(e, col.id)}
                            className={`flex-1 min-w-[240px] bg-slate-800/50 rounded-xl border-t-4 ${col.color} border-x border-b border-slate-700 flex flex-col h-full`}
                          >
                              {/* Column Header */}
                              <div className="p-3 border-b border-slate-700 bg-slate-800 rounded-t-lg">
                                  <div className="flex justify-between items-center mb-1">
                                      <h3 className="font-bold text-slate-200 text-sm uppercase tracking-wide">{col.label}</h3>
                                      <span className="text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">{colLeads.length}</span>
                                  </div>
                                  <p className="text-xs text-slate-500 font-mono">R$ {colValue.toLocaleString()}</p>
                              </div>

                              {/* Drop Zone / List */}
                              <div className="flex-1 p-3 space-y-3 overflow-y-auto custom-scrollbar">
                                  {colLeads.map(lead => (
                                      <div
                                        key={lead.id}
                                        draggable
                                        onDragStart={(e) => handleDragStart(e, lead.id)}
                                        className={`
                                            bg-slate-800 p-4 rounded-lg border border-slate-600 shadow-sm cursor-move 
                                            hover:border-blue-400 hover:shadow-lg hover:shadow-blue-900/10 transition-all group
                                            ${draggedLeadId === lead.id ? 'opacity-50 ring-2 ring-blue-500 ring-offset-2 ring-offset-slate-900' : ''}
                                        `}
                                      >
                                          <div className="flex justify-between items-start mb-2">
                                              <h4 className="font-bold text-white text-sm">{lead.name}</h4>
                                              <GripVertical size={14} className="text-slate-600 opacity-0 group-hover:opacity-100" />
                                          </div>

                                          <div className="text-xs text-slate-400 mb-3 flex items-center gap-1">
                                              <Building2 size={12}/> {lead.company}
                                          </div>

                                          <div className="flex justify-between items-end">
                                              <div>
                                                  <p className="text-[10px] text-slate-500 uppercase font-bold">Valor</p>
                                                  <p className="text-emerald-400 font-mono text-sm font-medium">R$ {lead.value.toLocaleString()}</p>
                                              </div>
                                              {lead.probability > 0 && (
                                                  <div className="text-right">
                                                      <p className="text-[10px] text-slate-500 uppercase font-bold">Prob.</p>
                                                      <p className={`text-sm font-medium ${lead.probability > 70 ? 'text-green-400' : lead.probability > 30 ? 'text-amber-400' : 'text-red-400'}`}>
                                                          {lead.probability}%
                                                      </p>
                                                  </div>
                                              )}
                                          </div>

                                          {/* Action / Next Step */}
                                          <div className="mt-3 pt-2 border-t border-slate-700/50">
                                              <p className="text-[10px] text-slate-500 flex items-center gap-1 truncate">
                                                  <TrendingUp size={10} /> {lead.nextAction}
                                              </p>
                                          </div>
                                      </div>
                                  ))}
                                  {colLeads.length === 0 && (
                                      <div className="h-24 border-2 border-dashed border-slate-700/50 rounded-lg flex items-center justify-center text-slate-600 text-xs">
                                          Arraste para cá
                                      </div>
                                  )}
                              </div>
                          </div>
                      );
                  })}
              </div>
          </div>
      )}

      {/* --- LIST VIEW (Original) --- */}
      {viewMode === 'list' && (
        <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden flex-1 overflow-y-auto">
            <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-slate-900/50 border-b border-slate-700 text-slate-400 text-sm uppercase tracking-wider sticky top-0 bg-slate-900 z-10">
                            <th className="p-4">Lead / Empresa</th>
                            <th className="p-4">Contato</th>
                            <th className="p-4">Status</th>
                            <th className="p-4">Valor</th>
                            <th className="p-4">Probabilidade</th>
                            <th className="p-4"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-700">
                        {leads.map((lead) => (
                            <tr key={lead.id} className="hover:bg-slate-700/30 transition-colors group">
                                <td className="p-4">
                                    <p className="font-bold text-white flex items-center gap-2">{lead.name}</p>
                                    <p className="text-xs text-slate-500 flex items-center gap-1">
                                        <Building2 size={10} /> {lead.company}
                                    </p>
                                    {lead.location && <p className="text-[10px] text-slate-500 flex items-center gap-1 mt-0.5"><MapPin size={8} /> {lead.location} - {lead.state}</p>}
                                </td>
                                <td className="p-4">
                                    <div className="space-y-1">
                                        {lead.phone && <p className="text-xs text-slate-300 flex items-center gap-1"><Phone size={10} /> {lead.phone}</p>}
                                        {lead.instagram && <p className="text-xs text-slate-300 flex items-center gap-1"><Instagram size={10} /> {lead.instagram}</p>}
                                        {lead.cpfCnpj && <p className="text-[10px] text-slate-500">Doc: {lead.cpfCnpj}</p>}
                                    </div>
                                </td>
                                <td className="p-4">
                                    <span className={`px-2 py-1 rounded-full text-xs font-bold border ${getStatusColor(lead.status)}`}>
                                        {getStatusLabel(lead.status)}
                                    </span>
                                </td>
                                <td className="p-4 text-slate-300 font-mono">${lead.value.toLocaleString()}</td>
                                <td className="p-4">
                                    <div className="flex items-center gap-2">
                                        <div className="w-16 h-1.5 bg-slate-700 rounded-full overflow-hidden">
                                            <div className="h-full bg-blue-500" style={{ width: `${lead.probability}%` }}></div>
                                        </div>
                                        <span className="text-xs text-slate-400">{lead.probability}%</span>
                                    </div>
                                </td>
                                <td className="p-4 text-right">
                                    <button className="text-slate-500 hover:text-white p-2">
                                        <MoreHorizontal size={18} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
      )}

      {/* MODAL DE CADASTRO DE CLIENTE */}
      {showForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
              <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl">
                  <header className="p-6 border-b border-slate-800 flex justify-between items-center sticky top-0 bg-slate-900 z-10">
                      <h2 className="text-xl font-bold text-white flex items-center gap-2">
                          <Plus className="text-emerald-500" /> Cadastro de Novo Cliente
                      </h2>
                      <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-white">
                          <X size={24} />
                      </button>
                  </header>

                  <form onSubmit={handleSaveClient} className="p-6 space-y-6">
                      {/* Dados Principais */}
                      <div className="space-y-4">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <User size={14} /> Informações Básicas
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Nome Completo *</label>
                                  <input 
                                    required
                                    type="text" 
                                    value={formData.name} 
                                    onChange={e => setFormData({...formData, name: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Ex: João Silva"
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Empresa</label>
                                  <input 
                                    type="text" 
                                    value={formData.company} 
                                    onChange={e => setFormData({...formData, company: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Ex: Minha Empresa Ltda"
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">CPF ou CNPJ</label>
                                  <input 
                                    type="text" 
                                    value={formData.cpfCnpj} 
                                    onChange={e => setFormData({...formData, cpfCnpj: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="000.000.000-00"
                                  />
                              </div>
                          </div>
                      </div>

                      {/* Contato e Localização */}
                      <div className="space-y-4 pt-4 border-t border-slate-800">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <MapPin size={14} /> Contato & Localização
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div>
                                  <label className="block text-xs text-slate-400 mb-1">Telefone</label>
                                  <div className="relative">
                                    <Phone className="absolute left-3 top-3.5 text-slate-500" size={16} />
                                    <input 
                                        type="text" 
                                        value={formData.phone} 
                                        onChange={e => setFormData({...formData, phone: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 pl-10 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                    />
                                  </div>
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Instagram da Empresa</label>
                                  <div className="relative">
                                    <Instagram className="absolute left-3 top-3.5 text-slate-500" size={16} />
                                    <input 
                                        type="text" 
                                        value={formData.instagram} 
                                        onChange={e => setFormData({...formData, instagram: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 pl-10 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="@usuario"
                                    />
                                  </div>
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Estado (UF)</label>
                                  <input 
                                    type="text" 
                                    value={formData.state} 
                                    onChange={e => setFormData({...formData, state: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="SP, RJ, MG..."
                                    maxLength={2}
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Onde Fica (Cidade/Endereço)</label>
                                  <input 
                                    type="text" 
                                    value={formData.location} 
                                    onChange={e => setFormData({...formData, location: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Cidade ou Bairro"
                                  />
                              </div>
                          </div>
                      </div>

                       {/* Dados do Pipeline (Opcionais para cadastro rápido) */}
                       <div className="space-y-4 pt-4 border-t border-slate-800">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <TrendingUp size={14} /> Dados do Pipeline (Inicial)
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <div>
                                    <label className="block text-xs text-slate-400 mb-1">Valor Potencial ($)</label>
                                    <input 
                                        type="number" 
                                        value={formData.value} 
                                        onChange={e => setFormData({...formData, value: Number(e.target.value)})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs text-slate-400 mb-1">Fase do Pipeline</label>
                                    <select 
                                        value={formData.status} 
                                        onChange={e => setFormData({...formData, status: e.target.value as any})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    >
                                        <option value="lead">Lead</option>
                                        <option value="contact">Contato</option>
                                        <option value="proposal">Proposta</option>
                                        <option value="negotiation">Negociação</option>
                                        <option value="closed">Fechado</option>
                                        <option value="followup">Follow-up</option>
                                    </select>
                                </div>
                          </div>
                       </div>

                      <div className="pt-6 flex gap-3">
                          <button 
                            type="button" 
                            onClick={() => setShowForm(false)}
                            className="flex-1 py-3 bg-slate-800 text-slate-300 font-bold rounded-lg hover:bg-slate-700 transition-colors"
                          >
                            Cancelar
                          </button>
                          <button 
                            type="submit" 
                            className="flex-1 py-3 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-500 transition-colors flex justify-center items-center gap-2"
                          >
                            <Save size={18} /> Salvar Cliente
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

export type NavigationTab = 'dashboard' | 'professional' | 'body' | 'finance' | 'productivity' | 'reports';

export interface CheckIn {
  energy: number; // 0-10
  mood: string;
  sleepQuality: string;
  sleepHours: number; // New field for reporting
  mainGoal: string;
  timestamp: string;
}

export type TaskCategory = 'work' | 'study' | 'workout' | 'routine' | 'wasted' | 'leisure';

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  category: TaskCategory;
  startTime?: string; // HH:mm
  endTime?: string;   // HH:mm
  durationMinutes: number;
  xpReward: number;
  date: string; // ISO Date string for filtering daily/weekly
}

export interface FunnelStage {
  id: string;
  name: string;
  color: string; // Tailwind border color class or hex
}

export interface Funnel {
  id: string;
  name: string;
  stages: FunnelStage[];
}

export interface Lead {
  id: string;
  funnelId: string; // Links the lead to a specific funnel
  name: string;
  company: string;
  status: string; // Now dynamic, matching a FunnelStage id
  value: number;
  probability: number;
  lastContact: string;
  nextAction: string;
  // New Contact Fields
  cpfCnpj?: string;
  instagram?: string;
  phone?: string;
  state?: string;
  location?: string;
}

export interface WorkoutProfile {
  sex: string;
  age: number;
  weight: number;
  goal: 'weight_loss' | 'hypertrophy' | 'conditioning' | 'health';
  limitations: string;
}

export interface WorkoutLog {
    id: string;
    description: string;
    date: string;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  category: string;
  amount: number;
  date: string;
}

export interface Message {
