                        <tbody className="divide-y divide-slate-700">
                            {activeLeads.map((lead) => (
                                <tr key={lead.id} onClick={() => openEditClientModal(lead)} className="hover:bg-slate-700/30 transition-colors group cursor-pointer">
                                    <td className="p-4">
