                  <form onSubmit={handleSaveFunnel} className="p-6 space-y-6">
                      <div>
                          <label className="block text-xs text-slate-400 mb-1 uppercase font-bold">Nome do Funil</label>
                          <input 
                             required
                             type="text"
                             value={editingFunnel.name}
                             onChange={(e) => setEditingFunnel({...editingFunnel, name: e.target.value})}
                             className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none"
                             placeholder="Ex: Vendas B2B"
                          />
                      </div>

                      <div className="space-y-3">
                          <div className="flex justify-between items-center">
                              <label className="block text-xs text-slate-400 uppercase font-bold">Fases do Funil (Edite os nomes aqui)</label>
                              <button type="button" onClick={addStage} className="text-xs text-emerald-400 hover:text-emerald-300 flex items-center gap-1">
                                  <Plus size={12}/> Adicionar Fase
                              </button>
                          </div>

                          <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                              {editingFunnel.stages?.map((stage, idx) => (
                                  <div key={idx} className="flex gap-2 items-center">
                                      <div className="cursor-grab text-slate-600"><GripVertical size={16}/></div>
                                      <input 
                                         type="text"
                                         value={stage.name}
                                         onChange={(e) => updateStage(idx, 'name', e.target.value)}
                                         className="flex-1 bg-slate-800 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:border-blue-500 focus:outline-none"
                                         placeholder="Nome da Fase"
                                      />
                                      <select
                                          value={stage.color}
                                          onChange={(e) => updateStage(idx, 'color', e.target.value)}
                                          className="w-8 h-9 bg-slate-800 border border-slate-700 rounded text-transparent focus:outline-none cursor-pointer"
                                          style={{backgroundColor: stage.color.replace('border-', '').replace('/50', '').replace('500', '500')}} // Rough preview
                                      >
                                          <option value="border-slate-500/50" className="text-black">Cinza</option>
                                          <option value="border-blue-500/50" className="text-blue-500">Azul</option>
                                          <option value="border-emerald-500/50" className="text-emerald-500">Verde</option>
                                          <option value="border-purple-500/50" className="text-purple-500">Roxo</option>
                                          <option value="border-amber-500/50" className="text-amber-500">Amarelo</option>
                                          <option value="border-red-500/50" className="text-red-500">Vermelho</option>
                                          <option value="border-pink-500/50" className="text-pink-500">Rosa</option>
                                          <option value="border-cyan-500/50" className="text-cyan-500">Ciano</option>
                                      </select>
                                      <button 
                                        type="button" 
                                        onClick={() => removeStage(idx)}
                                        className="text-slate-500 hover:text-red-400 p-2"
                                        disabled={editingFunnel.stages!.length <= 1}
                                      >
                                          <Trash2 size={16}/>
                                      </button>
                                  </div>
                              ))}
                          </div>
                      </div>

                      <button type="submit" className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 rounded-lg shadow-lg">
                          Salvar Configuração
                      </button>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Lead, Funnel, FunnelStage } from '../types';
import { MOCK_LEADS, MOCK_FUNNELS } from '../constants';
import { analyzeCRM } from '../services/geminiService';
import { TrendingUp, Users, DollarSign, Brain, MoreHorizontal, Plus, X, Save, MapPin, Instagram, Phone, Building2, User, LayoutGrid, List as ListIcon, GripVertical, Settings, Trash2, ChevronDown, Edit3, Map as MapIcon, Globe2, Loader2 } from 'lucide-react';
import L from 'leaflet';

export const Professional: React.FC = () => {
  // Data State
  const [funnels, setFunnels] = useState<Funnel[]>(MOCK_FUNNELS);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS as any);
  const [activeFunnelId, setActiveFunnelId] = useState<string>(MOCK_FUNNELS[0].id);

  // View & UX State
  const [aiAnalysis, setAiAnalysis] = useState<string>("");
  const [analyzing, setAnalyzing] = useState(false);
  const [showClientForm, setShowClientForm] = useState(false);
  const [showFunnelModal, setShowFunnelModal] = useState(false);
  const [viewMode, setViewMode] = useState<'list' | 'kanban' | 'map'>('kanban');
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);
  const [isGeocoding, setIsGeocoding] = useState(false);

  // -- MAP REFS --
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);

  // -- FUNNEL EDITING STATE --
  const [editingFunnel, setEditingFunnel] = useState<Partial<Funnel> | null>(null);
  const [showFunnelDropdown, setShowFunnelDropdown] = useState(false);

  // -- CLIENT FORM STATE --
  const [editingLeadId, setEditingLeadId] = useState<string | null>(null); // Track if we are editing an existing lead
  const [clientFormData, setClientFormData] = useState<Partial<Lead>>({
    name: '',
    company: '',
    cpfCnpj: '',
    instagram: '',
    phone: '',
    zipCode: '',
    address: '',
    number: '',
    state: '',
    location: '', // city
    value: 0,
    status: '',
    probability: 10,
    nextAction: 'Iniciar contato'
  });

  const activeFunnel = funnels.find(f => f.id === activeFunnelId) || funnels[0];
  const activeLeads = leads.filter(l => l.funnelId === activeFunnelId);

  // Default status when opening form
  useEffect(() => {
    if (activeFunnel && !clientFormData.status && !editingLeadId) {
        setClientFormData(prev => ({ ...prev, status: activeFunnel.stages[0].id }));
    }
  }, [activeFunnelId, activeFunnel, editingLeadId]);

  // --- MAP INITIALIZATION ---
  useEffect(() => {
      // Only initialize map if viewMode is 'map'
      if (viewMode !== 'map') return;

      // Cleanup previous map instance if it exists
      if (mapInstanceRef.current) {
          mapInstanceRef.current.remove();
          mapInstanceRef.current = null;
      }

      // Small timeout to allow DOM to render the container
      const timer = setTimeout(() => {
          if (mapContainerRef.current && leads.length > 0) {
              // Default center (Brazil approx)
              const map = L.map(mapContainerRef.current).setView([-14.2350, -51.9253], 3);

              L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
                  attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
                  subdomains: 'abcd',
                  maxZoom: 19
              }).addTo(map);

              // Add markers for leads with coordinates
              const bounds = L.latLngBounds([]);
              let hasMarkers = false;

              leads.forEach(lead => {
                  if (lead.lat && lead.lng) {
                      hasMarkers = true;
                      const latLng = L.latLng(lead.lat, lead.lng);
                      bounds.extend(latLng);

                      const markerColor = lead.status === 'closed' ? '#10b981' : (lead.status === 'lost' ? '#ef4444' : '#3b82f6');

                      // Custom simple dot icon
                      const customIcon = L.divIcon({
                          className: 'custom-div-icon',
                          html: `<div style="background-color: ${markerColor}; width: 12px; height: 12px; border-radius: 50%; border: 2px solid white; box-shadow: 0 0 10px ${markerColor};"></div>`,
                          iconSize: [12, 12],
                          iconAnchor: [6, 6]
                      });

                      L.marker(latLng, { icon: customIcon })
                        .addTo(map)
                        .bindPopup(`
                            <div style="min-width: 150px;">
                                <strong style="font-size: 14px; color: #fff;">${lead.name}</strong><br/>
                                <span style="color: #94a3b8; font-size: 12px;">${lead.company}</span><br/>
                                <div style="margin-top: 5px; font-weight: bold; color: ${markerColor}">${activeFunnel.stages.find(s => s.id === lead.status)?.name || lead.status}</div>
                                <div style="font-size: 11px; color: #cbd5e1; margin-top: 5px;">${lead.location} - ${lead.state}</div>
                            </div>
                        `);
                  }
              });

              if (hasMarkers) {
                  map.fitBounds(bounds, { padding: [50, 50], maxZoom: 10 });
              }

              mapInstanceRef.current = map;
          }
      }, 100);

      return () => {
          clearTimeout(timer);
          if (mapInstanceRef.current) {
              mapInstanceRef.current.remove();
              mapInstanceRef.current = null;
          }
      };
  }, [leads, activeFunnelId, viewMode]); // Re-render map when leads change or view mode switches to map


  // --- FUNNEL MANAGEMENT ---

  const handleCreateFunnel = () => {
      setEditingFunnel({
          id: '',
          name: 'Novo Funil',
          stages: [
              { id: 'stage_1', name: 'Início', color: 'border-blue-500/50' },
              { id: 'stage_2', name: 'Fim', color: 'border-emerald-500/50' }
          ]
      });
      setShowFunnelModal(true);
      setShowFunnelDropdown(false);
  };

  const handleEditFunnel = () => {
      setEditingFunnel(JSON.parse(JSON.stringify(activeFunnel))); // Deep copy
      setShowFunnelModal(true);
      setShowFunnelDropdown(false);
  };

  const handleDeleteFunnel = () => {
      if (funnels.length <= 1) {
          alert("Você precisa ter pelo menos um funil.");
          return;
      }
      if (confirm(`Tem certeza que deseja excluir o funil "${activeFunnel.name}"? Todos os leads deste funil serão ocultados.`)) {
          const newFunnels = funnels.filter(f => f.id !== activeFunnelId);
          setFunnels(newFunnels);
          setActiveFunnelId(newFunnels[0].id);
          setShowFunnelDropdown(false);
      }
  };

  const handleSaveFunnel = (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingFunnel || !editingFunnel.name) return;

      if (editingFunnel.id) {
          // Edit existing
          setFunnels(prev => prev.map(f => f.id === editingFunnel.id ? editingFunnel as Funnel : f));
      } else {
          // Create new
          const newId = `funnel_${Date.now()}`;
          const newFunnel = { ...editingFunnel, id: newId } as Funnel;
          setFunnels(prev => [...prev, newFunnel]);
          setActiveFunnelId(newId);
      }
      setShowFunnelModal(false);
      setEditingFunnel(null);
  };

  const updateStage = (index: number, field: keyof FunnelStage, value: string) => {
      if (!editingFunnel || !editingFunnel.stages) return;
      const newStages = [...editingFunnel.stages];
      newStages[index] = { ...newStages[index], [field]: value };
      setEditingFunnel({ ...editingFunnel, stages: newStages });
  };

  const addStage = () => {
      if (!editingFunnel || !editingFunnel.stages) return;
      const newStage: FunnelStage = {
          id: `stage_${Date.now()}`,
          name: 'Nova Etapa',
          color: 'border-slate-500/50'
      };
      setEditingFunnel({ ...editingFunnel, stages: [...editingFunnel.stages, newStage] });
  };

  const removeStage = (index: number) => {
      if (!editingFunnel || !editingFunnel.stages) return;
      if (editingFunnel.stages.length <= 1) return;
      const newStages = editingFunnel.stages.filter((_, i) => i !== index);
      setEditingFunnel({ ...editingFunnel, stages: newStages });
  };

  const toggleMapMode = () => {
      if (viewMode === 'map') {
          setViewMode('kanban');
      } else {
          setViewMode('map');
      }
  };

  // --- CLIENT MANAGEMENT ---

  const handleAnalyze = async () => {
    setAnalyzing(true);
    const result = await analyzeCRM(activeLeads);
    setAiAnalysis(result);
    setAnalyzing(false);
  };

  const openNewClientModal = () => {
      setEditingLeadId(null);
      setClientFormData({
          name: '', company: '', cpfCnpj: '', instagram: '', phone: '', 
          zipCode: '', address: '', number: '', state: '', location: '',
          value: 0, status: activeFunnel.stages[0].id, probability: 10, nextAction: 'Iniciar contato'
      });
      setShowClientForm(true);
  };

  const openEditClientModal = (lead: Lead) => {
      setEditingLeadId(lead.id);
      setClientFormData({ ...lead });
      setShowClientForm(true);
  };

  // Geocoding Service (Nominatim OpenStreetMap)
  const getCoordinates = async (address: string, city: string, state: string, zip: string) => {
    try {
        const query = `${address}, ${city}, ${state}, Brazil`;
        const encodedQuery = encodeURIComponent(query);
        const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodedQuery}&limit=1`);
        const data = await response.json();
        if (data && data.length > 0) {
            return { lat: parseFloat(data[0].lat), lng: parseFloat(data[0].lon) };
        }
        return null;
    } catch (error) {
        console.error("Geocoding failed", error);
        return null;
    }
  };

  const handleSaveClient = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!clientFormData.name) return;

      setIsGeocoding(true);

      // Attempt Geocode if address data is present
      let coords = { lat: clientFormData.lat, lng: clientFormData.lng };
      if ((clientFormData.address || clientFormData.location) && (!clientFormData.lat || !clientFormData.lng)) {
           const result = await getCoordinates(
               clientFormData.address || '', 
               clientFormData.location || '', 
               clientFormData.state || '',
               clientFormData.zipCode || ''
           );
           if (result) coords = result;
      }

      const leadDataToSave = {
          ...clientFormData,
          ...coords,
          value: Number(clientFormData.value) || 0,
          probability: Number(clientFormData.probability) || 0
      };

      if (editingLeadId) {
          // UPDATE EXISTING LEAD
          setLeads(prevLeads => prevLeads.map(lead => {
              if (lead.id === editingLeadId) {
                  return { ...lead, ...leadDataToSave } as Lead;
              }
              return lead;
          }));
      } else {
          // CREATE NEW LEAD
          const newClient: Lead = {
              id: Date.now().toString(),
              funnelId: activeFunnelId,
              name: clientFormData.name || 'Cliente Sem Nome',
              company: clientFormData.company || 'N/A',
              status: clientFormData.status || activeFunnel.stages[0].id,
              value: Number(clientFormData.value) || 0,
              probability: Number(clientFormData.probability) || 0,
              lastContact: new Date().toISOString().split('T')[0],
              nextAction: clientFormData.nextAction || 'Definir próximos passos',
              cpfCnpj: clientFormData.cpfCnpj,
              instagram: clientFormData.instagram,
              phone: clientFormData.phone,
              state: clientFormData.state,
              location: clientFormData.location,
              zipCode: clientFormData.zipCode,
              address: clientFormData.address,
              number: clientFormData.number,
              lat: coords.lat,
              lng: coords.lng
          };
          setLeads([...leads, newClient]);
      }

      setIsGeocoding(false);
      setShowClientForm(false);
      setEditingLeadId(null);
  };

  // --- DRAG AND DROP HANDLERS ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      setDraggedLeadId(id);
      e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, newStatus: string) => {
      e.preventDefault();
      if (!draggedLeadId) return;

      setLeads(prevLeads => prevLeads.map(lead => {
          if (lead.id === draggedLeadId) {
              return { ...lead, status: newStatus };
          }
          return lead;
      }));
      setDraggedLeadId(null);
  };

  const getStatusLabel = (statusId: string) => {
      const stage = activeFunnel.stages.find(s => s.id === statusId);
      return stage ? stage.name : statusId;
  };

  const getStatusColor = (statusId: string) => {
      const stage = activeFunnel.stages.find(s => s.id === statusId);
      return stage ? stage.color.replace('border-', 'bg-').replace('/50', '/20') + ' ' + stage.color.replace('border-', 'text-').replace('/50', '/80') + ' border ' + stage.color.replace('/50', '/30') : 'bg-slate-700 text-slate-300';
  };

  const totalPipeline = activeLeads.reduce((acc, lead) => acc + lead.value, 0);
  const weightedPipeline = activeLeads.reduce((acc, lead) => acc + (lead.value * (lead.probability / 100)), 0);

  // Stats for Map Report
  const leadsByState = leads.reduce((acc, lead) => {
      if (lead.state) {
          const upperState = lead.state.toUpperCase().trim();
          acc[upperState] = (acc[upperState] || 0) + 1;
      }
      return acc;
  }, {} as Record<string, number>);

  return (
    <div className="p-4 md:p-8 h-full flex flex-col relative overflow-hidden" onClick={() => setShowFunnelDropdown(false)}>

      {/* HEADER WITH FUNNEL SELECTOR */}
      <header className="flex flex-col md:flex-row md:justify-between md:items-center mb-6 gap-4 flex-shrink-0 z-20">
        <div className="flex flex-col gap-1">
            <h1 className="text-3xl font-bold text-white flex items-center gap-2">
                CRM
                <span className="text-slate-600">/</span>
                <div className="relative" onClick={(e) => e.stopPropagation()}>
                    <button 
                        onClick={() => setShowFunnelDropdown(!showFunnelDropdown)}
                        className="flex items-center gap-2 text-emerald-400 hover:text-emerald-300 transition-colors"
                    >
                        {activeFunnel.name}
                        <ChevronDown size={20} className={`transition-transform ${showFunnelDropdown ? 'rotate-180' : ''}`}/>
                    </button>

                    {/* Funnel Dropdown */}
                    {showFunnelDropdown && (
                        <div className="absolute top-full left-0 mt-2 w-64 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl overflow-hidden animate-fade-in z-50">
                            <div className="p-2 border-b border-slate-700">
                                <p className="text-xs font-bold text-slate-500 uppercase px-2 py-1">Meus Funis</p>
                                {funnels.map(f => (
                                    <button
                                        key={f.id}
                                        onClick={() => { setActiveFunnelId(f.id); setShowFunnelDropdown(false); }}
                                        className={`w-full text-left px-3 py-2 rounded-lg text-sm font-medium flex justify-between items-center ${activeFunnelId === f.id ? 'bg-blue-600 text-white' : 'text-slate-300 hover:bg-slate-700'}`}
                                    >
                                        {f.name}
                                        {activeFunnelId === f.id && <div className="w-2 h-2 bg-white rounded-full"></div>}
                                    </button>
                                ))}
                            </div>
                            <div className="p-2 space-y-1">
                                <button onClick={handleCreateFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-emerald-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Plus size={14}/> Criar Novo Funil
                                </button>
                                <button onClick={handleEditFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-blue-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Edit3 size={14}/> Editar Atual
                                </button>
                                <button onClick={handleDeleteFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-red-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Trash2 size={14}/> Excluir Atual
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </h1>
            <p className="text-slate-400 text-sm">Gerencie seu pipeline de vendas</p>
        </div>

        <div className="flex gap-2">

            {/* View Toggles - Only show if NOT in map mode to avoid clutter */}
            {viewMode !== 'map' && (
                <div className="bg-slate-800 p-1 rounded-lg border border-slate-700 flex mr-2">
                    <button 
                        onClick={() => setViewMode('kanban')}
                        className={`p-2 rounded ${viewMode === 'kanban' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                        title="Visão de Funil"
                    >
                        <LayoutGrid size={18} />
                    </button>
                    <button 
                        onClick={() => setViewMode('list')}
                        className={`p-2 rounded ${viewMode === 'list' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                        title="Visão de Lista"
                    >
                        <ListIcon size={18} />
                    </button>
                </div>
            )}

            {/* 1. AUDITORIA */}
            <button 
                onClick={handleAnalyze}
                disabled={analyzing}
                className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-4 py-2 rounded-lg text-white font-medium transition-all disabled:opacity-50"
            >
                <Brain size={18} /> {analyzing ? 'Analisando...' : 'Auditoria IA'}
            </button>

             {/* 2. NOVO CLIENTE */}
            <button 
                onClick={openNewClientModal}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 px-4 py-2 rounded-lg text-white font-medium transition-all shadow-lg shadow-emerald-900/20"
            >
                <Plus size={18} /> Novo Cliente
            </button>

            {/* 3. MAPA (Toggle) */}
            <button 
                onClick={toggleMapMode}
                className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition-all shadow-lg ${viewMode === 'map' ? 'bg-blue-600 text-white shadow-blue-900/20' : 'bg-slate-800 text-slate-300 hover:bg-slate-700 hover:text-white border border-slate-700'}`}
            >
                <MapIcon size={18} /> Mapa
            </button>

        </div>
      </header>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6 flex-shrink-0">
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Pipeline Total</span>
                <p className="text-xl font-bold text-white">${totalPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400"><DollarSign size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Ponderado</span>
                <p className="text-xl font-bold text-white">${weightedPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-400"><TrendingUp size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                 <span className="text-slate-400 text-xs font-medium uppercase">Leads Ativos</span>
                <p className="text-xl font-bold text-white">{activeLeads.length}</p>
            </div>
            <div className="p-2 bg-purple-500/10 rounded-lg text-purple-400"><Users size={20} /></div>
        </div>
      </div>

      {aiAnalysis && (
        <div className="mb-6 bg-indigo-900/20 border border-indigo-500/50 p-4 rounded-xl animate-fade-in flex-shrink-0">
            <h3 className="text-indigo-400 font-bold mb-1 flex items-center gap-2"><Brain size={16}/> Insight Estratégico</h3>
            <p className="text-slate-200 text-sm">{aiAnalysis}</p>
        </div>
      )}

       {/* SCROLLABLE CONTENT CONTAINER */}
      <div className="flex-1 overflow-y-auto custom-scrollbar pb-20">

          {/* --- KANBAN FUNNEL VIEW --- */}
          {viewMode === 'kanban' && (
              <div className="overflow-x-auto pb-4 mb-8">
                  <div className="flex gap-4 min-w-[1400px] h-[500px]">
                      {activeFunnel.stages.map(stage => {
                          const colLeads = activeLeads.filter(l => l.status === stage.id);
                          const colValue = colLeads.reduce((acc, l) => acc + l.value, 0);

                          return (
                              <div 
                                key={stage.id}
                                onDragOver={handleDragOver}
                                onDrop={(e) => handleDrop(e, stage.id)}
                                className={`flex-1 min-w-[240px] bg-slate-800/50 rounded-xl border-t-4 ${stage.color} border-x border-b border-slate-700 flex flex-col h-full`}
                              >
                                  {/* Column Header */}
                                  <div className="p-3 border-b border-slate-700 bg-slate-800 rounded-t-lg group relative">
                                      <div className="flex justify-between items-center mb-1">
                                          <h3 className="font-bold text-slate-200 text-sm uppercase tracking-wide truncate" title={stage.name}>{stage.name}</h3>
                                          <span className="text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">{colLeads.length}</span>
                                      </div>
                                      <p className="text-xs text-slate-500 font-mono">R$ {colValue.toLocaleString()}</p>
                                  </div>

                                  {/* Drop Zone / List */}
                                  <div className="flex-1 p-3 space-y-3 overflow-y-auto custom-scrollbar">
                                      {colLeads.map(lead => (
                                          <div
                                            key={lead.id}
                                            draggable
                                            onDragStart={(e) => handleDragStart(e, lead.id)}
                                            onClick={() => openEditClientModal(lead)}
                                            className={`
                                                bg-slate-800 p-4 rounded-lg border border-slate-600 shadow-sm cursor-pointer 
                                                hover:border-blue-400 hover:shadow-lg hover:shadow-blue-900/10 transition-all group relative
                                                ${draggedLeadId === lead.id ? 'opacity-50 ring-2 ring-blue-500 ring-offset-2 ring-offset-slate-900' : ''}
                                            `}
                                          >
                                              <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                  <Edit3 size={12} className="text-slate-500 hover:text-blue-400" />
                                              </div>

                                              <div className="flex justify-between items-start mb-2 pr-4">
                                                  <h4 className="font-bold text-white text-sm">{lead.name}</h4>
                                              </div>

                                              <div className="text-xs text-slate-400 mb-3 flex items-center gap-1">
                                                  <Building2 size={12}/> {lead.company}
                                              </div>

                                              <div className="flex justify-between items-end">
                                                  <div>
                                                      <p className="text-[10px] text-slate-500 uppercase font-bold">Valor</p>
                                                      <p className="text-emerald-400 font-mono text-sm font-medium">R$ {lead.value.toLocaleString()}</p>
                                                  </div>
                                                  {lead.probability > 0 && (
                                                      <div className="text-right">
                                                          <p className="text-[10px] text-slate-500 uppercase font-bold">Prob.</p>
                                                          <p className={`text-sm font-medium ${lead.probability > 70 ? 'text-green-400' : lead.probability > 30 ? 'text-amber-400' : 'text-red-400'}`}>
                                                              {lead.probability}%
                                                          </p>
                                                      </div>
                                                  )}
                                              </div>

                                              {/* Action / Next Step */}
                                              <div className="mt-3 pt-2 border-t border-slate-700/50">
                                                  <p className="text-[10px] text-slate-500 flex items-center gap-1 truncate">
                                                      <TrendingUp size={10} /> {lead.nextAction}
                                                  </p>
                                              </div>
                                          </div>
                                      ))}
                                      {colLeads.length === 0 && (
                                          <div className="h-24 border-2 border-dashed border-slate-700/50 rounded-lg flex items-center justify-center text-slate-600 text-xs">
                                              Arraste para cá
                                          </div>
                                      )}
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              </div>
          )}

          {/* --- LIST VIEW --- */}
          {viewMode === 'list' && (
            <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden mb-8">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-900/50 border-b border-slate-700 text-slate-400 text-sm uppercase tracking-wider">
                                <th className="p-4">Lead / Empresa</th>
                                <th className="p-4">Contato</th>
                                <th className="p-4">Status</th>
                                <th className="p-4">Valor</th>
                                <th className="p-4">Probabilidade</th>
                                <th className="p-4"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-700">
                            {activeLeads.map((lead) => (
                                <tr key={lead.id} onClick={() => openEditClientModal(lead)} className="hover:bg-slate-700/30 transition-colors group cursor-pointer">
                                    <td className="p-4">
                                        <p className="font-bold text-white flex items-center gap-2">{lead.name}</p>
                                        <p className="text-xs text-slate-500 flex items-center gap-1">
                                            <Building2 size={10} /> {lead.company}
                                        </p>
                                        {lead.location && <p className="text-[10px] text-slate-500 flex items-center gap-1 mt-0.5"><MapPin size={8} /> {lead.location} - {lead.state}</p>}
                                    </td>
                                    <td className="p-4">
                                        <div className="space-y-1">
                                            {lead.phone && <p className="text-xs text-slate-300 flex items-center gap-1"><Phone size={10} /> {lead.phone}</p>}
                                            {lead.instagram && <p className="text-xs text-slate-300 flex items-center gap-1"><Instagram size={10} /> {lead.instagram}</p>}
                                            {lead.cpfCnpj && <p className="text-[10px] text-slate-500">Doc: {lead.cpfCnpj}</p>}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${getStatusColor(lead.status)}`}>
                                            {getStatusLabel(lead.status)}
                                        </span>
                                    </td>
                                    <td className="p-4 text-slate-300 font-mono">${lead.value.toLocaleString()}</td>
                                    <td className="p-4">
                                        <div className="flex items-center gap-2">
                                            <div className="w-16 h-1.5 bg-slate-700 rounded-full overflow-hidden">
                                                <div className="h-full bg-blue-500" style={{ width: `${lead.probability}%` }}></div>
                                            </div>
                                            <span className="text-xs text-slate-400">{lead.probability}%</span>
                                        </div>
                                    </td>
                                    <td className="p-4 text-right">
                                        <button className="text-slate-500 hover:text-white p-2">
                                            <Edit3 size={18} />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
          )}

          {/* --- MAP SECTION (Dedicated View) --- */}
          {viewMode === 'map' && (
              <section className="animate-fade-in space-y-6">
                  <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden">
                      <div className="p-6 border-b border-slate-700 bg-slate-900/50 flex flex-col md:flex-row md:justify-between md:items-center gap-4">
                          <div>
                              <h2 className="text-xl font-bold text-white flex items-center gap-2">
                                  <MapIcon className="text-blue-500" /> Clientes pelo Mapa
                              </h2>
                              <p className="text-sm text-slate-400">Distribuição geográfica dos seus leads e clientes.</p>
                          </div>
                      </div>

                      <div className="h-[600px] w-full relative bg-slate-900">
                          <div ref={mapContainerRef} className="h-full w-full z-10" />

                          {leads.filter(l => l.lat).length === 0 && (
                              <div className="absolute inset-0 z-20 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm">
                                  <div className="text-center p-6 max-w-md">
                                      <Globe2 size={48} className="mx-auto text-slate-600 mb-4" />
                                      <h3 className="text-lg font-bold text-white">Mapa Vazio</h3>
                                      <p className="text-slate-400 text-sm mt-2">Cadastre clientes com Endereço e CEP para visualizá-los aqui.</p>
                                  </div>
                              </div>
                          )}
                      </div>
                  </div>

                  {/* State Report Section */}
                   <div className="p-6 bg-slate-800 rounded-2xl border border-slate-700">
                      <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                          <MapPin size={14} /> Detalhamento por Região
                      </h3>

                      {Object.keys(leadsByState).length === 0 ? (
                          <div className="text-slate-500 text-sm italic py-2">
                              Nenhum dado de localização disponível.
                          </div>
                      ) : (
                          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-3">
                              {Object.entries(leadsByState)
                                .sort((a, b) => (b[1] as number) - (a[1] as number))
                                .map(([state, count]) => (
                                  <div key={state} className="bg-slate-900/50 p-3 rounded-lg border border-slate-700 flex flex-col items-center justify-center hover:border-blue-500/50 transition-colors group">
                                      <span className="font-bold text-2xl text-white mb-1 group-hover:text-blue-400 transition-colors">{state}</span>
                                      <span className="text-xs text-slate-400 font-medium bg-slate-800 px-2 py-0.5 rounded-full border border-slate-700">
                                          {count} {count === 1 ? 'Cliente' : 'Clientes'}
                                      </span>
                                  </div>
                              ))}
                          </div>
                      )}
                  </div>
              </section>
          )}

      </div>

      {/* MODAL: CLIENT FORM (CREATE / EDIT) */}
      {showClientForm && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
              <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl">
                  <header className="p-6 border-b border-slate-800 flex justify-between items-center sticky top-0 bg-slate-900 z-10">
                      <h2 className="text-xl font-bold text-white flex items-center gap-2">
                          {editingLeadId ? <Edit3 className="text-blue-500" /> : <Plus className="text-emerald-500" />}
                          {editingLeadId ? 'Editar Cliente' : 'Cadastro de Novo Cliente'}
                      </h2>
                      <button onClick={() => setShowClientForm(false)} className="text-slate-400 hover:text-white">
                          <X size={24} />
                      </button>
                  </header>

                  <form onSubmit={handleSaveClient} className="p-6 space-y-6">
                      {/* Dados Principais */}
                      <div className="space-y-4">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <User size={14} /> Informações Básicas
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Nome Completo *</label>
                                  <input 
                                    required
                                    type="text" 
                                    value={clientFormData.name} 
                                    onChange={e => setClientFormData({...clientFormData, name: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Ex: João Silva"
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Empresa</label>
                                  <input 
                                    type="text" 
                                    value={clientFormData.company} 
                                    onChange={e => setClientFormData({...clientFormData, company: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Ex: Minha Empresa Ltda"
                                  />
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">CPF ou CNPJ</label>
                                  <input 
                                    type="text" 
                                    value={clientFormData.cpfCnpj} 
                                    onChange={e => setClientFormData({...clientFormData, cpfCnpj: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="000.000.000-00"
                                  />
                              </div>
                          </div>
                      </div>

                      {/* Contato e Localização */}
                      <div className="space-y-4 pt-4 border-t border-slate-800">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <MapPin size={14} /> Contato & Localização
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div>
                                  <label className="block text-xs text-slate-400 mb-1">Telefone</label>
                                  <div className="relative">
                                    <Phone className="absolute left-3 top-3.5 text-slate-500" size={16} />
                                    <input 
                                        type="text" 
                                        value={clientFormData.phone} 
                                        onChange={e => setClientFormData({...clientFormData, phone: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 pl-10 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="(00) 00000-0000"
                                    />
                                  </div>
                              </div>
                              <div>
                                  <label className="block text-xs text-slate-400 mb-1">Instagram da Empresa</label>
                                  <div className="relative">
                                    <Instagram className="absolute left-3 top-3.5 text-slate-500" size={16} />
                                    <input 
                                        type="text" 
                                        value={clientFormData.instagram} 
                                        onChange={e => setClientFormData({...clientFormData, instagram: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 pl-10 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="@usuario"
                                    />
                                  </div>
                              </div>

                              {/* FULL ADDRESS FIELDS */}
                              <div className="md:col-span-2 grid grid-cols-4 gap-4">
                                  <div className="col-span-1">
                                      <label className="block text-xs text-slate-400 mb-1">CEP</label>
                                      <input 
                                        type="text" 
                                        value={clientFormData.zipCode} 
                                        onChange={e => setClientFormData({...clientFormData, zipCode: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="00000-000"
                                      />
                                  </div>
                                  <div className="col-span-3">
                                      <label className="block text-xs text-slate-400 mb-1">Endereço (Rua/Av)</label>
                                      <input 
                                        type="text" 
                                        value={clientFormData.address} 
                                        onChange={e => setClientFormData({...clientFormData, address: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="Rua Exemplo"
                                      />
                                  </div>
                              </div>

                              <div className="md:col-span-2 grid grid-cols-4 gap-4">
                                  <div className="col-span-1">
                                      <label className="block text-xs text-slate-400 mb-1">Número</label>
                                      <input 
                                        type="text" 
                                        value={clientFormData.number} 
                                        onChange={e => setClientFormData({...clientFormData, number: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="123"
                                      />
                                  </div>
                                  <div className="col-span-2">
                                      <label className="block text-xs text-slate-400 mb-1">Cidade</label>
                                      <input 
                                        type="text" 
                                        value={clientFormData.location} 
                                        onChange={e => setClientFormData({...clientFormData, location: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="Cidade"
                                      />
                                  </div>
                                   <div className="col-span-1">
                                      <label className="block text-xs text-slate-400 mb-1">Estado (UF)</label>
                                      <input 
                                        type="text" 
                                        value={clientFormData.state} 
                                        onChange={e => setClientFormData({...clientFormData, state: e.target.value})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                        placeholder="SP"
                                        maxLength={2}
                                      />
                                  </div>
                              </div>
                          </div>
                      </div>

                       {/* Dados do Pipeline (Opcionais para cadastro rápido) */}
                       <div className="space-y-4 pt-4 border-t border-slate-800">
                          <h3 className="text-sm uppercase font-bold text-slate-500 tracking-wider flex items-center gap-2">
                              <TrendingUp size={14} /> Dados do Pipeline ({activeFunnel.name})
                          </h3>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <div>
                                    <label className="block text-xs text-slate-400 mb-1">Valor Potencial ($)</label>
                                    <input 
                                        type="number" 
                                        value={clientFormData.value} 
                                        onChange={e => setClientFormData({...clientFormData, value: Number(e.target.value)})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="block text-xs text-slate-400 mb-1">Fase do Pipeline</label>
                                    <select 
                                        value={clientFormData.status} 
                                        onChange={e => setClientFormData({...clientFormData, status: e.target.value as any})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    >
                                        {activeFunnel.stages.map(s => (
                                            <option key={s.id} value={s.id}>{s.name}</option>
                                        ))}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-xs text-slate-400 mb-1">Probabilidade (%)</label>
                                    <input 
                                        type="number" 
                                        value={clientFormData.probability} 
                                        onChange={e => setClientFormData({...clientFormData, probability: Number(e.target.value)})}
                                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    />
                                </div>
                          </div>
                          <div>
                                <label className="block text-xs text-slate-400 mb-1">Próxima Ação</label>
                                <input 
                                    type="text" 
                                    value={clientFormData.nextAction} 
                                    onChange={e => setClientFormData({...clientFormData, nextAction: e.target.value})}
                                    className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-emerald-500 focus:outline-none"
                                    placeholder="Ex: Ligar amanhã"
                                />
                          </div>
                       </div>

                      <div className="pt-6 flex gap-3">
                          <button 
                            type="button" 
                            onClick={() => setShowClientForm(false)}
                            className="flex-1 py-3 bg-slate-800 text-slate-300 font-bold rounded-lg hover:bg-slate-700 transition-colors"
                          >
                            Cancelar
                          </button>
                          <button 
                            type="submit" 
                            disabled={isGeocoding}
                            className="flex-1 py-3 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-500 transition-colors flex justify-center items-center gap-2 disabled:opacity-50"
                          >
                            {isGeocoding ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />} 
                            {isGeocoding ? 'Localizando Endereço...' : (editingLeadId ? 'Atualizar Cliente' : 'Salvar Cliente')}
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* MODAL: FUNNEL MANAGER (CREATE/EDIT) */}
      {showFunnelModal && editingFunnel && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
              <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto shadow-2xl">
                   <header className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900 z-10">
                      <h2 className="text-xl font-bold text-white flex items-center gap-2">
                          <Settings className="text-blue-500" /> {editingFunnel.id ? 'Editar Funil e Fases' : 'Novo Funil'}
                      </h2>
                      <button onClick={() => setShowFunnelModal(false)} className="text-slate-400 hover:text-white">
                          <X size={24} />
                      </button>
                  </header>

                  <form onSubmit={handleSaveFunnel} className="p-6 space-y-6">
                      <div>
                          <label className="block text-xs text-slate-400 mb-1 uppercase font-bold">Nome do Funil</label>
                          <input 
                             required
                             type="text"
                             value={editingFunnel.name}
                             onChange={(e) => setEditingFunnel({...editingFunnel, name: e.target.value})}
                             className="w-full bg-slate-800 border border-slate-700 rounded-lg p-3 text-white focus:border-blue-500 focus:outline-none"
                             placeholder="Ex: Vendas B2B"
                          />
                      </div>

                      <div className="space-y-3">
                          <div className="flex justify-between items-center">
                              <label className="block text-xs text-slate-400 uppercase font-bold">Fases do Funil (Edite os nomes aqui)</label>
                              <button type="button" onClick={addStage} className="text-xs text-emerald-400 hover:text-emerald-300 flex items-center gap-1">
                                  <Plus size={12}/> Adicionar Fase
                              </button>
                          </div>

                          <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                              {editingFunnel.stages?.map((stage, idx) => (
                                  <div key={idx} className="flex gap-2 items-center">
                                      <div className="cursor-grab text-slate-600"><GripVertical size={16}/></div>
                                      <input 
                                         type="text"
                                         value={stage.name}
                                         onChange={(e) => updateStage(idx, 'name', e.target.value)}
                                         className="flex-1 bg-slate-800 border border-slate-700 rounded px-3 py-2 text-sm text-white focus:border-blue-500 focus:outline-none"
                                         placeholder="Nome da Fase"
                                      />
                                      <select
                                          value={stage.color}
                                          onChange={(e) => updateStage(idx, 'color', e.target.value)}
                                          className="w-8 h-9 bg-slate-800 border border-slate-700 rounded text-transparent focus:outline-none cursor-pointer"
                                          style={{backgroundColor: stage.color.replace('border-', '').replace('/50', '').replace('500', '500')}} // Rough preview
                                      >
                                          <option value="border-slate-500/50" className="text-black">Cinza</option>
                                          <option value="border-blue-500/50" className="text-blue-500">Azul</option>
                                          <option value="border-emerald-500/50" className="text-emerald-500">Verde</option>
                                          <option value="border-purple-500/50" className="text-purple-500">Roxo</option>
                                          <option value="border-amber-500/50" className="text-amber-500">Amarelo</option>
                                          <option value="border-red-500/50" className="text-red-500">Vermelho</option>
                                          <option value="border-pink-500/50" className="text-pink-500">Rosa</option>
                                          <option value="border-cyan-500/50" className="text-cyan-500">Ciano</option>
                                      </select>
                                      <button 
                                        type="button" 
                                        onClick={() => removeStage(idx)}
                                        className="text-slate-500 hover:text-red-400 p-2"
                                        disabled={editingFunnel.stages!.length <= 1}
                                      >
                                          <Trash2 size={16}/>
                                      </button>
                                  </div>
                              ))}
                          </div>
                      </div>

                      <button type="submit" className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 rounded-lg shadow-lg">
                          Salvar Configuração
                      </button>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Task, TaskCategory, UserStats } from '../types';
import { CheckSquare, Square, Trash2, Plus, Clock, AlertCircle, Calendar as CalendarIcon, CalendarDays, AlertTriangle, ArrowRight, History, ChevronLeft, ChevronRight, RotateCcw, CornerDownRight } from 'lucide-react';

interface ProductivityProps {
    tasks: Task[];
    stats: UserStats;
    onToggleTask: (id: string) => void;
    onDeleteTask: (id: string) => void;
    onAddTask: (task: Partial<Task>) => void;
}

export const Productivity: React.FC<ProductivityProps> = ({ tasks, stats, onToggleTask, onDeleteTask, onAddTask }) => {
    // View Mode State
    const [viewMode, setViewMode] = useState<'day' | 'week' | 'month'>('day');

    // Current Date being viewed (defaults to Today)
    const [currentViewDate, setCurrentViewDate] = useState(new Date());

    // Form State
    const [title, setTitle] = useState('');
    const [time, setTime] = useState('');
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]); // Default to today
    const [duration, setDuration] = useState(60);
    const [category, setCategory] = useState<TaskCategory>('work');

    // Sync form date when view date changes (helpful when clicking a day in calendar)
    useEffect(() => {
        // We update the form date whenever the viewed date changes, 
        // so adding a task defaults to the currently viewed day.
        setDate(currentViewDate.toISOString().split('T')[0]);
    }, [currentViewDate]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (title.trim()) {
            onAddTask({
                title,
                startTime: time || '00:00',
                date: new Date(date).toISOString(),
                durationMinutes: duration,
                category,
                completed: false,
                xpReward: category === 'wasted' ? 0 : (duration >= 60 ? 100 : 50)
            });
            setTitle('');
            setTime('');
        }
    };

    const handleJumpToDate = (isoDate: string | Date) => {
        const targetDate = new Date(isoDate);
        // Fix timezone offset issues by setting hours to 12
        targetDate.setHours(12, 0, 0, 0);
        setCurrentViewDate(targetDate);
        setViewMode('day');
    };

    const navigateDay = (direction: 'prev' | 'next') => {
        const newDate = new Date(currentViewDate);
        newDate.setDate(newDate.getDate() + (direction === 'next' ? 1 : -1));
        setCurrentViewDate(newDate);
    };

    const navigateMonth = (direction: 'prev' | 'next') => {
        const newDate = new Date(currentViewDate);
        newDate.setMonth(newDate.getMonth() + (direction === 'next' ? 1 : -1));
        setCurrentViewDate(newDate);
    }

    const resetToToday = () => {
        setCurrentViewDate(new Date());
        setViewMode('day');
    };

    const getCategoryColor = (cat: TaskCategory) => {
        switch(cat) {
            case 'work': return 'bg-blue-600/20 border-l-4 border-blue-500 text-blue-100';
            case 'study': return 'bg-purple-600/20 border-l-4 border-purple-500 text-purple-100';
            case 'workout': return 'bg-emerald-600/20 border-l-4 border-emerald-500 text-emerald-100';
            case 'wasted': return 'bg-red-600/20 border-l-4 border-red-500 text-red-100 opacity-60';
            case 'leisure': return 'bg-pink-600/20 border-l-4 border-pink-500 text-pink-100';
            default: return 'bg-slate-700/50 border-l-4 border-slate-500 text-slate-300';
        }
    };

    // --- Filter Logic ---
    const isViewingToday = () => {
        const today = new Date();
        return currentViewDate.getDate() === today.getDate() &&
               currentViewDate.getMonth() === today.getMonth() &&
               currentViewDate.getFullYear() === today.getFullYear();
    };

    const getFilteredTasks = () => {
        const viewDateStart = new Date(currentViewDate);
        viewDateStart.setHours(0,0,0,0);

        const today = new Date();
        today.setHours(0,0,0,0);

        return tasks.filter(task => {
            const taskDate = new Date(task.date);
            taskDate.setHours(0,0,0,0);

            if (viewMode === 'day') {
                // If viewing Today: Return Today's tasks AND Past Incomplete tasks
                if (isViewingToday()) {
                    return taskDate.getTime() === today.getTime() || (taskDate < today && !task.completed);
                }
                // If viewing another day: Return only that day's tasks
                return taskDate.getTime() === viewDateStart.getTime();

            } else if (viewMode === 'week') {
                const startOfWeek = new Date(today);
                startOfWeek.setDate(today.getDate() - today.getDay());
                const endOfWeek = new Date(today);
                endOfWeek.setDate(today.getDate() + (6 - today.getDay()));
                return taskDate >= startOfWeek && taskDate <= endOfWeek;
            } 
            // Note: Month filtering is handled separately in the Calendar Grid logic
            return true;
        }).sort((a, b) => {
            if (a.date !== b.date) return new Date(a.date).getTime() - new Date(b.date).getTime();
            const timeA = a.startTime || '23:59';
            const timeB = b.startTime || '23:59';
            return timeA.localeCompare(timeB);
        });
    };

    const filteredTasks = getFilteredTasks();
    const pendingCount = filteredTasks.filter(t => !t.completed).length;

    // Helper to group tasks
    const todayRef = new Date();
    todayRef.setHours(0,0,0,0);

    // Split tasks for Day View logic
    const overdueTasks = (viewMode === 'day' && isViewingToday()) 
        ? filteredTasks.filter(t => new Date(t.date) < todayRef) 
        : [];

    const viewDateTasks = (viewMode === 'day')
        ? filteredTasks.filter(t => {
            if (isViewingToday()) return new Date(t.date) >= todayRef; // Today's tasks
            return true; // All tasks for the selected historical date
        })
        : [];

    const groupedTasks: { [key: string]: Task[] } = {};
    if (viewMode === 'week') {
        filteredTasks.forEach(task => {
            const dateKey = new Date(task.date).toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit' });
            if (!groupedTasks[dateKey]) groupedTasks[dateKey] = [];
            groupedTasks[dateKey].push(task);
        });
    }

    // --- CALENDAR GRID GENERATION ---
    const generateCalendarDays = () => {
        const year = currentViewDate.getFullYear();
        const month = currentViewDate.getMonth();

        const firstDayOfMonth = new Date(year, month, 1).getDay(); // 0 = Sunday
        const daysInMonth = new Date(year, month + 1, 0).getDate();

        const days = [];
        // Add empty slots for days before the 1st
        for (let i = 0; i < firstDayOfMonth; i++) {
            days.push(null);
        }
        // Add actual days
        for (let i = 1; i <= daysInMonth; i++) {
            days.push(new Date(year, month, i));
        }
        return days;
    };

    return (
        <div className="p-4 md:p-8 flex flex-col max-w-7xl mx-auto">
            <header className="mb-8 flex flex-col md:flex-row md:justify-between md:items-end gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                        <CheckSquare className="text-emerald-500" /> Cronograma
                    </h1>
                    <p className="text-slate-400">Gerenciamento de tempo Macro e Micro.</p>
                </div>

                <div className={`px-6 py-3 rounded-lg border flex items-center gap-4 shadow-lg ${pendingCount > 0 ? 'bg-amber-900/30 border-amber-500/50' : 'bg-emerald-900/30 border-emerald-500/50'}`}>
                     {pendingCount > 0 ? <AlertTriangle className="text-amber-500" size={24} /> : <CheckSquare className="text-emerald-500" size={24}/>}
                     <div>
                         <p className={`text-xs font-bold uppercase ${pendingCount > 0 ? 'text-amber-500' : 'text-emerald-500'}`}>Status Atual</p>
                         <p className="text-white font-bold text-lg">{pendingCount > 0 ? `${pendingCount} Tarefas Pendentes` : 'Tudo Feito!'}</p>
                     </div>
                </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

                {/* Agendamento Manual */}
                <div className="md:col-span-1">
                    <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 h-fit shadow-xl sticky top-4">
                        <h3 className="text-white font-bold mb-6 flex items-center gap-2 text-lg">
                            <Plus size={20} className="text-blue-400"/> Novo Evento
                        </h3>
                        <form onSubmit={handleSubmit} className="space-y-5">
                            <div>
                                <label className="text-xs text-slate-400 uppercase font-bold tracking-wider">O que fazer?</label>
                                <input 
                                    type="text" 
                                    value={title}
                                    onChange={(e) => setTitle(e.target.value)}
                                    placeholder="Ex: Reunião de Alinhamento"
                                    className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3.5 mt-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 transition-all"
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-xs text-slate-400 uppercase font-bold tracking-wider">Data</label>
                                    <input 
                                        type="date" 
                                        value={date}
                                        onChange={(e) => setDate(e.target.value)}
                                        className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3.5 mt-2 focus:border-blue-500 focus:outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="text-xs text-slate-400 uppercase font-bold tracking-wider">Início</label>
                                    <input 
                                        type="time" 
                                        value={time}
                                        onChange={(e) => setTime(e.target.value)}
                                        className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3.5 mt-2 focus:border-blue-500 focus:outline-none"
                                    />
                                </div>
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-xs text-slate-400 uppercase font-bold tracking-wider">Duração (min)</label>
                                    <input 
                                        type="number" 
                                        value={duration}
                                        onChange={(e) => setDuration(Number(e.target.value))}
                                        className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3.5 mt-2 focus:border-blue-500 focus:outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="text-xs text-slate-400 uppercase font-bold tracking-wider">Categoria</label>
                                    <select 
                                        value={category}
                                        onChange={(e) => setCategory(e.target.value as TaskCategory)}
                                        className="w-full bg-slate-900 border border-slate-700 text-white rounded-lg p-3.5 mt-2 focus:border-blue-500 focus:outline-none"
                                    >
                                        <option value="work">Trabalho</option>
                                        <option value="study">Estudo</option>
                                        <option value="workout">Treino</option>
                                        <option value="routine">Rotina</option>
                                        <option value="leisure">Lazer</option>
                                        <option value="wasted">Tempo Ocioso</option>
                                    </select>
                                </div>
                            </div>
                            <button type="submit" className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-lg transition-all shadow-lg shadow-blue-900/20 mt-2">
                            Agendar
                            </button>
                        </form>
                    </div>
                </div>

                {/* Área de Visualização (Dia / Semana / Calendário) */}
                <div className="md:col-span-2 bg-slate-900/50 rounded-xl border border-slate-800 flex flex-col relative shadow-2xl min-h-[600px]">

                    {/* View Switcher Tabs */}
                    <div className="flex border-b border-slate-800 bg-slate-950 sticky top-0 z-20 rounded-t-xl">
                        <button 
                            onClick={() => { setViewMode('day'); resetToToday(); }}
                            className={`flex-1 py-5 text-sm font-bold flex justify-center items-center gap-2 transition-colors ${viewMode === 'day' ? 'text-blue-400 border-b-2 border-blue-500 bg-slate-900' : 'text-slate-500 hover:bg-slate-900 hover:text-slate-300'}`}
                        >
                            <Clock size={16} /> Dia
                        </button>
                        <button 
                            onClick={() => setViewMode('week')}
                            className={`flex-1 py-5 text-sm font-bold flex justify-center items-center gap-2 transition-colors ${viewMode === 'week' ? 'text-blue-400 border-b-2 border-blue-500 bg-slate-900' : 'text-slate-500 hover:bg-slate-900 hover:text-slate-300'}`}
                        >
                            <CalendarIcon size={16} /> Semana
                        </button>
                        <button 
                            onClick={() => setViewMode('month')}
                            className={`flex-1 py-5 text-sm font-bold flex justify-center items-center gap-2 transition-colors ${viewMode === 'month' ? 'text-blue-400 border-b-2 border-blue-500 bg-slate-900' : 'text-slate-500 hover:bg-slate-900 hover:text-slate-300'}`}
                        >
                            <CalendarDays size={16} /> Mês
                        </button>
                    </div>

                    <div className="p-6 bg-slate-900 rounded-b-xl relative flex-1">

                        {/* 1. DAY VIEW */}
                        {viewMode === 'day' && (
                            <>
                                <div className="flex items-center justify-between mb-8 pb-4 border-b border-slate-800">
                                    <button onClick={() => navigateDay('prev')} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
                                        <ChevronLeft size={24} />
                                    </button>
                                    <div className="text-center">
                                        <h2 className="text-xl font-bold text-white capitalize">
                                            {currentViewDate.toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}
                                        </h2>
                                        {!isViewingToday() && (
                                            <button onClick={resetToToday} className="text-xs text-blue-400 font-bold flex items-center justify-center gap-1 mt-1 hover:underline">
                                                <RotateCcw size={10} /> Voltar para Hoje
                                            </button>
                                        )}
                                    </div>
                                    <button onClick={() => navigateDay('next')} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
                                        <ChevronRight size={24} />
                                    </button>
                                </div>

                                {filteredTasks.length === 0 && (
                                     <div className="flex flex-col items-center justify-center py-20 text-slate-600">
                                        <Clock size={64} className="mb-4 opacity-30"/>
                                        <p className="text-lg font-medium">Agenda livre.</p>
                                        <p className="text-sm">Nenhuma tarefa encontrada para este dia.</p>
                                    </div>
                                )}

                                {/* OVERDUE SECTION */}
                                {overdueTasks.length > 0 && (
                                    <div className="mb-8 animate-fade-in bg-red-950/10 border border-red-900/30 rounded-xl p-4">
                                        <div className="flex items-center gap-3 mb-4 pb-2 border-b border-red-500/20">
                                            <AlertCircle className="text-red-500" />
                                            <span className="text-red-400 font-bold uppercase tracking-widest text-sm">Pendentes de Dias Anteriores</span>
                                        </div>
                                        <div className="space-y-4">
                                            {overdueTasks.map((task) => (
                                                <TaskItem 
                                                    key={task.id} 
                                                    task={task} 
                                                    onToggle={onToggleTask} 
                                                    onDelete={onDeleteTask} 
                                                    getCategoryColor={getCategoryColor}
                                                    isOverdue={true}
                                                    onJumpToDate={() => handleJumpToDate(task.date)}
                                                />
                                            ))}
                                        </div>
                                    </div>
                                )}

                                {/* CURRENT DAY TASKS SECTION */}
                                {viewDateTasks.length > 0 && (
                                    <div className="relative">
                                         {/* Vertical Guide Line */}
                                        <div className="absolute top-4 bottom-4 left-[3.25rem] w-px bg-slate-800 z-0"></div>

                                        <div className="flex items-center gap-3 mb-6 pb-2 border-b border-slate-800 mt-4">
                                            <div className="w-2.5 h-2.5 bg-blue-500 rounded-full shadow-[0_0_10px_rgba(59,130,246,0.5)]"></div>
                                            <span className="text-slate-200 font-bold uppercase tracking-widest text-sm">
                                                {isViewingToday() ? 'Cronograma de Hoje' : 'Histórico do Dia'}
                                            </span>
                                        </div>

                                        <div className="space-y-2 relative z-10">
                                            {viewDateTasks.map((task) => (
                                                <TaskItem 
                                                    key={task.id} 
                                                    task={task} 
                                                    onToggle={onToggleTask} 
                                                    onDelete={onDeleteTask} 
                                                    getCategoryColor={getCategoryColor}
                                                />
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </>
                        )}

                        {/* 2. WEEK VIEW */}
                        {viewMode === 'week' && Object.keys(groupedTasks).map(dateKey => (
                            <div key={dateKey} className="animate-fade-in mb-8">
                                <div className="sticky top-16 bg-slate-900/95 backdrop-blur py-3 z-10 flex items-center gap-3 border-b border-slate-800 mb-4">
                                    <div className="w-2.5 h-2.5 bg-blue-500 rounded-full shadow-[0_0_10px_rgba(59,130,246,0.5)]"></div>
                                    <span className="text-slate-200 font-bold uppercase text-sm tracking-widest">{dateKey}</span>
                                </div>
                                <div className="space-y-1 pl-4 ml-1 border-l-2 border-slate-800/50">
                                    {groupedTasks[dateKey].map((task) => (
                                        <TaskItem 
                                            key={task.id} 
                                            task={task} 
                                            onToggle={onToggleTask} 
                                            onDelete={onDeleteTask} 
                                            getCategoryColor={getCategoryColor} 
                                            compact={true}
                                        />
                                    ))}
                                </div>
                            </div>
                        ))}

                        {/* 3. CALENDAR MONTH VIEW */}
                        {viewMode === 'month' && (
                             <div className="animate-fade-in flex flex-col h-full">
                                {/* Calendar Controls */}
                                <div className="flex items-center justify-between mb-6 pb-4 border-b border-slate-800">
                                    <button onClick={() => navigateMonth('prev')} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
                                        <ChevronLeft size={24} />
                                    </button>
                                    <h2 className="text-xl font-bold text-white capitalize">
                                        {currentViewDate.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' })}
                                    </h2>
                                    <button onClick={() => navigateMonth('next')} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400 hover:text-white transition-colors">
                                        <ChevronRight size={24} />
                                    </button>
                                </div>

                                {/* Calendar Grid */}
                                <div className="grid grid-cols-7 gap-2 text-center mb-2">
                                    {['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].map(d => (
                                        <div key={d} className="text-xs font-bold text-slate-500 uppercase py-2">{d}</div>
                                    ))}
                                </div>
                                <div className="grid grid-cols-7 gap-2 auto-rows-fr flex-1">
                                    {generateCalendarDays().map((dateItem, idx) => {
                                        if (!dateItem) return <div key={`empty-${idx}`} className="bg-transparent p-2"></div>;

                                        // Check if this date is "Today"
                                        const isToday = new Date().toDateString() === dateItem.toDateString();

                                        // Find tasks for this date
                                        const dayTasks = tasks.filter(t => {
                                            const tDate = new Date(t.date);
                                            return tDate.getDate() === dateItem.getDate() && 
                                                   tDate.getMonth() === dateItem.getMonth() &&
                                                   tDate.getFullYear() === dateItem.getFullYear();
                                        });

                                        const hasPending = dayTasks.some(t => !t.completed);
                                        const hasCompleted = dayTasks.some(t => t.completed);

                                        return (
                                            <button 
                                                key={dateItem.toISOString()} 
                                                onClick={() => handleJumpToDate(dateItem)}
                                                className={`
                                                    relative p-2 rounded-xl border flex flex-col items-start justify-start min-h-[80px] transition-all hover:scale-105 group
                                                    ${isToday ? 'bg-blue-900/20 border-blue-500/50' : 'bg-slate-800 border-slate-700 hover:bg-slate-700 hover:border-slate-500'}
                                                `}
                                            >
                                                <span className={`text-sm font-bold ${isToday ? 'text-blue-400' : 'text-slate-300'}`}>
                                                    {dateItem.getDate()}
                                                </span>

                                                {/* Dots Indicator */}
                                                <div className="mt-auto flex gap-1 flex-wrap">
                                                    {hasPending && <div className="w-2 h-2 rounded-full bg-amber-500 shadow-[0_0_5px_rgba(245,158,11,0.5)]"></div>}
                                                    {hasCompleted && <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]"></div>}
                                                    {dayTasks.length > 0 && <span className="text-[10px] text-slate-500 ml-1">({dayTasks.length})</span>}
                                                </div>

                                                {/* Add hover effect text */}
                                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/40 backdrop-blur-[1px] rounded-xl transition-opacity">
                                                    <Plus size={20} className="text-white"/>
                                                </div>
                                            </button>
                                        );
                                    })}
                                </div>
                             </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

// Sub-component for rendering a single task row with EXPANDED view
const TaskItem = ({ task, onToggle, onDelete, getCategoryColor, compact = false, isOverdue = false, onJumpToDate }: any) => {
    if (compact) {
        return (
            <div className={`flex items-center gap-4 p-4 rounded-lg border ${getCategoryColor(task.category)} transition-all hover:brightness-110 relative group mb-2 bg-slate-800/50`}>
                <button 
                    onClick={() => onToggle(task.id)} 
                    className={`text-inherit transition-transform active:scale-90 ${task.completed ? 'opacity-50' : ''}`}
                >
                    {task.completed ? <CheckSquare size={20} /> : <Square size={20} />}
                </button>
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                        <span className="text-xs font-mono font-bold opacity-70 border border-current px-1 rounded">{task.startTime}</span>
                        <span className={`font-medium truncate ${task.completed ? 'line-through opacity-60' : ''}`}>
                            {task.title}
                        </span>
                    </div>
                </div>
                <button onClick={() => onDelete(task.id)} className="opacity-0 group-hover:opacity-100 text-inherit hover:text-red-400 transition-opacity p-2">
                    <Trash2 size={16} />
                </button>
            </div>
        )
    }

    return (
        <div className="flex group relative">
            {/* Timeline Time Column */}
            <div className="flex flex-col items-center mr-6 w-14 shrink-0 pt-6">
                <span className={`text-sm font-bold font-mono mb-2 ${isOverdue ? 'text-red-400' : 'text-slate-400'}`}>
                    {isOverdue ? <History size={16}/> : task.startTime}
                </span>
                <div className={`w-4 h-4 rounded-full border-2 z-10 transition-colors ${task.completed ? 'bg-slate-700 border-slate-600' : (isOverdue ? 'bg-red-500 border-red-400 shadow-[0_0_10px_rgba(239,68,68,0.6)]' : 'bg-blue-500 border-blue-400 shadow-[0_0_10px_rgba(59,130,246,0.6)]')}`}></div>
            </div>

            {/* Task Card - Expanded (FIXED HEIGHT) */}
            <div 
                className={`flex-1 flex items-center gap-5 p-6 h-32 mb-3 rounded-2xl border ${getCategoryColor(task.category)} transition-all hover:brightness-110 relative bg-slate-800/40 shadow-lg ${isOverdue ? 'cursor-pointer hover:border-red-400 hover:shadow-red-900/20' : ''}`}
            >
                {/* Large Checkbox */}
                <div className="z-10 shrink-0" onClick={(e) => e.stopPropagation()}>
                    <button 
                        onClick={() => onToggle(task.id)} 
                        className={`text-inherit transition-all active:scale-90 hover:scale-105 mt-1 ${task.completed ? 'opacity-40' : 'opacity-100'}`}
                    >
                        {task.completed ? <CheckSquare size={32} /> : <Square size={32} strokeWidth={1.5} />}
                    </button>
                </div>

                {/* Content - Clickable if Overdue */}
                <div 
                    className="flex-1 min-w-0 flex flex-col justify-center h-full"
                    onClick={isOverdue ? onJumpToDate : undefined}
                >
                    <div className="flex items-start justify-between mb-2 w-full">
                        <span className={`text-xl font-bold leading-tight truncate w-full pr-8 ${task.completed ? 'line-through opacity-50 text-slate-400' : 'text-white'}`} title={task.title}>
                            {task.title}
                        </span>
                         {isOverdue && (
                            <span className="shrink-0 flex items-center gap-1 bg-red-500/20 text-red-400 border border-red-500/30 px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest group-hover:bg-red-500 group-hover:text-white transition-colors">
                                <CornerDownRight size={10} /> Ir para o dia
                            </span>
                        )}
                    </div>

                    <div className="flex items-center gap-4 text-sm opacity-80 mt-1">
                         {isOverdue && <span className="text-xs font-mono text-red-300 bg-red-900/50 px-2 rounded border border-red-800">{new Date(task.date).toLocaleDateString('pt-BR')}</span>}
                        <span className="flex items-center gap-1.5 bg-black/20 px-2 py-1 rounded text-xs font-mono"><Clock size={12}/> {task.durationMinutes} min</span>
                        <span className="uppercase tracking-widest font-bold text-[10px] border border-current px-2 py-0.5 rounded-full">{task.category}</span>
                        {!task.completed && !isOverdue && (
                            <span className="text-amber-400 text-xs font-bold uppercase tracking-wider flex items-center gap-1 ml-auto animate-pulse">
                                <AlertCircle size={12}/> Pendente
                            </span>
                        )}
                    </div>
                </div>

                {/* Delete Action */}
                <div className="absolute top-4 right-4 z-10" onClick={(e) => e.stopPropagation()}>
                    <button onClick={() => onDelete(task.id)} className="opacity-0 group-hover:opacity-100 text-slate-500 hover:text-red-400 transition-all p-2 bg-slate-900/50 rounded-lg backdrop-blur-sm">
                        <Trash2 size={18} />
                    </button>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { Lead, Funnel, FunnelStage } from '../types';
import { MOCK_LEADS, MOCK_FUNNELS } from '../constants';
import { analyzeCRM } from '../services/geminiService';
import { TrendingUp, Users, DollarSign, Brain, MoreHorizontal, Plus, X, Save, MapPin, Instagram, Phone, Building2, User, LayoutGrid, List as ListIcon, GripVertical, Settings, Trash2, ChevronDown, Edit3, Map as MapIcon, Globe2, Loader2 } from 'lucide-react';
import L from 'leaflet';

export const Professional: React.FC = () => {
  // Data State
  const [funnels, setFunnels] = useState<Funnel[]>(MOCK_FUNNELS);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS as any);
  const [activeFunnelId, setActiveFunnelId] = useState<string>(MOCK_FUNNELS[0].id);

  // View & UX State
  const [aiAnalysis, setAiAnalysis] = useState<string>("");
  const [analyzing, setAnalyzing] = useState(false);
  const [showClientForm, setShowClientForm] = useState(false);
  const [showFunnelModal, setShowFunnelModal] = useState(false);
  const [viewMode, setViewMode] = useState<'list' | 'kanban' | 'map'>('kanban');
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);
  const [isGeocoding, setIsGeocoding] = useState(false);

  // -- MAP REFS --
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);

  // -- FUNNEL EDITING STATE --
  const [editingFunnel, setEditingFunnel] = useState<Partial<Funnel> | null>(null);
  const [showFunnelDropdown, setShowFunnelDropdown] = useState(false);

  // -- CLIENT FORM STATE --
  const [editingLeadId, setEditingLeadId] = useState<string | null>(null); // Track if we are editing an existing lead
  const [clientFormData, setClientFormData] = useState<Partial<Lead>>({
    name: '',
    company: '',
    cpfCnpj: '',
    instagram: '',
    phone: '',
    zipCode: '',
    address: '',
    number: '',
    state: '',
    location: '', // city
    value: 0,
    status: '',
    probability: 10,
    nextAction: 'Iniciar contato'
  });

  const activeFunnel = funnels.find(f => f.id === activeFunnelId) || funnels[0];
  const activeLeads = leads.filter(l => l.funnelId === activeFunnelId);

  // Default status when opening form
  useEffect(() => {
    if (activeFunnel && !clientFormData.status && !editingLeadId) {
        setClientFormData(prev => ({ ...prev, status: activeFunnel.stages[0].id }));
    }
  }, [activeFunnelId, activeFunnel, editingLeadId]);

  // --- MAP INITIALIZATION ---
  useEffect(() => {
      // Only initialize map if viewMode is 'map'
      if (viewMode !== 'map') return;

      // Cleanup previous map instance if it exists
      if (mapInstanceRef.current) {
          mapInstanceRef.current.remove();
          mapInstanceRef.current = null;
      }

      // Small timeout to allow DOM to render the container
      const timer = setTimeout(() => {
          if (mapContainerRef.current && leads.length > 0) {
              // Default center (Brazil approx)
              const map = L.map(mapContainerRef.current).setView([-14.2350, -51.9253], 3);

              L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
                  attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
                  subdomains: 'abcd',
                  maxZoom: 19
              }).addTo(map);

              // Add markers for leads with coordinates
              const bounds = L.latLngBounds([]);
              let hasMarkers = false;

              leads.forEach(lead => {
                  if (lead.lat && lead.lng) {
                      hasMarkers = true;
                      const latLng = L.latLng(lead.lat, lead.lng);
                      bounds.extend(latLng);

                      const markerColor = lead.status === 'closed' ? '#10b981' : (lead.status === 'lost' ? '#ef4444' : '#3b82f6');

                      // Custom simple dot icon
                      const customIcon = L.divIcon({
                          className: 'custom-div-icon',
                          html: `<div style="background-color: ${markerColor}; width: 12px; height: 12px; border-radius: 50%; border: 2px solid white; box-shadow: 0 0 10px ${markerColor};"></div>`,
                          iconSize: [12, 12],
                          iconAnchor: [6, 6]
                      });

                      L.marker(latLng, { icon: customIcon })
                        .addTo(map)
                        .bindPopup(`
                            <div style="min-width: 150px;">
                                <strong style="font-size: 14px; color: #fff;">${lead.name}</strong><br/>
                                <span style="color: #94a3b8; font-size: 12px;">${lead.company}</span><br/>
                                <div style="margin-top: 5px; font-weight: bold; color: ${markerColor}">${activeFunnel.stages.find(s => s.id === lead.status)?.name || lead.status}</div>
                                <div style="font-size: 11px; color: #cbd5e1; margin-top: 5px;">${lead.location} - ${lead.state}</div>
                            </div>
                        `);
                  }
              });

              if (hasMarkers) {
                  map.fitBounds(bounds, { padding: [50, 50], maxZoom: 10 });
              }

              mapInstanceRef.current = map;
          }
      }, 100);

      return () => {
          clearTimeout(timer);
          if (mapInstanceRef.current) {
              mapInstanceRef.current.remove();
              mapInstanceRef.current = null;
          }
      };
  }, [leads, activeFunnelId, viewMode]); // Re-render map when leads change or view mode switches to map


  // --- FUNNEL MANAGEMENT ---

  const handleCreateFunnel = () => {
      setEditingFunnel({
          id: '',
          name: 'Novo Funil',
          stages: [
              { id: 'stage_1', name: 'Início', color: 'border-blue-500/50' },
              { id: 'stage_2', name: 'Fim', color: 'border-emerald-500/50' }
          ]
      });
      setShowFunnelModal(true);
      setShowFunnelDropdown(false);
  };

  const handleEditFunnel = () => {
      setEditingFunnel(JSON.parse(JSON.stringify(activeFunnel))); // Deep copy
      setShowFunnelModal(true);
      setShowFunnelDropdown(false);
  };

  const handleDeleteFunnel = () => {
      if (funnels.length <= 1) {
          alert("Você precisa ter pelo menos um funil.");
          return;
      }
      if (confirm(`Tem certeza que deseja excluir o funil "${activeFunnel.name}"? Todos os leads deste funil serão ocultados.`)) {
          const newFunnels = funnels.filter(f => f.id !== activeFunnelId);
          setFunnels(newFunnels);
          setActiveFunnelId(newFunnels[0].id);
          setShowFunnelDropdown(false);
      }
  };

  const handleSaveFunnel = (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingFunnel || !editingFunnel.name) return;

      if (editingFunnel.id) {
          // Edit existing
          setFunnels(prev => prev.map(f => f.id === editingFunnel.id ? editingFunnel as Funnel : f));
      } else {
          // Create new
          const newId = `funnel_${Date.now()}`;
          const newFunnel = { ...editingFunnel, id: newId } as Funnel;
          setFunnels(prev => [...prev, newFunnel]);
          setActiveFunnelId(newId);
      }
      setShowFunnelModal(false);
      setEditingFunnel(null);
  };

  const updateStage = (index: number, field: keyof FunnelStage, value: string) => {
      if (!editingFunnel || !editingFunnel.stages) return;
      const newStages = [...editingFunnel.stages];
      newStages[index] = { ...newStages[index], [field]: value };
      setEditingFunnel({ ...editingFunnel, stages: newStages });
  };

  const addStage = () => {
      if (!editingFunnel || !editingFunnel.stages) return;
      const newStage: FunnelStage = {
          id: `stage_${Date.now()}`,
          name: 'Nova Etapa',
          color: 'border-slate-500/50'
      };
      setEditingFunnel({ ...editingFunnel, stages: [...editingFunnel.stages, newStage] });
  };

  const removeStage = (index: number) => {
      if (!editingFunnel || !editingFunnel.stages) return;
      if (editingFunnel.stages.length <= 1) return;
      const newStages = editingFunnel.stages.filter((_, i) => i !== index);
      setEditingFunnel({ ...editingFunnel, stages: newStages });
  };

  const toggleMapMode = () => {
      if (viewMode === 'map') {
          setViewMode('kanban');
      } else {
          setViewMode('map');
      }
  };

  // --- CLIENT MANAGEMENT ---

  const handleAnalyze = async () => {
    setAnalyzing(true);
    const result = await analyzeCRM(activeLeads);
    setAiAnalysis(result);
    setAnalyzing(false);
  };

  const openNewClientModal = () => {
      setEditingLeadId(null);
      setClientFormData({
          name: '', company: '', cpfCnpj: '', instagram: '', phone: '', 
          zipCode: '', address: '', number: '', state: '', location: '',
          value: 0, status: activeFunnel.stages[0].id, probability: 10, nextAction: 'Iniciar contato'
      });
      setShowClientForm(true);
  };

  const openEditClientModal = (lead: Lead) => {
      setEditingLeadId(lead.id);
      setClientFormData({ ...lead });
      setShowClientForm(true);
  };

  // Geocoding Service (Nominatim OpenStreetMap)
  const getCoordinates = async (address: string, city: string, state: string, zip: string) => {
    try {
        const query = `${address}, ${city}, ${state}, Brazil`;
        const encodedQuery = encodeURIComponent(query);
        const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodedQuery}&limit=1`);
        const data = await response.json();
        if (data && data.length > 0) {
            return { lat: parseFloat(data[0].lat), lng: parseFloat(data[0].lon) };
        }
        return null;
    } catch (error) {
        console.error("Geocoding failed", error);
        return null;
    }
  };

  const handleSaveClient = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!clientFormData.name) return;

      setIsGeocoding(true);

      // Attempt Geocode if address data is present
      let coords = { lat: clientFormData.lat, lng: clientFormData.lng };
      if ((clientFormData.address || clientFormData.location) && (!clientFormData.lat || !clientFormData.lng)) {
           const result = await getCoordinates(
               clientFormData.address || '', 
               clientFormData.location || '', 
               clientFormData.state || '',
               clientFormData.zipCode || ''
           );
           if (result) coords = result;
      }

      const leadDataToSave = {
          ...clientFormData,
          ...coords,
          value: Number(clientFormData.value) || 0,
          probability: Number(clientFormData.probability) || 0
      };

      if (editingLeadId) {
          // UPDATE EXISTING LEAD
          setLeads(prevLeads => prevLeads.map(lead => {
              if (lead.id === editingLeadId) {
                  return { ...lead, ...leadDataToSave } as Lead;
              }
              return lead;
          }));
      } else {
          // CREATE NEW LEAD
          const newClient: Lead = {
              id: Date.now().toString(),
              funnelId: activeFunnelId,
              name: clientFormData.name || 'Cliente Sem Nome',
              company: clientFormData.company || 'N/A',
              status: clientFormData.status || activeFunnel.stages[0].id,
              value: Number(clientFormData.value) || 0,
              probability: Number(clientFormData.probability) || 0,
              lastContact: new Date().toISOString().split('T')[0],
              nextAction: clientFormData.nextAction || 'Definir próximos passos',
              cpfCnpj: clientFormData.cpfCnpj,
              instagram: clientFormData.instagram,
              phone: clientFormData.phone,
              state: clientFormData.state,
              location: clientFormData.location,
              zipCode: clientFormData.zipCode,
              address: clientFormData.address,
              number: clientFormData.number,
              lat: coords.lat,
              lng: coords.lng
          };
          setLeads([...leads, newClient]);
      }

      setIsGeocoding(false);
      setShowClientForm(false);
      setEditingLeadId(null);
  };

  // --- DRAG AND DROP HANDLERS ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      setDraggedLeadId(id);
      e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, newStatus: string) => {
      e.preventDefault();
      if (!draggedLeadId) return;

      setLeads(prevLeads => prevLeads.map(lead => {
          if (lead.id === draggedLeadId) {
              return { ...lead, status: newStatus };
          }
          return lead;
      }));
      setDraggedLeadId(null);
  };

  const getStatusLabel = (statusId: string) => {
      const stage = activeFunnel.stages.find(s => s.id === statusId);
      return stage ? stage.name : statusId;
  };

  const getStatusColor = (statusId: string) => {
      const stage = activeFunnel.stages.find(s => s.id === statusId);
      return stage ? stage.color.replace('border-', 'bg-').replace('/50', '/20') + ' ' + stage.color.replace('border-', 'text-').replace('/50', '/80') + ' border ' + stage.color.replace('/50', '/30') : 'bg-slate-700 text-slate-300';
  };

  const totalPipeline = activeLeads.reduce((acc, lead) => acc + lead.value, 0);
  const weightedPipeline = activeLeads.reduce((acc, lead) => acc + (lead.value * (lead.probability / 100)), 0);

  // Stats for Map Report
  const leadsByState = leads.reduce((acc, lead) => {
      if (lead.state) {
          const upperState = lead.state.toUpperCase().trim();
          acc[upperState] = (acc[upperState] || 0) + 1;
      }
      return acc;
  }, {} as Record<string, number>);

  return (
    <div className="p-4 md:p-8 h-full flex flex-col relative overflow-hidden" onClick={() => setShowFunnelDropdown(false)}>

      {/* HEADER WITH FUNNEL SELECTOR */}
      <header className="flex flex-col md:flex-row md:justify-between md:items-center mb-6 gap-4 flex-shrink-0 z-20">
        <div className="flex flex-col gap-1">
            <h1 className="text-3xl font-bold text-white flex items-center gap-2">
                CRM
                <span className="text-slate-600">/</span>
                <div className="relative" onClick={(e) => e.stopPropagation()}>
                    <button 
                        onClick={() => setShowFunnelDropdown(!showFunnelDropdown)}
                        className="flex items-center gap-2 text-emerald-400 hover:text-emerald-300 transition-colors"
                    >
                        {activeFunnel.name}
                        <ChevronDown size={20} className={`transition-transform ${showFunnelDropdown ? 'rotate-180' : ''}`}/>
                    </button>

                    {/* Funnel Dropdown */}
                    {showFunnelDropdown && (
                        <div className="absolute top-full left-0 mt-2 w-64 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl overflow-hidden animate-fade-in z-50">
                            <div className="p-2 border-b border-slate-700">
                                <p className="text-xs font-bold text-slate-500 uppercase px-2 py-1">Meus Funis</p>
                                {funnels.map(f => (
                                    <button
                                        key={f.id}
                                        onClick={() => { setActiveFunnelId(f.id); setShowFunnelDropdown(false); }}
                                        className={`w-full text-left px-3 py-2 rounded-lg text-sm font-medium flex justify-between items-center ${activeFunnelId === f.id ? 'bg-blue-600 text-white' : 'text-slate-300 hover:bg-slate-700'}`}
                                    >
                                        {f.name}
                                        {activeFunnelId === f.id && <div className="w-2 h-2 bg-white rounded-full"></div>}
                                    </button>
                                ))}
                            </div>
                            <div className="p-2 space-y-1">
                                <button onClick={handleCreateFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-emerald-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Plus size={14}/> Criar Novo Funil
                                </button>
                                <button onClick={handleEditFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-blue-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Edit3 size={14}/> Editar Atual
                                </button>
                                <button onClick={handleDeleteFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-red-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Trash2 size={14}/> Excluir Atual
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </h1>
            <p className="text-slate-400 text-sm">Gerencie seu pipeline de vendas</p>
        </div>

        <div className="flex gap-2">

            {/* View Toggles - Only show if NOT in map mode to avoid clutter */}
            {viewMode !== 'map' && (
                <div className="bg-slate-800 p-1 rounded-lg border border-slate-700 flex mr-2">
                    <button 
                        onClick={() => setViewMode('kanban')}
                        className={`p-2 rounded ${viewMode === 'kanban' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                        title="Visão de Funil"
                    >
                        <LayoutGrid size={18} />
                    </button>
                    <button 
                        onClick={() => setViewMode('list')}
                        className={`p-2 rounded ${viewMode === 'list' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                        title="Visão de Lista"
                    >
                        <ListIcon size={18} />
                    </button>
                </div>
            )}

            {/* 1. AUDITORIA */}
            <button 
                onClick={handleAnalyze}
                disabled={analyzing}
                className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-3 py-1.5 rounded-lg text-white font-medium text-sm transition-all disabled:opacity-50"
            >
                <Brain size={16} /> {analyzing ? 'Analisando...' : 'Auditoria IA'}
            </button>

             {/* 2. NOVO CLIENTE */}
            <button 
                onClick={openNewClientModal}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 px-3 py-1.5 rounded-lg text-white font-medium text-sm transition-all shadow-lg shadow-emerald-900/20"
            >
                <Plus size={16} /> Novo Cliente
            </button>

            {/* 3. MAPA (Toggle) */}
            <button 
                onClick={toggleMapMode}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg font-medium text-sm transition-all shadow-lg ${viewMode === 'map' ? 'bg-blue-600 text-white shadow-blue-900/20' : 'bg-slate-800 text-slate-300 hover:bg-slate-700 hover:text-white border border-slate-700'}`}
            >
                <MapIcon size={16} /> Mapa
            </button>

        </div>
      </header>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6 flex-shrink-0">
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Pipeline Total</span>
                <p className="text-xl font-bold text-white">${totalPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-blue-500/10 rounded-lg text-blue-400"><DollarSign size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                <span className="text-slate-400 text-xs font-medium uppercase">Ponderado</span>
                <p className="text-xl font-bold text-white">${weightedPipeline.toLocaleString()}</p>
            </div>
            <div className="p-2 bg-emerald-500/10 rounded-lg text-emerald-400"><TrendingUp size={20} /></div>
        </div>
        <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 flex justify-between items-center">
            <div>
                 <span className="text-slate-400 text-xs font-medium uppercase">Leads Ativos</span>
                <p className="text-xl font-bold text-white">{activeLeads.length}</p>
            </div>
            <div className="p-2 bg-purple-500/10 rounded-lg text-purple-400"><Users size={20} /></div>
        </div>
      </div>

      {aiAnalysis && (
        <div className="mb-6 bg-indigo-900/20 border border-indigo-500/50 p-4 rounded-xl animate-fade-in flex-shrink-0">
            <h3 className="text-indigo-400 font-bold mb-1 flex items-center gap-2"><Brain size={16}/> Insight Estratégico</h3>
            <p className="text-slate-200 text-sm">{aiAnalysis}</p>
        </div>
      )}

       {/* SCROLLABLE CONTENT CONTAINER */}
      <div className="flex-1 overflow-y-auto custom-scrollbar pb-20">

          {/* --- KANBAN FUNNEL VIEW --- */}
          {viewMode === 'kanban' && (
              <div className="overflow-x-auto pb-4 mb-8">
                  <div className="flex gap-4 min-w-[1400px] h-[500px]">
                      {activeFunnel.stages.map(stage => {
                          const colLeads = activeLeads.filter(l => l.status === stage.id);
                          const colValue = colLeads.reduce((acc, l) => acc + l.value, 0);

                          return (
                              <div 
                                key={stage.id}
                                onDragOver={handleDragOver}
                                onDrop={(e) => handleDrop(e, stage.id)}
                                className={`flex-1 min-w-[240px] bg-slate-800/50 rounded-xl border-t-4 ${stage.color} border-x border-b border-slate-700 flex flex-col h-full`}
                              >
                                  {/* Column Header */}
                                  <div className="p-3 border-b border-slate-700 bg-slate-800 rounded-t-lg group relative">
                                      <div className="flex justify-between items-center mb-1">
                                          <h3 className="font-bold text-slate-200 text-sm uppercase tracking-wide truncate" title={stage.name}>{stage.name}</h3>
                                          <span className="text-xs bg-slate-700 text-slate-300 px-2 py-0.5 rounded-full">{colLeads.length}</span>
                                      </div>
                                      <p className="text-xs text-slate-500 font-mono">R$ {colValue.toLocaleString()}</p>
                                  </div>

                                  {/* Drop Zone / List */}
                                  <div className="flex-1 p-3 space-y-3 overflow-y-auto custom-scrollbar">
                                      {colLeads.map(lead => (
                                          <div
                                            key={lead.id}
                                            draggable
                                            onDragStart={(e) => handleDragStart(e, lead.id)}
                                            onClick={() => openEditClientModal(lead)}
                                            className={`
