import React, { useState } from 'react';
import { WorkoutProfile, WorkoutLog } from '../types';
import { generateWorkoutPlan } from '../services/geminiService';
import { Activity, Dumbbell, PlayCircle, RotateCcw, CheckCircle, History, ChevronDown } from 'lucide-react';

interface BodyProps {
    workoutLogs: WorkoutLog[];
}

export const Body: React.FC<BodyProps> = ({ workoutLogs }) => {
  const [profile, setProfile] = useState<WorkoutProfile | null>(null);
  const [formData, setFormData] = useState<Partial<WorkoutProfile>>({
    sex: 'Masculino', age: 30, weight: 75, goal: 'hypertrophy', limitations: 'Nenhuma'
  });
  const [plan, setPlan] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!formData.age) return;
    const p = formData as WorkoutProfile;
    setProfile(p);
    setLoading(true);
    const aiPlan = await generateWorkoutPlan(p);
    setPlan(aiPlan);
    setLoading(false);
  };

  return (
    <div className="p-4 md:p-8 h-full flex flex-col gap-6 overflow-y-auto custom-scrollbar">
        <header className="flex flex-col md:flex-row md:justify-between md:items-end gap-4">
            <div>
                <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                    <Dumbbell className="text-emerald-500" /> Corpo & Performance
                </h1>
                <p className="text-slate-400">Geração de treino e registros de atividade.</p>
            </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

            {/* Logs Section (From Chat) */}
            <div className="lg:col-span-1 bg-slate-800 p-6 rounded-xl border border-slate-700 h-fit">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <History size={18} className="text-blue-400" /> Histórico de Atividades
                </h3>
                <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
                    {workoutLogs.length === 0 && <p className="text-sm text-slate-500">Nenhum treino registrado via Chat ainda.</p>}
                    {workoutLogs.slice().reverse().map(log => (
                        <div key={log.id} className="border-l-2 border-emerald-500 pl-3 py-1">
                            <p className="text-white font-medium text-sm">{log.description}</p>
                            <p className="text-xs text-slate-500">{new Date(log.date).toLocaleString()}</p>
                        </div>
                    ))}
                </div>
            </div>

            {/* Generator Section */}
            <div className="lg:col-span-2 space-y-6">
                {!plan ? (
                     <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 space-y-4">
                        <h3 className="text-white font-bold">Gerador de Treino IA</h3>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-slate-400 text-sm mb-1">Peso (kg)</label>
                                <input type="number" value={formData.weight} onChange={(e) => setFormData({...formData, weight: Number(e.target.value)})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white" />
                            </div>
                            <div>
                                <label className="block text-slate-400 text-sm mb-1">Idade</label>
                                <input type="number" value={formData.age} onChange={(e) => setFormData({...formData, age: Number(e.target.value)})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white" />
                            </div>
                        </div>

                        <div>
                            <label className="block text-slate-400 text-sm mb-1">Objetivo</label>
                            <select value={formData.goal} onChange={(e) => setFormData({...formData, goal: e.target.value as any})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white">
                                <option value="hypertrophy">Hipertrofia</option>
                                <option value="weight_loss">Perda de Peso</option>
                                <option value="conditioning">Condicionamento</option>
                            </select>
                        </div>

                        <button 
                            onClick={handleGenerate}
                            disabled={loading}
                            className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-3 rounded-lg flex justify-center items-center gap-2 transition-all"
                        >
                            {loading ? <RotateCcw className="animate-spin" /> : <Activity />}
                            {loading ? 'Criando...' : 'Gerar Plano'}
                        </button>
                     </div>
                ) : (
                    <div className="space-y-4 animate-fade-in">
                        <div className="flex justify-between items-center">
                             <h3 className="text-xl font-bold text-emerald-400">{plan.focus} ({plan.durationMinutes} min)</h3>
                             <button onClick={() => setPlan(null)} className="text-sm text-slate-400 hover:text-white">Fechar</button>
                        </div>
                        {plan.exercises?.map((ex: any, idx: number) => (
                            <div key={idx} className="bg-slate-800 p-4 rounded-xl border border-slate-700">
                                <h4 className="font-bold text-white">{ex.name}</h4>
                                <p className="text-sm text-slate-400">{ex.sets} Séries • {ex.reps} Reps</p>
                                <p className="text-xs text-emerald-500 mt-1 italic">{ex.tip}</p>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>

        {/* Footer Space */}
        <div className="mt-16 pt-8 border-t border-slate-800/50 flex flex-col items-center justify-center text-slate-600 gap-2 pb-8">
            <div className="w-1 h-1 bg-slate-700 rounded-full"></div>
            <p className="text-xs uppercase tracking-widest font-bold opacity-50">Nexus 360</p>
            <ChevronDown className="animate-bounce opacity-30 mt-2" size={16} />
        </div>
    </div>
  );
};

