import React, { useState, useRef, useEffect } from 'react';
import { Message } from '../types';
import { chatWithNexus } from '../services/geminiService';
import { NexusLogo } from './NexusLogo';
import { Send, Sparkles, Bot, User, ArrowUp, DollarSign, Dumbbell, Clock, Mic, Image as ImageIcon, X, Paperclip } from 'lucide-react';

interface DashboardProps {
  onCommand: (toolName: string, args: any) => void;
  messages: Message[];
  setMessages: React.Dispatch<React.SetStateAction<Message[]>>;
}

export const Dashboard: React.FC<DashboardProps> = ({ onCommand, messages, setMessages }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  // New States for Audio/Image
  const [isListening, setIsListening] = useState(false);
  const [attachment, setAttachment] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, loading]);

  // --- AUDIO INPUT HANDLER ---
  const toggleListening = () => {
    if (isListening) {
        recognitionRef.current?.stop();
        setIsListening(false);
        return;
    }

    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

    if (!SpeechRecognition) {
        alert("Seu navegador não suporta entrada de voz. Recomendamos o Google Chrome.");
        return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'pt-BR';
    recognition.continuous = false; // Stop after one command/sentence
    recognition.interimResults = false;

    recognitionRef.current = recognition;

    recognition.onstart = () => {
        setIsListening(true);
    };

    recognition.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        if (transcript) {
            // AUTO-SEND: Immediately process the command without user needing to click send
            handleSend(undefined, transcript);
        }
        setIsListening(false);
    };

    recognition.onerror = (event: any) => {
        console.error("Speech error", event.error);
        setIsListening(false);
    };

    recognition.onend = () => {
        setIsListening(false);
    };

    recognition.start();
  };

  // --- IMAGE UPLOAD HANDLER ---
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => {
              setAttachment(reader.result as string);
          };
          reader.readAsDataURL(file);
      }
  };

  const handleSend = async (e?: React.FormEvent, textOverride?: string) => {
    if (e) e.preventDefault();
    const textToSend = textOverride || input;

    // Allow sending if there is text OR an attachment
    if (!textToSend.trim() && !attachment) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      timestamp: new Date()
    };

    // Include a visual indicator in the message list if an image was sent
    if (!textToSend.trim() && attachment) {
        userMsg.text = "📷 [Imagem enviada para análise]";
    }

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    const currentAttachment = attachment;
    setAttachment(null); // Clear attachment immediately
    setLoading(true);

    const { text, functionCall } = await chatWithNexus(textToSend, messages, currentAttachment || undefined);

    setLoading(false);

    if (functionCall) {
        onCommand(functionCall.name, functionCall.args);

        const responseText = text || "Certo, comando processado.";

        setMessages(prev => [...prev, {
            id: Date.now().toString() + '_ai',
            role: 'model',
            text: responseText,
            timestamp: new Date()
        }]);

    } else if (text) {
        setMessages(prev => [...prev, {
            id: Date.now().toString() + '_ai',
            role: 'model',
            text: text,
            timestamp: new Date()
        }]);
    }
  };

  const SuggestionCard = ({ icon: Icon, text, onClick }: any) => (
      <button 
        onClick={onClick}
        className="flex flex-col items-start gap-2 p-4 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-2xl transition-all text-left group w-full"
      >
          <div className="p-2 rounded-full bg-slate-900 group-hover:bg-slate-800 text-blue-400">
            <Icon size={18} />
          </div>
          <span className="text-sm text-slate-300 font-medium">{text}</span>
      </button>
  );

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto relative">

      {/* Header Minimalista */}
      <header className="absolute top-0 left-0 right-0 p-4 z-10 flex justify-between items-center bg-gradient-to-b from-slate-900 to-transparent">
        <div className="flex items-center gap-2">
            <NexusLogo size={24} />
            <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400 tracking-wider">
                NEXUS AI
            </span>
            <span className="text-[10px] px-2 py-0.5 rounded-full bg-blue-500/10 text-blue-400 border border-blue-500/20 font-bold tracking-wider">BETA</span>
        </div>
      </header>

      {/* Área Principal */}
      <div className="flex-1 overflow-y-auto pt-16 pb-32 px-4 scrollbar-hide">

        {/* Estado Vazio (Welcome) */}
        {messages.length === 0 && (
            <div className="flex flex-col items-center justify-center min-h-[60vh] animate-fade-in">
                <div className="w-20 h-20 mb-6 flex items-center justify-center bg-slate-800/50 rounded-3xl border border-slate-700 shadow-xl shadow-blue-900/10">
                     <NexusLogo size={48} className="drop-shadow-[0_0_10px_rgba(59,130,246,0.4)]" />
                </div>
                <h2 className="text-3xl font-bold text-white mb-2 text-center">Como posso ajudar hoje?</h2>
                <p className="text-slate-400 text-center max-w-md mb-12">
                    Sou seu controlador geral. Posso analisar fotos de documentos, registrar gastos por voz e organizar seu dia.
                </p>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full max-w-2xl">
                    <SuggestionCard 
                        icon={DollarSign} 
                        text="Gastei R$ 45,00 no almoço" 
                        onClick={() => handleSend(undefined, "Gastei R$ 45,00 no almoço")}
                    />
                     <SuggestionCard 
                        icon={ImageIcon} 
                        text="Analise esta foto (conta/gráfico)" 
                        onClick={() => {
                            // Trigger file upload programmatically
                            fileInputRef.current?.click();
                        }}
                    />
                    <SuggestionCard 
                        icon={Dumbbell} 
                        text="Treinei superiores por 1 hora" 
                        onClick={() => handleSend(undefined, "Treinei superiores por 1 hora")}
                    />
                    <SuggestionCard 
                        icon={Mic} 
                        text="Clique para falar (Auto)" 
                        onClick={toggleListening}
                    />
                </div>
            </div>
        )}

        {/* Lista de Mensagens */}
        <div className="space-y-6 max-w-3xl mx-auto">
            {messages.map((msg) => (
            <div key={msg.id} className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>

                {msg.role !== 'user' && (
                    <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-gradient-to-br from-blue-600 to-purple-600 shadow-lg mt-1">
                        <Bot size={16} className="text-white" />
                    </div>
                )}

                <div className={`p-4 rounded-2xl max-w-[85%] text-sm leading-relaxed shadow-sm
                    ${msg.role === 'user' 
                        ? 'bg-slate-800 text-slate-100 rounded-tr-sm' 
                        : 'text-slate-200'}`}>
                    {msg.role === 'model' ? (
                        <div className="prose prose-invert prose-sm max-w-none">
                           {msg.text.split('\n').map((line, i) => <p key={i} className="mb-2 last:mb-0">{line}</p>)}
                        </div>
                    ) : (
                        msg.text
                    )}
                </div>

                {msg.role === 'user' && (
                    <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-slate-700 mt-1">
                        <User size={16} className="text-slate-300" />
                    </div>
                )}
            </div>
            ))}

            {loading && (
                <div className="flex gap-4 max-w-3xl mx-auto">
                     <div className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 bg-gradient-to-br from-blue-600 to-purple-600 shadow-lg mt-1">
                        <Sparkles size={16} className="text-white animate-pulse" />
                    </div>
                    <div className="flex items-center gap-1 h-10">
                        <span className="w-2 h-2 bg-slate-600 rounded-full animate-bounce"></span>
                        <span className="w-2 h-2 bg-slate-600 rounded-full animate-bounce delay-75"></span>
                        <span className="w-2 h-2 bg-slate-600 rounded-full animate-bounce delay-150"></span>
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>
      </div>

      {/* Input Flutuante */}
      <div className="absolute bottom-6 left-0 right-0 px-4 flex justify-center">
        <form onSubmit={(e) => handleSend(e)} className="w-full max-w-3xl relative flex flex-col items-center">

            {/* Image Preview */}
            {attachment && (
                <div className="self-start mb-2 relative bg-slate-800 p-2 rounded-xl border border-slate-700 animate-fade-in">
                    <img src={attachment} alt="Preview" className="h-24 rounded-lg object-cover" />
                    <button 
                        type="button"
                        onClick={() => setAttachment(null)}
                        className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg hover:bg-red-600 transition-colors"
                    >
                        <X size={14} />
                    </button>
                </div>
            )}

            <div className="relative w-full">
                {/* Hidden File Input */}
                <input 
                    type="file" 
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    accept="image/*"
                    className="hidden"
                />

                <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder={isListening ? "Ouvindo... (Enviarei ao parar de falar)" : "Converse ou envie uma foto..."}
                    className={`w-full bg-slate-800/90 backdrop-blur-md text-white pl-12 pr-28 py-4 rounded-full border shadow-2xl focus:outline-none transition-all placeholder:text-slate-500
                        ${isListening ? 'border-red-500/50 ring-1 ring-red-500/50' : 'border-slate-700 focus:border-blue-500 focus:ring-1 focus:ring-blue-500'}
                    `}
                />

                {/* Image Upload Button */}
                <button 
                    type="button"
                    onClick={() => fileInputRef.current?.click()}
                    className="absolute left-3 top-3 bottom-3 aspect-square text-slate-400 hover:text-blue-400 hover:bg-slate-700/50 rounded-full transition-all flex items-center justify-center"
                    title="Anexar Imagem"
                >
                    <Paperclip size={20} />
                </button>

                {/* Right Side Buttons */}
                <div className="absolute right-2 top-2 bottom-2 flex items-center gap-1">
                    {/* Mic Button */}
                    <button 
                        type="button"
                        onClick={toggleListening}
                        className={`aspect-square rounded-full transition-all flex items-center justify-center w-10 h-10
                            ${isListening 
                                ? 'bg-red-600 text-white animate-pulse shadow-[0_0_15px_rgba(220,38,38,0.7)]' 
                                : 'text-slate-400 hover:bg-slate-700 hover:text-white'
                            }`}
                        title={isListening ? "Parar e Enviar" : "Falar"}
                    >
                        <Mic size={20} className={isListening ? "animate-bounce" : ""} />
                    </button>

                    {/* Send Button */}
                    <button 
                        type="submit" 
                        disabled={(!input.trim() && !attachment) || loading}
                        className="aspect-square bg-blue-600 hover:bg-blue-500 text-white rounded-full transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center shadow-lg w-10 h-10"
                    >
                        {loading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"/> : <ArrowUp size={20} />}
                    </button>
                </div>
            </div>
        </form>
      </div>

    </div>
  );
};

import React, { useId } from 'react';

export const NexusLogo: React.FC<{ size?: number, className?: string }> = ({ size = 40, className = "" }) => {
  // Generates a unique ID for this specific instance of the logo
  // This ensures the gradient works even if multiple logos are on screen
  const uniqueId = useId();
  const gradientId = `nexusGradient-${uniqueId}`;

  return (
    <svg width={size} height={size} viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg" className={className}>
      <defs>
        <linearGradient id={gradientId} x1="10" y1="8" x2="30" y2="32" gradientUnits="userSpaceOnUse">
          <stop offset="0%" stopColor="#3B82F6" /> {/* Blue-500 */}
          <stop offset="100%" stopColor="#9333EA" /> {/* Purple-600 */}
        </linearGradient>
      </defs>
      {/* Left Pillar - Solid Blue */}
      <path d="M11 6V34" stroke="#3B82F6" strokeWidth="5" strokeLinecap="round"/>
      {/* Right Pillar - Solid Purple */}
      <path d="M29 6V34" stroke="#8B5CF6" strokeWidth="5" strokeLinecap="round"/>
      {/* The Connection (Nexus) - Uses the Unique Gradient ID */}
      <path d="M11 6L29 34" stroke={`url(#${gradientId})`} strokeWidth="5" strokeLinecap="round" />
    </svg>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Lead, Funnel, FunnelStage } from '../types';
import { analyzeCRM } from '../services/geminiService';
import { TrendingUp, Users, DollarSign, Brain, MoreHorizontal, Plus, X, Save, MapPin, Instagram, Phone, Building2, User, LayoutGrid, List as ListIcon, GripVertical, Settings, Trash2, ChevronDown, Edit3, Map as MapIcon, Globe2, Loader2 } from 'lucide-react';
import L from 'leaflet';

interface ProfessionalProps {
    leads: Lead[];
    setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
    funnels: Funnel[];
    setFunnels: React.Dispatch<React.SetStateAction<Funnel[]>>;
}

export const Professional: React.FC<ProfessionalProps> = ({ leads, setLeads, funnels, setFunnels }) => {
  // Data State
  const [activeFunnelId, setActiveFunnelId] = useState<string>(funnels[0]?.id || 'default');

  // View & UX State
  const [aiAnalysis, setAiAnalysis] = useState<string>("");
  const [analyzing, setAnalyzing] = useState(false);
  const [showClientForm, setShowClientForm] = useState(false);
  const [showFunnelModal, setShowFunnelModal] = useState(false);
  const [viewMode, setViewMode] = useState<'list' | 'kanban' | 'map'>('kanban');
  const [draggedLeadId, setDraggedLeadId] = useState<string | null>(null);
  const [isGeocoding, setIsGeocoding] = useState(false);

  // -- MAP REFS --
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);

  // -- FUNNEL EDITING STATE --
  const [editingFunnel, setEditingFunnel] = useState<Partial<Funnel> | null>(null);
  const [showFunnelDropdown, setShowFunnelDropdown] = useState(false);

  // -- CLIENT FORM STATE --
  const [editingLeadId, setEditingLeadId] = useState<string | null>(null); // Track if we are editing an existing lead
  const [clientFormData, setClientFormData] = useState<Partial<Lead>>({
    name: '',
    company: '',
    cpfCnpj: '',
    instagram: '',
    phone: '',
    zipCode: '',
    address: '',
    number: '',
    state: '',
    location: '', // city
    value: 0,
    status: '',
    probability: 10,
    nextAction: 'Iniciar contato'
  });

  const activeFunnel = funnels.find(f => f.id === activeFunnelId) || funnels[0];
  const activeLeads = leads.filter(l => l.funnelId === activeFunnelId);

  // Default status when opening form
  useEffect(() => {
    if (activeFunnel && !clientFormData.status && !editingLeadId) {
        setClientFormData(prev => ({ ...prev, status: activeFunnel.stages[0].id }));
    }
  }, [activeFunnelId, activeFunnel, editingLeadId]);

  // --- MAP INITIALIZATION ---
  useEffect(() => {
      // Only initialize map if viewMode is 'map'
      if (viewMode !== 'map') return;

      // Cleanup previous map instance if it exists
      if (mapInstanceRef.current) {
          mapInstanceRef.current.remove();
          mapInstanceRef.current = null;
      }

      // Small timeout to allow DOM to render the container
      const timer = setTimeout(() => {
          if (mapContainerRef.current && leads.length > 0) {
              // Default center (Brazil approx)
              const map = L.map(mapContainerRef.current).setView([-14.2350, -51.9253], 3);

              L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
                  attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
                  subdomains: 'abcd',
                  maxZoom: 19
              }).addTo(map);

              // Add markers for leads with coordinates
              const bounds = L.latLngBounds([]);
              let hasMarkers = false;

              leads.forEach(lead => {
                  if (lead.lat && lead.lng) {
                      hasMarkers = true;
                      const latLng = L.latLng(lead.lat, lead.lng);
                      bounds.extend(latLng);

                      const markerColor = lead.status === 'closed' ? '#10b981' : (lead.status === 'lost' ? '#ef4444' : '#3b82f6');

                      // Custom simple dot icon
                      const customIcon = L.divIcon({
                          className: 'custom-div-icon',
                          html: `<div style="background-color: ${markerColor}; width: 12px; height: 12px; border-radius: 50%; border: 2px solid white; box-shadow: 0 0 10px ${markerColor};"></div>`,
                          iconSize: [12, 12],
                          iconAnchor: [6, 6]
                      });

                      L.marker(latLng, { icon: customIcon })
                        .addTo(map)
                        .bindPopup(`
                            <div style="min-width: 150px;">
                                <strong style="font-size: 14px; color: #fff;">${lead.name}</strong><br/>
                                <span style="color: #94a3b8; font-size: 12px;">${lead.company}</span><br/>
                                <div style="margin-top: 5px; font-weight: bold; color: ${markerColor}">${activeFunnel.stages.find(s => s.id === lead.status)?.name || lead.status}</div>
                                <div style="font-size: 11px; color: #cbd5e1; margin-top: 5px;">${lead.location} - ${lead.state}</div>
                            </div>
                        `);
                  }
              });

              if (hasMarkers) {
                  map.fitBounds(bounds, { padding: [50, 50], maxZoom: 10 });
              }

              mapInstanceRef.current = map;
          }
      }, 100);

      return () => {
          clearTimeout(timer);
          if (mapInstanceRef.current) {
              mapInstanceRef.current.remove();
              mapInstanceRef.current = null;
          }
      };
  }, [leads, activeFunnelId, viewMode]); // Re-render map when leads change or view mode switches to map


  // --- FUNNEL MANAGEMENT ---

  const handleCreateFunnel = () => {
      setEditingFunnel({
          id: '',
          name: 'Novo Funil',
          stages: [
              { id: 'stage_1', name: 'Início', color: 'border-blue-500/50' },
              { id: 'stage_2', name: 'Fim', color: 'border-emerald-500/50' }
          ]
      });
      setShowFunnelModal(true);
      setShowFunnelDropdown(false);
  };

  const handleEditFunnel = () => {
      setEditingFunnel(JSON.parse(JSON.stringify(activeFunnel))); // Deep copy
      setShowFunnelModal(true);
      setShowFunnelDropdown(false);
  };

  const handleDeleteFunnel = () => {
      if (funnels.length <= 1) {
          alert("Você precisa ter pelo menos um funil.");
          return;
      }
      if (confirm(`Tem certeza que deseja excluir o funil "${activeFunnel.name}"? Todos os leads deste funil serão ocultados.`)) {
          const newFunnels = funnels.filter(f => f.id !== activeFunnelId);
          setFunnels(newFunnels);
          setActiveFunnelId(newFunnels[0].id);
          setShowFunnelDropdown(false);
      }
  };

  const handleSaveFunnel = (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingFunnel || !editingFunnel.name) return;

      if (editingFunnel.id) {
          // Edit existing
          setFunnels(prev => prev.map(f => f.id === editingFunnel.id ? editingFunnel as Funnel : f));
      } else {
          // Create new
          const newId = `funnel_${Date.now()}`;
          const newFunnel = { ...editingFunnel, id: newId } as Funnel;
          setFunnels(prev => [...prev, newFunnel]);
          setActiveFunnelId(newId);
      }
      setShowFunnelModal(false);
      setEditingFunnel(null);
  };

  const updateStage = (index: number, field: keyof FunnelStage, value: string) => {
      if (!editingFunnel || !editingFunnel.stages) return;
      const newStages = [...editingFunnel.stages];
      newStages[index] = { ...newStages[index], [field]: value };
      setEditingFunnel({ ...editingFunnel, stages: newStages });
  };

  const addStage = () => {
      if (!editingFunnel || !editingFunnel.stages) return;
      const newStage: FunnelStage = {
          id: `stage_${Date.now()}`,
          name: 'Nova Etapa',
          color: 'border-slate-500/50'
      };
      setEditingFunnel({ ...editingFunnel, stages: [...editingFunnel.stages, newStage] });
  };

  const removeStage = (index: number) => {
      if (!editingFunnel || !editingFunnel.stages) return;
      if (editingFunnel.stages.length <= 1) return;
      const newStages = editingFunnel.stages.filter((_, i) => i !== index);
      setEditingFunnel({ ...editingFunnel, stages: newStages });
  };

  const toggleMapMode = () => {
      if (viewMode === 'map') {
          setViewMode('kanban');
      } else {
          setViewMode('map');
      }
  };

  // --- CLIENT MANAGEMENT ---

  const handleAnalyze = async () => {
    setAnalyzing(true);
    const result = await analyzeCRM(activeLeads);
    setAiAnalysis(result);
    setAnalyzing(false);
  };

  const openNewClientModal = () => {
      setEditingLeadId(null);
      setClientFormData({
          name: '', company: '', cpfCnpj: '', instagram: '', phone: '', 
          zipCode: '', address: '', number: '', state: '', location: '',
          value: 0, status: activeFunnel.stages[0].id, probability: 10, nextAction: 'Iniciar contato'
      });
      setShowClientForm(true);
  };

  const openEditClientModal = (lead: Lead) => {
      setEditingLeadId(lead.id);
      setClientFormData({ ...lead });
      setShowClientForm(true);
  };

  // Geocoding Service (Nominatim OpenStreetMap)
  const getCoordinates = async (address: string, city: string, state: string, zip: string) => {
    try {
        const query = `${address}, ${city}, ${state}, Brazil`;
        const encodedQuery = encodeURIComponent(query);
        const response = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${encodedQuery}&limit=1`);
        const data = await response.json();
        if (data && data.length > 0) {
            return { lat: parseFloat(data[0].lat), lng: parseFloat(data[0].lon) };
        }
        return null;
    } catch (error) {
        console.error("Geocoding failed", error);
        return null;
    }
  };

  const handleSaveClient = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!clientFormData.name) return;

      setIsGeocoding(true);

      // Attempt Geocode if address data is present
      let coords = { lat: clientFormData.lat, lng: clientFormData.lng };
      if ((clientFormData.address || clientFormData.location) && (!clientFormData.lat || !clientFormData.lng)) {
           const result = await getCoordinates(
               clientFormData.address || '', 
               clientFormData.location || '', 
               clientFormData.state || '',
               clientFormData.zipCode || ''
           );
           if (result) coords = result;
      }

      const leadDataToSave = {
          ...clientFormData,
          ...coords,
          value: Number(clientFormData.value) || 0,
          probability: Number(clientFormData.probability) || 0
      };

      if (editingLeadId) {
          // UPDATE EXISTING LEAD
          setLeads(prevLeads => prevLeads.map(lead => {
              if (lead.id === editingLeadId) {
                  return { ...lead, ...leadDataToSave } as Lead;
              }
              return lead;
          }));
      } else {
          // CREATE NEW LEAD
          const newClient: Lead = {
              id: Date.now().toString(),
              funnelId: activeFunnelId,
              name: clientFormData.name || 'Cliente Sem Nome',
              company: clientFormData.company || 'N/A',
              status: clientFormData.status || activeFunnel.stages[0].id,
              value: Number(clientFormData.value) || 0,
              probability: Number(clientFormData.probability) || 0,
              lastContact: new Date().toISOString().split('T')[0],
              nextAction: clientFormData.nextAction || 'Definir próximos passos',
              cpfCnpj: clientFormData.cpfCnpj,
              instagram: clientFormData.instagram,
              phone: clientFormData.phone,
              state: clientFormData.state,
              location: clientFormData.location,
              zipCode: clientFormData.zipCode,
              address: clientFormData.address,
              number: clientFormData.number,
              lat: coords.lat,
              lng: coords.lng
          };
          setLeads([...leads, newClient]);
      }

      setIsGeocoding(false);
      setShowClientForm(false);
      setEditingLeadId(null);
  };

  // --- DRAG AND DROP HANDLERS ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      setDraggedLeadId(id);
      e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, newStatus: string) => {
      e.preventDefault();
      if (!draggedLeadId) return;

      setLeads(prevLeads => prevLeads.map(lead => {
          if (lead.id === draggedLeadId) {
              return { ...lead, status: newStatus };
          }
          return lead;
      }));
      setDraggedLeadId(null);
  };

  const getStatusLabel = (statusId: string) => {
      const stage = activeFunnel.stages.find(s => s.id === statusId);
      return stage ? stage.name : statusId;
  };

  const getStatusColor = (statusId: string) => {
      const stage = activeFunnel.stages.find(s => s.id === statusId);
      return stage ? stage.color.replace('border-', 'bg-').replace('/50', '/20') + ' ' + stage.color.replace('border-', 'text-').replace('/50', '/80') + ' border ' + stage.color.replace('/50', '/30') : 'bg-slate-700 text-slate-300';
  };

  const totalPipeline = activeLeads.reduce((acc, lead) => acc + lead.value, 0);
  const weightedPipeline = activeLeads.reduce((acc, lead) => acc + (lead.value * (lead.probability / 100)), 0);

  // Stats for Map Report
  const leadsByState = leads.reduce((acc, lead) => {
      if (lead.state) {
          const upperState = lead.state.toUpperCase().trim();
          acc[upperState] = (acc[upperState] || 0) + 1;
      }
      return acc;
  }, {} as Record<string, number>);

  return (
    <div className="p-4 md:p-8 h-full flex flex-col relative overflow-hidden" onClick={() => setShowFunnelDropdown(false)}>

      {/* HEADER WITH FUNNEL SELECTOR */}
      <header className="flex flex-col md:flex-row md:justify-between md:items-center mb-6 gap-4 flex-shrink-0 z-20">
        <div className="flex flex-col gap-1">
            <h1 className="text-3xl font-bold text-white flex items-center gap-2">
                CRM
                <span className="text-slate-600">/</span>
                <div className="relative" onClick={(e) => e.stopPropagation()}>
                    <button 
                        onClick={() => setShowFunnelDropdown(!showFunnelDropdown)}
                        className="flex items-center gap-2 text-emerald-400 hover:text-emerald-300 transition-colors"
                    >
                        {activeFunnel.name}
                        <ChevronDown size={20} className={`transition-transform ${showFunnelDropdown ? 'rotate-180' : ''}`}/>
                    </button>

                    {/* Funnel Dropdown */}
                    {showFunnelDropdown && (
                        <div className="absolute top-full left-0 mt-2 w-64 bg-slate-800 border border-slate-700 rounded-xl shadow-2xl overflow-hidden animate-fade-in z-50">
                            <div className="p-2 border-b border-slate-700">
                                <p className="text-xs font-bold text-slate-500 uppercase px-2 py-1">Meus Funis</p>
                                {funnels.map(f => (
                                    <button
                                        key={f.id}
                                        onClick={() => { setActiveFunnelId(f.id); setShowFunnelDropdown(false); }}
                                        className={`w-full text-left px-3 py-2 rounded-lg text-sm font-medium flex justify-between items-center ${activeFunnelId === f.id ? 'bg-blue-600 text-white' : 'text-slate-300 hover:bg-slate-700'}`}
                                    >
                                        {f.name}
                                        {activeFunnelId === f.id && <div className="w-2 h-2 bg-white rounded-full"></div>}
                                    </button>
                                ))}
                            </div>
                            <div className="p-2 space-y-1">
                                <button onClick={handleCreateFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-emerald-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Plus size={14}/> Criar Novo Funil
                                </button>
                                <button onClick={handleEditFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-blue-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Edit3 size={14}/> Editar Atual
                                </button>
                                <button onClick={handleDeleteFunnel} className="w-full text-left px-3 py-2 rounded-lg text-sm text-red-400 hover:bg-slate-700 flex items-center gap-2">
                                    <Trash2 size={14}/> Excluir Atual
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </h1>
            <p className="text-slate-400 text-sm">Gerencie seu pipeline de vendas</p>
        </div>

        <div className="flex gap-2">

            {/* View Toggles - Always visible to maintain size stability */}
            <div className="bg-slate-800 p-1 rounded-lg border border-slate-700 flex mr-2 flex-shrink-0">
                <button 
                    onClick={() => setViewMode('kanban')}
                    className={`p-2 rounded ${viewMode === 'kanban' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                    title="Visão de Funil"
                >
                    <LayoutGrid size={18} />
                </button>
                <button 
                    onClick={() => setViewMode('list')}
                    className={`p-2 rounded ${viewMode === 'list' ? 'bg-slate-700 text-blue-400' : 'text-slate-500 hover:text-white'}`}
                    title="Visão de Lista"
                >
                    <ListIcon size={18} />
                </button>
            </div>

            {/* 1. AUDITORIA */}
            <button 
                onClick={handleAnalyze}
                disabled={analyzing}
                className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-3 py-1.5 rounded-lg text-white font-medium text-sm transition-all disabled:opacity-50 whitespace-nowrap flex-shrink-0"
            >
                <Brain size={16} /> {analyzing ? 'Analisando...' : 'Auditoria IA'}
            </button>

             {/* 2. NOVO CLIENTE */}
            <button 
                onClick={openNewClientModal}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-500 px-3 py-1.5 rounded-lg text-white font-medium text-sm transition-all shadow-lg shadow-emerald-900/20 whitespace-nowrap flex-shrink-0"
            >
                <Plus size={16} /> Novo Cliente
            </button>

            {/* 3. MAPA (Toggle) */}
            <button 
                onClick={toggleMapMode}
