                                    type="text" 
                                    value={studyFormData.subject} 
                                    onChange={(e) => setStudyFormData({...studyFormData, subject: e.target.value})} 
                                    placeholder="Ex: Inglês, Python, História da Arte..."
                                    className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white focus:border-purple-500 outline-none transition-colors" 
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-slate-400 text-xs uppercase font-bold mb-1">Nível Atual</label>
                                    <select value={studyFormData.currentLevel} onChange={(e) => setStudyFormData({...studyFormData, currentLevel: e.target.value as any})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white focus:border-purple-500 outline-none transition-colors">
                                        <option value="iniciante">Iniciante</option>
                                        <option value="intermediario">Intermediário</option>
                                        <option value="avancado">Avançado</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-slate-400 text-xs uppercase font-bold mb-1">Disponibilidade</label>
                                    <input type="text" value={studyFormData.availability} onChange={(e) => setStudyFormData({...studyFormData, availability: e.target.value})} className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white focus:border-purple-500 outline-none transition-colors" />
                                </div>
                            </div>

                            <div>
                                <label className="block text-slate-400 text-xs uppercase font-bold mb-1">Objetivo Específico</label>
