                                    type="text" 
                                    value={studyFormData.goal} 
                                    onChange={(e) => setStudyFormData({...studyFormData, goal: e.target.value})} 
                                    placeholder="Ex: Passar na certificação AWS, Fluência em conversação..."
                                    className="w-full bg-slate-900 border border-slate-700 rounded p-3 text-white focus:border-purple-500 outline-none transition-colors" 
                                />
                            </div>

                            <button 
                                onClick={handleGenerateStudy}
                                disabled={loading}
                                className="w-full bg-purple-600 hover:bg-purple-500 text-white font-bold py-4 rounded-lg flex justify-center items-center gap-2 transition-all shadow-lg shadow-purple-900/20 mt-2"
                            >
                                {loading ? <RotateCcw className="animate-spin" /> : <Brain />}
                                {loading ? 'Desenvolvendo Estratégia...' : 'Gerar Cronograma de Estudos'}
                            </button>
                         </div>
                    ) : (
                        <div className="space-y-4 animate-fade-in">
