    sex: 'Masculino', age: 30, weight: 75, goal: 'conditioning', limitations: 'Sem agachamentos'
  });
  const [aiWorkoutPlan, setAiWorkoutPlan] = useState<any>(null);

  // --- STUDY STATE ---
  const [currentDay, setCurrentDay] = useState<string>(WEEK_DAYS[new Date().getDay()]);
  const [currentModule, setCurrentModule] = useState<number>(1);

  // --- HANDLERS ---
  const handleGenerateWorkout = async () => {
    if (!workoutFormData.age) return;
    const p = workoutFormData as WorkoutProfile;
    setWorkoutProfile(p);
    setLoading(true);
    const aiPlan = await generateWorkoutPlan(p);
    setAiWorkoutPlan(aiPlan);
    setLoading(false);
  };

  const toggleExerciseDetails = (name: string) => {
      if (expandedExercise === name) {
          setExpandedExercise(null);
      } else {
          setExpandedExercise(name);
      }
  };

  // --- CALISTHENICS LOGIC ---
  const currentRoutine = CALISTHENICS_LEVELS[calisthenicsLevel];
  const todayDate = new Date();
  const todayName = WEEK_DAYS[todayDate.getDay()];

  const getDailyPlan = () => {
      const subjects = SCHEDULE[currentDay] || [];
      return subjects.map(subject => {
          const allTopicsForSubject = studyTopics.filter(t => t.subject === subject);
          const topicIndex = currentModule - 1;
          const specificTopic = allTopicsForSubject[topicIndex];
          return { subject, topic: specificTopic, totalTopics: allTopicsForSubject.length };
      });
  };

  const getSubjectProgress = (subject: string) => {
      const total = studyTopics.filter(t => t.subject === subject).length;
      if (total === 0) return 0;
      const done = studyTopics.filter(t => t.subject === subject && t.completed).length;
      return Math.round((done / total) * 100);
  };

