    'Segunda': ['PORTUGUÊS', 'HISTÓRIA', 'FILOSOFIA'],
    'Terça': ['FÍSICA', 'GEOGRAFIA', 'SOCIOLOGIA'],
    'Quarta': ['MATEMÁTICA', 'INFORMÁTICA', 'ING/ESP'],
    'Quinta': ['QUÍMICA', 'BIOLOGIA', 'DIREITO'],
    'Sexta': ['REDAÇÃO', 'QUESTÕES'],
    'Sábado': ['HISTÓRIA', 'SOCIOLOGIA'], 
    'Domingo': ['MATEMÁTICA', 'REDAÇÃO', 'QUESTÕES'] 
};

export const Body: React.FC<BodyProps> = ({ workoutLogs, tasks, studyTopics, onToggleTopic }) => {
  const [activeTab, setActiveTab] = useState<'body' | 'mind'>('body');
  const [loading, setLoading] = useState(false);

  // --- WORKOUT STATE ---
  const [calisthenicsLevel, setCalisthenicsLevel] = useState<number>(1);
  const [expandedExercise, setExpandedExercise] = useState<string | null>(null); // Track which exercise demo is open
  const [workoutProfile, setWorkoutProfile] = useState<WorkoutProfile | null>(null);

  // Keep the generator just in case
  const [workoutFormData, setWorkoutFormData] = useState<Partial<WorkoutProfile>>({
    sex: 'Masculino', age: 30, weight: 75, goal: 'conditioning', limitations: 'Sem agachamentos'
  });
  const [aiWorkoutPlan, setAiWorkoutPlan] = useState<any>(null);

  // --- STUDY STATE ---
  const [currentDay, setCurrentDay] = useState<string>(WEEK_DAYS[new Date().getDay()]);
  const [currentModule, setCurrentModule] = useState<number>(1);

  // --- HANDLERS ---
  const handleGenerateWorkout = async () => {
    if (!workoutFormData.age) return;
    const p = workoutFormData as WorkoutProfile;
    setWorkoutProfile(p);
    setLoading(true);
    const aiPlan = await generateWorkoutPlan(p);
    setAiWorkoutPlan(aiPlan);
    setLoading(false);
  };

  const toggleExerciseDetails = (name: string) => {
      if (expandedExercise === name) {
          setExpandedExercise(null);
      } else {
          setExpandedExercise(name);
      }
  };

  // --- CALISTHENICS LOGIC ---
  const currentRoutine = CALISTHENICS_LEVELS[calisthenicsLevel];
  const todayDate = new Date();
  const todayName = WEEK_DAYS[todayDate.getDay()];

  const getDailyPlan = () => {
      const subjects = SCHEDULE[currentDay] || [];
      return subjects.map(subject => {
          const allTopicsForSubject = studyTopics.filter(t => t.subject === subject);
          const topicIndex = currentModule - 1;
          const specificTopic = allTopicsForSubject[topicIndex];
          return { subject, topic: specificTopic, totalTopics: allTopicsForSubject.length };
      });
  };

  const getSubjectProgress = (subject: string) => {
      const total = studyTopics.filter(t => t.subject === subject).length;
      if (total === 0) return 0;
      const done = studyTopics.filter(t => t.subject === subject && t.completed).length;
      return Math.round((done / total) * 100);
  };

  const studyLogs = tasks.filter(t => t.category === 'study' && t.completed).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const dailyPlan = getDailyPlan();

  return (
    <div className="p-4 md:p-8 h-full flex flex-col gap-6 overflow-y-auto custom-scrollbar">

        {/* --- HEADER: LARGE SPLIT BUTTONS --- */}
        <div className="flex w-full gap-4 md:gap-8 h-32 md:h-40 shrink-0">
