// --- IMAGE COMPONENT WITH FALLBACK ---
const SafeImage = ({ src, alt, className }: { src: string, alt: string, className?: string }) => {
    const [error, setError] = useState(false);

    // If user provides a non-image string in the future, we handle it
    if (!src || error) {
        return (
            <div className={`flex flex-col items-center justify-center bg-slate-900 text-slate-500 border border-slate-700 ${className}`}>
                <ImageOff size={32} className="mb-2 opacity-50"/>
                <span className="text-xs text-center px-4">
                    Visualização não disponível.<br/>
                    (Verifique a conexão ou o link)
                </span>
            </div>
        );
    }

    return (
        <img 
            src={src} 
            alt={alt} 
            className={className} 
            onError={() => setError(true)}
        />
    );
};

export const Body: React.FC<BodyProps> = ({ workoutLogs, tasks, studyTopics, onToggleTopic, onLogWorkout }) => {
  const [activeTab, setActiveTab] = useState<'body' | 'mind'>('body');
  const [loading, setLoading] = useState(false);

  // --- WORKOUT STATE ---
  const [calisthenicsLevel, setCalisthenicsLevel] = useState<number>(1);
  const [expandedExercise, setExpandedExercise] = useState<string | null>(null); 
  const [workoutProfile, setWorkoutProfile] = useState<WorkoutProfile | null>(null);
  const [aiWorkoutPlan, setAiWorkoutPlan] = useState<any>(null);

  // --- TRAINING MODE STATE ---
  const [isTraining, setIsTraining] = useState(false);
  const [currentExIndex, setCurrentExIndex] = useState(0);
  const [sessionTimer, setSessionTimer] = useState(0); // Seconds
  const sessionIntervalRef = useRef<number | null>(null);

  // --- STUDY STATE ---
  const [currentDay, setCurrentDay] = useState<string>(WEEK_DAYS[new Date().getDay()]);
  const [currentModule, setCurrentModule] = useState<number>(1);

  // --- TRAINING LOGIC ---
  const startTraining = () => {
      setIsTraining(true);
      setCurrentExIndex(0);
      setSessionTimer(0);
      if (sessionIntervalRef.current) clearInterval(sessionIntervalRef.current);
      sessionIntervalRef.current = window.setInterval(() => {
          setSessionTimer(t => t + 1);
      }, 1000);
  };

  const endTraining = (completed: boolean) => {
      if (sessionIntervalRef.current) {
          clearInterval(sessionIntervalRef.current);
          sessionIntervalRef.current = null;
      }
      setIsTraining(false);

      if (completed && onLogWorkout) {
          const minutes = Math.floor(sessionTimer / 60);
          onLogWorkout({
              id: Date.now().toString(),
              description: `Treino Nível ${calisthenicsLevel} (${minutes} min)`,
              date: new Date().toISOString()
          });
          alert(`Treino finalizado! +100 XP`);
      }
  };

  const nextExercise = () => {
      const routine = CALISTENICS_LEVELS[calisthenicsLevel];
      if (currentExIndex < routine.exercises.length - 1) {
          setCurrentExIndex(prev => prev + 1);
      } else {
          endTraining(true); // Finish
      }
  };

  const prevExercise = () => {
      if (currentExIndex > 0) {
          setCurrentExIndex(prev => prev - 1);
      }
  };

  const formatTime = (seconds: number) => {
      const m = Math.floor(seconds / 60).toString().padStart(2, '0');
      const s = (seconds % 60).toString().padStart(2, '0');
      return `${m}:${s}`;
  };

  const CALISTENICS_LEVELS = CALISTHENICS_LEVELS; // Alias for consistency
  const currentRoutine = CALISTENICS_LEVELS[calisthenicsLevel];
  const todayDate = new Date();
  const todayName = WEEK_DAYS[todayDate.getDay()];

  // --- STUDY HELPERS ---
  const getDailyPlan = () => {
      const subjects = SCHEDULE[currentDay] || [];
      return subjects.map(subject => {
          const allTopicsForSubject = studyTopics.filter(t => t.subject === subject);
          const topicIndex = currentModule - 1;
          const specificTopic = allTopicsForSubject[topicIndex];
          return { subject, topic: specificTopic, totalTopics: allTopicsForSubject.length };
      });
  };

  const getSubjectProgress = (subject: string) => {
      const total = studyTopics.filter(t => t.subject === subject).length;
      if (total === 0) return 0;
      const done = studyTopics.filter(t => t.subject === subject && t.completed).length;
      return Math.round((done / total) * 100);
  };

  const studyLogs = tasks.filter(t => t.category === 'study' && t.completed).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const dailyPlan = getDailyPlan();

  // --- RENDER TRAINING MODE ---
  if (isTraining) {
      const ex = currentRoutine.exercises[currentExIndex];
      const progress = ((currentExIndex + 1) / currentRoutine.exercises.length) * 100;

      return (
